def _pvp_pair_key(a, b):
    """Return whichever direction of (a,b)/(b,a) exists in _pvp_cards, or (a,b)."""
    if (a, b) in _pvp_cards: return (a, b)
    if (b, a) in _pvp_cards: return (b, a)
    return (a, b)

def _start_pvp_turn(pair, active_uid, a, d, au_id, du_id, bot):
    """Set whose turn it is and start the 15-second countdown timer."""
    _pvp_turns[pair] = active_uid
    old = _pvp_turn_tasks.pop(pair, None)
    if old and not old.done():
        old.cancel()
    task = asyncio.create_task(
        _pvp_turn_timeout(pair, active_uid, a, d, au_id, du_id, bot))
    _pvp_turn_tasks[pair] = task
    _bg_tasks.add(task)
    task.add_done_callback(_bg_tasks.discard)


async def _pvp_turn_timeout(pair, active_uid, a, d, au_id, du_id, bot):
    """Auto-advance turn after 15 seconds of inactivity."""
    try:
        await asyncio.sleep(5)
        if _pvp_turns.get(pair) != active_uid:
            return
        opp_uid = du_id if active_uid == au_id else au_id
        fresh_a = get_player(au_id)
        fresh_d = get_player(du_id)
        if not fresh_a or not fresh_d:
            return
        active_p = fresh_a if active_uid == au_id else fresh_d
        opp_p    = fresh_d if active_uid == au_id else fresh_a
        warn_text = "⚠️ *10 seconds left — act or " + opp_p['username'] + " gets your turn!*"
        warn_card = _pvp_fight_card(active_p, opp_p, warn_text)
        markup    = _build_pvp_card_markup(active_uid, opp_uid, active_p, opp_p, is_my_turn=True)
        stored = _pvp_dm_last_msg.get(active_uid)
        if stored:
            try:
                await bot.edit_message_text(chat_id=stored[0], message_id=stored[1],
                                            text=warn_card, parse_mode="Markdown", reply_markup=markup)
            except Exception:
                pass
        await asyncio.sleep(10)
        if _pvp_turns.get(pair) != active_uid:
            return
        fresh_a = get_player(au_id)
        fresh_d = get_player(du_id)
        if not fresh_a or not fresh_d:
            return
        active_p = fresh_a if active_uid == au_id else fresh_d
        opp_p    = fresh_d if active_uid == au_id else fresh_a
        timeout_text = "⏰ *" + active_p['username'] + "* timed out — " + opp_p['username'] + "'s turn!"
        _pvp_log_append(pair, timeout_text)
        _pvp_battle_stats.setdefault(pair, {})["turns"] = _pvp_battle_stats[pair].get("turns", 0) + 1
        _pvp_turns[pair] = opp_uid
        await _pvp_notify_both(pair, fresh_a, fresh_d, au_id, du_id, timeout_text, bot)
        _start_pvp_turn(pair, opp_uid, fresh_a, fresh_d, au_id, du_id, bot)
    except asyncio.CancelledError:
        pass


def _reset_card_timer(pair, bot, chat_id, mid, seconds=20):
    """Cancel any existing auto-delete task for this card and schedule a fresh one."""
    old = _pvp_card_tasks.pop(pair, None)
    if old and not old.done():
        old.cancel()
    task = asyncio.create_task(_auto_delete(bot, chat_id, mid, seconds))
    _pvp_card_tasks[pair] = task
    _bg_tasks.add(task)
    task.add_done_callback(_bg_tasks.discard)

def _cancel_card_timer(pair):
    old = _pvp_card_tasks.pop(pair, None)
    if old and not old.done():
        old.cancel()

# ── RATE LIMITER ──────────────────────────────────────────────────────────────
_cmd_timestamps    = {}   # user_id -> [float timestamps]
_processing_users  = set()  # user_ids currently inside a state-changing callback

def _rate_ok(uid: int, max_cmds: int = 8, window: float = 6.0) -> bool:
    """Return True if the user is within the rate limit, False if they're spamming."""
    now = time.time()
    times = _cmd_timestamps.get(uid, [])
    times = [t for t in times if now - t < window]
    if len(uid_times := times) >= max_cmds:
        _cmd_timestamps[uid] = uid_times
        return False
    times.append(now)
    _cmd_timestamps[uid] = times
    return True

def _cb_lock(uid: int) -> bool:
    """Acquire a processing lock for a callback. Returns False if already held."""
    if uid in _processing_users:
        return False
    _processing_users.add(uid)
    return True

def _cb_unlock(uid: int):
    _processing_users.discard(uid)

# ── SEND HELPERS ──────────────────────────────────────────────────────────────
async def _auto_delete(bot, chat_id, msg_id, delay):
    await asyncio.sleep(delay)
    try:
        await bot.delete_message(chat_id=chat_id, message_id=msg_id)
    except Exception:
        pass

async def send_group(update: Update, text: str, parse_mode="Markdown",
                     permanent=False, delay=9, reply_markup=None):
    chat_id = update.effective_chat.id
    user_id = update.effective_user.id
    name_hdr = f"👤 *{update.effective_user.first_name}*\n"
    text = name_hdr + text
    key     = (chat_id, user_id)
    old_id  = last_bot_message.get(key)
    results = await asyncio.gather(
        update.get_bot().send_message(
            chat_id=chat_id, text=text[:4096],
            parse_mode=parse_mode, reply_markup=reply_markup),
        update.get_bot().delete_message(chat_id=chat_id, message_id=old_id)
            if old_id else asyncio.sleep(0),
        update.message.delete() if update.message else asyncio.sleep(0),
        return_exceptions=True
    )
    new_msg = results[0]
    if isinstance(new_msg, Exception):
        try:
            new_msg = await update.get_bot().send_message(
                chat_id=chat_id, text=text[:4096],
                parse_mode=parse_mode, reply_markup=reply_markup)
        except Exception:
            return None
    if not permanent:
        last_bot_message[key] = new_msg.message_id
        asyncio.create_task(_auto_delete(
            update.get_bot(), chat_id, new_msg.message_id, delay))
    return new_msg

async def announce(bot, chat_id: int, text: str,
                   parse_mode="Markdown", permanent=False, delay=9):
    try:
        msg = await bot.send_message(
            chat_id=chat_id, text=text[:4096], parse_mode=parse_mode)
        if not permanent:
            asyncio.create_task(_auto_delete(bot, chat_id, msg.message_id, delay))
        return msg
    except Exception:
        return None

async def reply_to_dm(update, context, text: str, parse_mode="Markdown"):
    """Send text to the user's DM. If in a group, delete command and post brief notice."""
    user = update.effective_user
    chat = update.effective_chat
    is_group = chat.type in ("group", "supergroup")
    # Always try to delete the user's command (works in groups with admin perm
    # and in private chats within 48h per Telegram API)
    try: await update.message.delete()
    except Exception: pass
    try:
        await context.bot.send_message(chat_id=user.id, text=text[:4096], parse_mode=parse_mode)
        if is_group:
            try:
                notice = await context.bot.send_message(chat_id=chat.id, text="📬 Sent to your DM!", parse_mode="Markdown")
                asyncio.create_task(_auto_delete(context.bot, chat.id, notice.message_id, 5))
            except Exception: pass
    except Exception:
        # Bot not started in DM — fall back to group with auto-delete
        try:
            msg = await context.bot.send_message(chat_id=chat.id, text=text[:4096], parse_mode=parse_mode)
            asyncio.create_task(_auto_delete(context.bot, chat.id, msg.message_id, 30))
        except Exception: pass

async def send_dm_or_group(bot, user_id: int, chat_id: int, text: str,
                            parse_mode="Markdown", group_delay: int = 20):
    """Try to DM the player; fall back to group with auto-delete."""
    try:
        return await bot.send_message(chat_id=user_id, text=text[:4096], parse_mode=parse_mode)
    except Exception:
        msg = await bot.send_message(chat_id=chat_id, text=text[:4096], parse_mode=parse_mode)
        if group_delay > 0:
            asyncio.create_task(_auto_delete(bot, chat_id, msg.message_id, group_delay))
        return msg

# ── SAFE HELPERS ──────────────────────────────────────────────────────────────
def sjl(v, d):
    if v is None: return d
    try: return json.loads(v)
    except: return d

def safe_inv(p):    return sjl(p.get("inventory"), [])
def safe_stats(p):
    return sjl(p.get("stats"),
               {"STR":5,"DEF":0,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5})
def safe_titles(p): return sjl(p.get("titles"), ["Adventurer"])  # default is Adventurer
def safe_cds(p):    return sjl(p.get("passive_cooldowns"), {})
def safe_int(v, d=0):
    try: return int(v or d)
    except: return d

def resolve_item_ci(typed, collection):
    """Return the canonical item name from collection that matches typed (case-insensitive), or None."""
    typed_l = typed.strip().lower()
    for item in collection:
        if item.lower() == typed_l:
            return item
    return None

