_shop_cache = {"date": None, "tabs": {}}

def _build_gear_shop_tab(pool, seed_key):
    today = datetime.now().strftime("%Y-%m-%d")
    rng = random.Random(today + seed_key)
    common_unc = [(n,d) for n,d in pool.items() if d.get("rarity") in ("common","uncommon")]
    rare       = [(n,d) for n,d in pool.items() if d.get("rarity") == "rare"]
    epic       = [(n,d) for n,d in pool.items() if d.get("rarity") == "epic"]
    picks = []
    if common_unc: picks += rng.sample(common_unc, min(2, len(common_unc)))
    if rare:       picks += rng.sample(rare,        min(2, len(rare)))
    if epic and rng.random() < 0.40: picks.append(rng.choice(epic))
    rng.shuffle(picks)
    result = []
    for name, data in picks:
        rarity = data.get("rarity","common")
        price  = _RARITY_PRICES.get(rarity, 350)
        if "atk" in data:   desc = f"+{data['atk']} ATK"
        elif "def" in data: desc = f"+{data['def']} DEF"
        else:               desc = data.get("desc","")[:45]
        item_line = data.get("line") or data.get("class", "")
        wtype = data.get("type", "")
        if item_line and item_line in LINE_ARCHETYPE:
            path = _WEAPON_TYPE_PATH.get(wtype, "")
            emoji = _LINE_EMOJI.get(item_line, "")
            arch  = LINE_ARCHETYPE[item_line]
            tag   = f"{emoji} {arch}{(' (' + path + ')') if path else ''}".strip()
            desc  = f"{desc} — {tag}"
        elif ("def" in data or "atk" in data) and not item_line:
            desc = f"{desc} (All Classes)"
        result.append({"item":name,"price":price,"desc":desc,"rarity":rarity})
    return result

_LEGEND_SHOP_PRICES = {"legendary": 18000, "mythic": 45000}

def _build_legend_shop_tab():
    all_pools = {**WEAPONS, **ARMORS, **SHIELDS, **ACCESSORIES, **HATS, **GLOVES, **BOOTS, **MASKS}
    leg   = [(n,d) for n,d in all_pools.items() if d.get("rarity") == "legendary"]
    myth  = [(n,d) for n,d in all_pools.items() if d.get("rarity") == "mythic"]
    rng   = random.Random(datetime.now().strftime("%Y-%m-%d") + "legend")
    picks = rng.sample(leg, min(4, len(leg))) + rng.sample(myth, min(2, len(myth)))
    rng.shuffle(picks)
    result = []
    for name, data in picks:
        rarity = data.get("rarity","legendary")
        price  = _LEGEND_SHOP_PRICES.get(rarity, 18000)
        if "atk" in data:   desc = f"+{data['atk']} ATK"
        elif "def" in data: desc = f"+{data['def']} DEF"
        else:               desc = data.get("desc","")[:45]
        item_line = data.get("line") or data.get("class", "")
        wtype = data.get("type", "")
        if item_line and item_line in LINE_ARCHETYPE:
            path = _WEAPON_TYPE_PATH.get(wtype, "")
            emoji = _LINE_EMOJI.get(item_line, "")
            arch  = LINE_ARCHETYPE[item_line]
            tag   = f"{emoji} {arch}{(' (' + path + ')') if path else ''}".strip()
            desc  = f"{desc} — {tag}"
        elif ("def" in data or "atk" in data) and not item_line:
            desc = f"{desc} (All Classes)"
        result.append({"item":name,"price":price,"desc":desc,"rarity":rarity})
    return result

def get_shop_tab(tab):
    today = datetime.now().strftime("%Y-%m-%d")
    if _shop_cache["date"] != today:
        _shop_cache["date"] = today
        _shop_cache["tabs"] = {}
    if tab not in _shop_cache["tabs"]:
        _gear_pools = {
            "wep":WEAPONS,"arm":ARMORS,"shd":SHIELDS,"acc":ACCESSORIES,
            "hat":HATS,"glv":GLOVES,"bot":BOOTS,"msk":MASKS,
        }
        if tab in _SHOP_STATIC_TABS:
            _shop_cache["tabs"][tab] = _SHOP_STATIC_TABS[tab]
        elif tab in _gear_pools:
            _built = _build_gear_shop_tab(_gear_pools[tab], tab)
            if tab == "acc":
                _built.append({"item":"Fortune Coin", "price":800, "desc":"+12 AGI, +8% crit damage.", "rarity":"rare"})
            _shop_cache["tabs"][tab] = _built
        elif tab == "legend":
            _shop_cache["tabs"][tab] = _build_legend_shop_tab()
        else:
            _shop_cache["tabs"][tab] = []
    return _shop_cache["tabs"][tab]

def get_daily_shop():
    return get_shop_tab("pot")

def _shop_discount(p):
    discount = 0
    if _ts_active(p, "shop_discount_until"): discount = 0.20
    if p.get("guild_id") and str(p.get("guild_id")) != "None":
        g = get_guild(p["guild_id"])
        if g:
            glvl = safe_int(g.get("level"),1)
            guild_disc = 0.15 if glvl >= 10 else (0.10 if glvl >= 7 else 0)
            discount = max(discount, guild_disc)
    return discount

def _get_shop_seed(p):
    """Return current shop seed for this player (auto-resets daily)."""
    today = datetime.now().strftime("%Y-%m-%d")
    if p.get("shop_reroll_date") != today:
        return 0  # default view, no reroll yet today
    return safe_int(p.get("shop_reroll_count", 0))

def get_shop_tab_for_player(tab, p):
    """Return shop items for tab, possibly reshuffled by player's reroll seed."""
    base = list(get_shop_tab(tab))
    seed = _get_shop_seed(p)
    if seed == 0 or len(base) <= 1:
        return base
    rng = random.Random(f"{p['user_id']}_{datetime.now().strftime('%Y-%m-%d')}_{seed}")
    rng.shuffle(base)
    return base

def _build_shop_view(p, tab, uid, discount=0):
    items  = get_shop_tab_for_player(tab, p)
    label  = _SHOP_TAB_LABELS.get(tab, tab)
    disc_note = f"  🏷️ *{int(discount*100)}% off!*" if discount else ""
    lines  = [f"👤 *{p['username']}*", f"🛒 *{label}* | 💰 {p['gold']} gold{disc_note}\n"]
    if not items:
        lines.append("_Nothing in stock today — check back tomorrow._")
    for i, e in enumerate(items):
        price = round(e["price"] * (1-discount))
        rem   = RARITY_EMOJI.get(e.get("rarity",""),"⚪")
        lines.append(f"{rem} *{e['item']}*  —  {price:,}g\n   _{e['desc']}_")
    # Tab nav (2 rows of 5)
    half = len(SHOP_TABS_ORDER) // 2
    def _tab_btn(t):
        lbl = ("▸ " if t == tab else "") + _SHOP_TAB_SHORT[t]
        return InlineKeyboardButton(lbl, callback_data=f"shoptab_{uid}_{t}")
    row1 = [_tab_btn(t) for t in SHOP_TABS_ORDER[:half]]
    row2 = [_tab_btn(t) for t in SHOP_TABS_ORDER[half:]]
    buy_rows = []
    for i, e in enumerate(items):
        price = round(e["price"] * (1-discount))
        buy_rows.append([InlineKeyboardButton(
            f"Buy: {e['item']} ({price:,}g)", callback_data=f"shopbuy_{uid}_{tab}_{i}")])
    today = datetime.now().strftime("%Y-%m-%d")
    reroll_count = safe_int(p.get("shop_reroll_count", 0)) if p.get("shop_reroll_date") == today else 0
    reroll_label = f"🎲 Reroll (1,000g)" if reroll_count < 3 else "🎲 Rerolled 3×"
    markup = InlineKeyboardMarkup([row1, row2] + buy_rows + [
        [InlineKeyboardButton(reroll_label, callback_data=f"shopreroll_{uid}_{tab}")],
        [InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")],
    ])
    return "\n".join(lines), markup

