def _dng_roll_floor_modifier(floor):
    """Roll a floor hazard for floors 2+. 40% chance of no modifier."""
    if floor <= 1 or random.random() < 0.40:
        return None
    return random.choice(_DNG_FLOOR_MODIFIERS)

