async def weather_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    w = get_weather()
    hint = "\n🌑 _Something stirs in the shadows..._" if w.get("secret_eligible") else ""
    await send_group(update,
        f"🌦️ *Table Conditions: {w['name']}*\n_{w['desc']}_\n\n"
        f"📈 EXP x{w['exp_mod']} | ⚔️ DMG x{w['dmg_mod']}{hint}", delay=15)

async def killcondition_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    line_k = get_class_line(p)
    kc_k = _KILL_CONDITIONS.get(line_k) if line_k else None
    if not kc_k:
        await send_group(update, "⚡ *Kill Condition*\n\nNo finisher yet — choose a class first with /class!", delay=9); return
    em_k = _LINE_EMOJI.get(line_k, "⚡")
    cond_strs_k = "\n".join(f"  • {f.replace('_',' ').title()} ≥ {v}" for f, v in kc_k["conds"])
    extras_k = ""
    if kc_k.get("drain_pct"):
        extras_k += f"\n🩸 Drains {round(kc_k['drain_pct']*100)}% of target's remaining HP (added to damage)"
    if kc_k.get("dot_burst"):
        extras_k += "\n☠️ Bursts all poison stacks on target for bonus damage"
    lines_k = [
        f"{em_k} *{kc_k['name']}* — {line_k.replace('_',' ').title()} Finisher\n",
        f"📋 *Conditions required (on your target):*",
        cond_strs_k,
        f"\n⚔️ *Damage:* {kc_k['stat']} × {kc_k['mult']}{extras_k}",
        f"\n💡 _Stack conditions via attacks & auto-afflictions (15% per hit)._",
        f"_When all conditions are met, ⚡ FINISHER appears on your PvP battle card._",
        f"_Instakills targets at ≤50% HP._",
    ]
    await send_group(update, "\n".join(lines_k), delay=25)


async def curepriority_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Set or view your auto-cure priority list."""
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    _all_names = [e[0] for e in _CURABLE_AFFLICTIONS]

    if not context.args:
        # Show current priority
        current = sjl(p.get("cure_priority"), []) or _DEFAULT_CURE_PRIORITY
        lines = ["💊 *Auto-Cure Priority*\n"]
        for i, k in enumerate(current, 1):
            em = _CURE_EMOJI.get(k, "•")
            lines.append(f"{i}. {em} {k.title()}")
        lines.append(f"\n_Set with: /curepriority poison bleed stun hex ..._")
        lines.append(f"_Available: {', '.join(_all_names)}_")
        lines.append(f"_Reset with: /curepriority reset_")
        await send_group(update, "\n".join(lines), delay=20); return

    if context.args[0].lower() == "reset":
        p["cure_priority"] = json.dumps(_DEFAULT_CURE_PRIORITY)
        save_player(p)
        await send_group(update, "💊 Cure priority reset to default.", delay=9); return

    chosen = []
    invalid = []
    for arg in context.args[:5]:
        a_lower = arg.lower()
        if a_lower in _all_names:
            if a_lower not in chosen:
                chosen.append(a_lower)
        else:
            invalid.append(arg)

    if invalid:
        await send_group(update, f"Unknown affliction(s): {', '.join(invalid)}\nUse: {', '.join(_all_names)}", delay=9); return
    if not chosen:
        await send_group(update, "No valid afflictions specified.", delay=9); return

    p["cure_priority"] = json.dumps(chosen)
    save_player(p)
    lines = ["💊 *Cure priority set:*"]
    for i, k in enumerate(chosen, 1):
        lines.append(f"{i}. {_CURE_EMOJI.get(k,'•')} {k.title()}")
    await send_group(update, "\n".join(lines), delay=15)


async def cooldowns_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await reply_to_dm(update, context, "Use /ascend first!"); return
    s_cd = get_shadow(user.id)
    pool_ts = p.get("last_pool") or (s_cd.get("last_pool") if s_cd else None)
    lines = [f"⏳ *{p['username']}'s Cooldowns:*\n",
             f"🎁 Daily:   {time_remaining(p.get('last_daily'), 86400)}",
             f"🗺️ Quest:   {time_remaining(p.get('last_quest'), 3600)}",
             f"🏋️ Train:   {time_remaining(p.get('last_train'), 1800)}",
             f"🎱 Pool:    {time_remaining(pool_ts, 8)}"]
    today = datetime.now().strftime("%Y-%m-%d")
    exp_count = safe_int(p.get("explore_count_today")) if p.get("explore_date")==today else 0
    lines.append(f"🗺️ Explore: {exp_count}/2 today")
    lines.append(f"🏰 Dungeon Run: {time_remaining(p.get('last_dungeon'), 86400)}")
    if is_defeated(p):
        end  = datetime.fromisoformat(p["defeated_until"])
        diff = end - datetime.now()
        m, s = divmod(int(diff.total_seconds()),60); h, m = divmod(m,60)
        lines.append(f"💀 Defeat:  {h}h {m}m remaining")
    if is_invincible(p):
        lines.append(f"🛡️ Invincible: still recovering")
    await reply_to_dm(update, context, "\n".join(lines))

async def who_cmd(update, context):
    conn = sqlite3.connect(DB_PATH); conn.row_factory = sqlite3.Row; c = conn.cursor()
    cutoff = (datetime.now() - timedelta(hours=24)).isoformat()
    c.execute("""SELECT s.user_id, s.username, s.level, s.last_seen,
                        p.class_id, p.hp, p.max_hp, p.kill_streak, p.kills_today,
                        p.kills_today_date, p.is_wanted,
                        p.invincible_until, p.defeated_until
                 FROM shadow_profiles s
                 LEFT JOIN players p ON p.user_id = s.user_id
                 WHERE s.last_seen > ?
                 ORDER BY s.last_seen DESC LIMIT 20""",
              (cutoff,))
    rows = c.fetchall()

    now_iso = datetime.now().isoformat()
    # Batch-fetch which players have active bounties
    if rows:
        uid_list = [row["user_id"] for row in rows]
        placeholders = ",".join("?" * len(uid_list))
        c.execute(
            f"SELECT DISTINCT target_id FROM bounties WHERE target_id IN ({placeholders})"
            f" AND claimed_by IS NULL AND expires_at > ?",
            uid_list + [now_iso])
        bounty_ids = {r[0] for r in c.fetchall()}
    else:
        bounty_ids = set()
    conn.close()

    if not rows:
        await send_group(update, "No players active in the last 24 hours.", delay=9); return

    today_str = datetime.now().strftime("%Y-%m-%d")
    lines = ["👥 *Active Players (last 24h)*\n"]
    for row in rows:
        cls = CLASS_TREE.get(row["class_id"] or "", {}).get("name", "No Class")
        hp  = safe_int(row["hp"]); mhp = safe_int(row["max_hp"])
        hp_pct = int((hp / max(1, mhp)) * 100) if mhp else 100
        try:
            inv_until = row["invincible_until"]
            def_until = row["defeated_until"]
        except (IndexError, KeyError):
            inv_until = None; def_until = None
        is_inv  = bool(inv_until and inv_until > now_iso)
        is_def  = bool(def_until and def_until > now_iso)
        if is_inv:
            hp_icon = "🛡️"
        elif is_def or (hp == 0 and mhp > 0):
            hp_icon = "💀"
        elif hp_pct > 50:
            hp_icon = "❤️"
        elif hp_pct > 25:
            hp_icon = "🟡"
        else:
            hp_icon = "🔴"
        try:
            kills_today = safe_int(row["kills_today"]) if row["kills_today_date"] == today_str else 0
            ks          = safe_int(row["kill_streak"])
            is_wanted   = safe_int(row["is_wanted"])
        except (IndexError, KeyError):
            kills_today = 0; ks = 0; is_wanted = 0
        wanted_tag  = " 🔴 WANTED" if is_wanted else ""
        streak_tag  = f" 🔥×{ks}" if ks >= 3 else ""
        bounty_tag  = " 💰" if row["user_id"] in bounty_ids else ""
        lines.append(f"{hp_icon} *{row['username']}* - Lv {row['level']} {cls}{streak_tag}{wanted_tag}{bounty_tag}")

    await send_group(update, "\n".join(lines), delay=20)

async def history_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    hist = sjl(p.get("pvp_history"), [])
    if not hist:
        await send_group(update, "📜 *PvP History*\n\nNo recent PvP activity.", delay=12); return
    lines = ["📜 *Your Last 5 PvP Hits*\n"]
    for entry in hist:
        if entry.get("dmg") == "KO":
            dmg_str = "💀 KO"
        else:
            raw = entry.get("dmg", "?")
            if entry.get("shield"):
                dmg_str = f"{raw} dmg _(🛡️ {entry['shield']} absorbed → {entry.get('hp_dmg', 0)} to HP)_"
            else:
                dmg_str = f"{raw} dmg"
        lines.append(f"⚔️ *{entry.get('attacker','?')}* — {dmg_str}  _{entry.get('ts','')}_")
    await send_group(update, "\n".join(lines), delay=20)

def _war_page_text(page: int) -> str:
    now_iso = datetime.now().isoformat()
    today_str = datetime.now().strftime("%Y-%m-%d")
    try:
        conn_w = sqlite3.connect(DB_PATH); conn_w.row_factory = sqlite3.Row; cw = conn_w.cursor()

        if page == 0:
            lines = [f"💀 *Today's Top Killers* _{today_str}_\n"]
            cw.execute("""SELECT username, kills_today, kill_streak, is_wanted
                          FROM players
                          WHERE kills_today_date=? AND kills_today>0
                          ORDER BY kills_today DESC LIMIT 15""", (today_str,))
            killers = cw.fetchall()
            if killers:
                medals = ["🥇","🥈","🥉"]
                for i, k in enumerate(killers):
                    medal = medals[i] if i < 3 else f"{i+1}."
                    wanted = " 🔴 WANTED" if safe_int(k["is_wanted"]) else ""
                    ks = safe_int(k["kill_streak"])
                    streak_txt = f"  🔥{ks}" if ks >= 3 else ""
                    lines.append(f"{medal} *{k['username']}* — {k['kills_today']} kills{streak_txt}{wanted}")
            else:
                lines.append("_No kills recorded today._")

        elif page == 1:
            lines = ["🎯 *Active Bounties*\n"]
            cw.execute("""SELECT b.reward, b.expires_at,
                                 p.username  AS target_name,
                                 p2.username AS placer_name
                          FROM bounties b
                          LEFT JOIN players p  ON b.target_id  = p.user_id
                          LEFT JOIN players p2 ON b.placer_id  = p2.user_id
                          WHERE b.claimed_by IS NULL AND b.expires_at > ?
                          ORDER BY b.reward DESC LIMIT 20""", (now_iso,))
            brows = cw.fetchall()
            if brows:
                for i, b in enumerate(brows, 1):
                    lines.append(f"{i}. 💰 *{b['target_name'] or 'Unknown'}* — {b['reward']}g  _(by {b['placer_name'] or 'Unknown'})_")
            else:
                lines.append("_No active bounties right now._")

        elif page == 2:
            lines = ["⚔️ *Active Guild Wars*\n"]
            cw.execute("""SELECT gw.expires_at, gw.kills1, gw.kills2,
                                 g1.name AS name1, g2.name AS name2
                          FROM guild_wars gw
                          LEFT JOIN guilds g1 ON g1.guild_id = gw.guild1_id
                          LEFT JOIN guilds g2 ON g2.guild_id = gw.guild2_id
                          WHERE gw.active=1 AND gw.expires_at > ?""", (now_iso,))
            wars = cw.fetchall()
            if wars:
                for wrow in wars:
                    tl = time_until(wrow["expires_at"]) or "ending soon"
                    lines.append(f"🏰 *{wrow['name1']}* vs *{wrow['name2']}*")
                    lines.append(f"   Score: {wrow['kills1']} – {wrow['kills2']}  |  {tl} left\n")
            else:
                lines.append("_No guild wars currently active._")

        elif page == 3:
            lines = ["☠️ *All-Time Kill Board*\n"]
            cw.execute("""SELECT username, wins, max_kill_streak
                          FROM players WHERE wins > 0
                          ORDER BY wins DESC LIMIT 15""")
            board = cw.fetchall()
            if board:
                medals = ["🥇","🥈","🥉"]
                for i, r in enumerate(board):
                    medal = medals[i] if i < 3 else f"{i+1}."
                    mks = safe_int(r["max_kill_streak"])
                    streak_txt = f"  (best streak: {mks})" if mks >= 3 else ""
                    lines.append(f"{medal} *{r['username']}* — {r['wins']} kills{streak_txt}")
            else:
                lines.append("_No kills recorded yet._")

        elif page == 4:
            lines = ["🏆 *Guild Hall of Fame — War Records*\n"]
            cw.execute("SELECT name, war_wins FROM guilds WHERE war_wins > 0 ORDER BY war_wins DESC LIMIT 15")
            hall = cw.fetchall()
            if hall:
                medals = ["🥇","🥈","🥉"]
                for i, h in enumerate(hall):
                    medal = medals[i] if i < 3 else f"{i+1}."
                    lines.append(f"{medal} *{h['name']}* — {h['war_wins']} war win{'s' if h['war_wins'] != 1 else ''}")
            else:
                lines.append("_No guild war records yet._")
        else:
            lines = ["⚠️ Invalid page."]

        conn_w.close()
    except Exception as e:
        lines = [f"⚠️ _War board error: {e}_"]

    return "\n".join(lines)

_WAR_PAGE_LABELS = ["Today's Killers", "Bounties", "Guild Wars", "All-Time Board", "Hall of Fame"]

def _war_nav_markup(page: int) -> InlineKeyboardMarkup:
    total = len(_WAR_PAGE_LABELS)
    row = []
    if page > 0:
        row.append(InlineKeyboardButton(f"◀ {_WAR_PAGE_LABELS[page-1]}", callback_data=f"war_p_{page-1}"))
    if page < total - 1:
        row.append(InlineKeyboardButton(f"{_WAR_PAGE_LABELS[page+1]} ▶", callback_data=f"war_p_{page+1}"))
    close_row = [InlineKeyboardButton("❌ Close", callback_data="close_msg")]
    return InlineKeyboardMarkup([row, close_row] if row else [close_row])

async def war_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        resolved = await resolve_expired_wars()
        for r in resolved:
            await send_group(update, r, delay=30)
    except Exception:
        pass

    text = "🔥 *8Ball World — War Board*\n\n" + _war_page_text(0)
    markup = _war_nav_markup(0)
    bot = update.get_bot()
    chat_id = update.effective_chat.id
    try:
        await update.effective_message.delete()
    except Exception:
        pass
    msg = await bot.send_message(chat_id=chat_id, text=text, parse_mode="Markdown", reply_markup=markup)
    asyncio.create_task(_auto_delete(bot, chat_id, msg.message_id, 45))

