async def encounter_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if is_defeated(p):
        await send_group(update, _defeated_msg(p), delay=15); return
    uid = user.id
    if uid in active_encounters:
        await send_group(update, "⚠️ You're already in an encounter! Use the buttons to continue.", delay=10); return
    markup = InlineKeyboardMarkup([
        [InlineKeyboardButton("⚔️ Battle — fight an NPC", callback_data=f"enc_mode_{uid}_battle")],
        [InlineKeyboardButton("🌿 Hunt — fight wild monsters", callback_data=f"enc_mode_{uid}_hunt")],
        [InlineKeyboardButton("🏚️ Dungeon — 6 floors, real-time combat", callback_data=f"enc_mode_{uid}_dungeon")],
        [InlineKeyboardButton("❌ Cancel", callback_data=f"close_msg_{uid}")],
    ])
    await send_group(update, "🎱 *Encounter*\nChoose your mode:\n\n"
                    "⚔️ *Battle* — fight NPCs for EXP and gear\n"
                    "🌿 *Hunt* — fight wild monsters; weaken them to 🎯 catch for *Monster Cores*\n"
                    "🏚️ *Dungeon* — 6 floors, 10 rooms, real-time enemy attacks",
                    reply_markup=markup, permanent=True)


async def _start_encounter_battle(query, uid, p):
    # 5% chance: treasure chest. 7% chance: random event.
    _roll = random.random()
    if _roll < 0.05:
        await _start_encounter_treasure(query, uid, p, "battle"); return
    elif _roll < 0.12:
        await _start_encounter_event(query, uid, p, "battle"); return

    p_level = p.get("level", 1)
    npc = _pick_random_npc(p_level)
    n_level = _enc_npc_level(npc, p_level)
    n_hp, n_atk, reward_mult, num_gear, num_pots, gear_rarities = _enc_level_stats(n_level, p_level)
    p_mhp = safe_int(p.get("max_hp")) or calc_max_hp(p)
    p_hp  = min(p_mhp, max(1, safe_int(p.get("hp")) or p_mhp))
    cls_name = CLASS_TREE.get(npc[1], {}).get("name", npc[1].replace("_"," ").title())
    # Load pet info for enc
    _enc_pet = get_active_pet_record(uid)
    _pet_info = None
    if _enc_pet and not _pet_is_on_adventure(_enc_pet):
        _sp = PET_SPECIES.get(_enc_pet.get("species"), {})
        _, _bond_label = _get_bond_tier(_enc_pet.get("bond_score", 0))
        _pet_info = {
            "pet_id": _enc_pet["pet_id"],
            "name": _enc_pet.get("nickname") or _sp.get("name","Pet"),
            "level": _enc_pet.get("level",1),
            "atk": get_pet_atk_bonus(_enc_pet),
            "bond_label": _bond_label,
            "species": _enc_pet.get("species"),
            "def_ability": _sp.get("def_ability"),
        }
    enc = {
        "uid": uid, "mode": "battle", "p_name": p.get("username", "You"),
        "p_hp": p_hp, "p_max_hp": p_mhp,
        "e_name": npc[0], "e_class": npc[1],
        "e_hp": n_hp, "e_max_hp": n_hp, "e_atk": n_atk, "e_level": n_level,
        "e_gold_range": npc[6], "e_exp_range": npc[7], "e_loot_key": npc[8],
        "action_log": [f"*{npc[0]}* [{cls_name}] Lv.{n_level} steps forward!"],
        "pet_info": _pet_info,
        "pet_ability_used": False,
        "reward_mult": reward_mult, "num_gear": num_gear,
        "num_pots": num_pots, "gear_rarities": gear_rarities,
    }
    active_encounters[uid] = enc
    _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})["mode"] = "battle"
    card = _encounter_battle_card(enc)
    markup = _encounter_battle_markup(enc, p)
    await query.edit_message_text(card, parse_mode="Markdown", reply_markup=markup)

async def _start_encounter_hunt(query, uid, p):
    # 3% chance: treasure chest. 5% chance: random event.
    _roll = random.random()
    if _roll < 0.03:
        await _start_encounter_treasure(query, uid, p, "hunt"); return
    elif _roll < 0.15:
        await _start_encounter_event(query, uid, p, "hunt"); return
    p_level = p.get("level", 1)
    monster = _pick_random_monster(p_level)
    m_level = _enc_monster_level(monster, p_level)
    m_hp, m_atk, reward_mult, num_gear, num_pots, gear_rarities = _enc_level_stats(m_level, p_level)
    p_mhp = safe_int(p.get("max_hp")) or calc_max_hp(p)
    p_hp  = min(p_mhp, max(1, safe_int(p.get("hp")) or p_mhp))
    elem_e = ELEMENT_EMOJI.get(monster[2], "")
    # Load pet info for enc
    _enc_pet = get_active_pet_record(uid)
    _pet_info = None
    if _enc_pet and not _pet_is_on_adventure(_enc_pet):
        _sp = PET_SPECIES.get(_enc_pet.get("species"), {})
        _, _bond_label = _get_bond_tier(_enc_pet.get("bond_score", 0))
        _pet_info = {
            "pet_id": _enc_pet["pet_id"],
            "name": _enc_pet.get("nickname") or _sp.get("name","Pet"),
            "level": _enc_pet.get("level",1),
            "atk": get_pet_atk_bonus(_enc_pet),
            "bond_label": _bond_label,
            "species": _enc_pet.get("species"),
            "def_ability": _sp.get("def_ability"),
        }
    enc = {
        "uid": uid, "mode": "hunt", "p_name": p.get("username", "You"),
        "p_hp": p_hp, "p_max_hp": p_mhp,
        "e_name": monster[1], "e_key": monster[0], "element": monster[2],
        "e_hp": m_hp, "e_max_hp": m_hp, "e_atk": m_atk, "e_level": m_level,
        "e_catch_rate": monster[6],
        "action_log": [f"A wild *{monster[1]}* {elem_e} (Lv.{m_level}) appears!"],
        "pet_info": _pet_info,
        "pet_ability_used": False,
        "reward_mult": reward_mult, "num_gear": num_gear,
        "num_pots": num_pots, "gear_rarities": gear_rarities,
    }
    active_encounters[uid] = enc
    _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})["mode"] = "hunt"
    card = _encounter_battle_card(enc)
    markup = _encounter_battle_markup(enc, p)
    await query.edit_message_text(card, parse_mode="Markdown", reply_markup=markup)

async def _start_encounter_treasure(query, uid, p, mode="battle"):
    tier = random.choices(["wooden", "iron", "golden"], weights=[60, 30, 10])[0]
    enc = {
        "uid": uid, "mode": "treasure", "p_name": p.get("username", "You"),
        "chest_tier": tier,
        "action_log": [],
    }
    active_encounters[uid] = enc
    _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})["mode"] = mode
    await query.edit_message_text(_treasure_card(enc), parse_mode="Markdown",
                                  reply_markup=_treasure_markup(enc))

async def _start_encounter_event(query, uid, p, mode="battle"):
    etype = random.choice(list(_RANDOM_EVENTS.keys()))
    enc = {
        "uid": uid, "mode": "event", "p_name": p.get("username", "You"),
        "event_type": etype,
        "action_log": [],
    }
    active_encounters[uid] = enc
    _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})["mode"] = mode
    await query.edit_message_text(_event_card(enc), parse_mode="Markdown",
                                  reply_markup=_event_markup(enc))

async def enc_next_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Continue / Retry / End buttons after an encounter result screen."""
    query = update.callback_query
    data  = query.data  # enc_next_{uid}_{action}
    parts = data.split("_")
    try:
        uid    = int(parts[2])
        action = parts[3]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your button!", show_alert=True); return
    await query.answer()

    if action == "end":
        sess = _enc_sessions.pop(uid, {})
        wins    = sess.get("wins", 0)
        losses  = sess.get("losses", 0)
        g_total = sess.get("gold", 0)
        e_total = sess.get("exp", 0)
        items   = sess.get("items", [])
        mode    = sess.get("mode", "battle")
        mode_label = "⚔️ NPC Battle" if mode == "battle" else ("🌿 Hunt" if mode == "hunt" else "🏰 Dungeon")
        lines = [f"🏁 *{mode_label} Session Complete!*", ""]
        lines.append(f"⚔️ Wins: *{wins}*  |  💀 Losses: *{losses}*")
        if g_total: lines.append(f"💰 Gold earned: *+{g_total:,}*")
        if e_total: lines.append(f"⭐ EXP earned:  *+{e_total:,}*")
        if items:
            lines.append("")
            lines.append("*🎒 Items Collected:*")
            _item_counts = {}
            for _itm in items:
                _item_counts[_itm] = _item_counts.get(_itm, 0) + 1
            for _itm, _cnt in sorted(_item_counts.items()):
                prefix = f"×{_cnt} " if _cnt > 1 else ""
                lines.append(f"  {prefix}*{_itm}*")
        if not wins and not losses and not items:
            lines.append("_No battles completed._")
        try:
            await query.edit_message_text("\n".join(lines), parse_mode="Markdown")
        except Exception: pass
        return

    # Continue or Retry: restart in the same mode (no picker shown)
    p = get_player(uid)
    if not p:
        try: await query.edit_message_text("Player data not found."); return
        except Exception: return
    if uid in active_encounters:
        await query.answer("Already in an encounter!", show_alert=True); return

    sess = _enc_sessions.get(uid, {})
    mode = sess.get("mode", "battle")

    if mode == "hunt":
        await _start_encounter_hunt(query, uid, p)
    else:
        await _start_encounter_battle(query, uid, p)


async def encounter_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    # Do NOT answer here — each branch answers (or show_alert) itself so we
    # don't conflict with subsequent query.answer(show_alert=True) calls.
    data  = query.data
    uid   = update.effective_user.id

    # ── mode select ─────────────────────────────────────────────────────────
    if data.startswith("enc_mode_"):
        parts = data.split("_"); target_uid = int(parts[2]); mode = parts[3]
        if uid != target_uid:
            await query.answer("Not your encounter!", show_alert=True); return
        p = get_player(uid)
        if not p: await query.answer(); return
        if uid in active_encounters:
            await query.answer("Already in an encounter!", show_alert=True); return
        await query.answer()
        if mode == "battle":
            await _start_encounter_battle(query, uid, p)
        elif mode == "dungeon":
            if uid in active_dungeons:
                await query.answer("Already in a dungeon! Use the dungeon buttons to continue.", show_alert=True); return
            chat_id = query.message.chat_id
            floors = [_dng_gen_floor(f + 1) for f in range(_DNG_FLOORS)]
            state = {
                "uid": uid, "floor": 1, "room": 1, "phase": "room",
                "p_hp": min(safe_int(p.get("hp", 1)) or calc_max_hp(p), calc_max_hp(p)),
                "p_max_hp": calc_max_hp(p),
                "p_name": p.get("username", "You"),
                "floors": floors,
                "s_gold": 0, "s_exp": 0, "s_items": [],
                "chat_id": chat_id, "msg_id": None,
                "combat_log": [], "enemy": None,
                "floor_modifier": None,
            }
            active_dungeons[uid] = state
            narr = _dng_roll_narration("floor_entry")
            intro = (
                f"🏚️ *The Dungeon — Floor 1*\n\n_{narr}_\n\n"
                f"*6 floors. 10 rooms each. Real-time combat.*\n"
                f"Die and you lose everything. Extract to keep your rewards.\n\n"
                f"❤️ HP: {state['p_hp']}/{state['p_max_hp']}"
            )
            msg = await context.bot.send_message(chat_id=chat_id, text=intro, parse_mode="Markdown",
                  reply_markup=InlineKeyboardMarkup([[
                      InlineKeyboardButton("⚔️ Enter the Dungeon", callback_data=f"dng_enter_{uid}"),
                  ]]))
            state["msg_id"] = msg.message_id
        else:
            await _start_encounter_hunt(query, uid, p)
        return

    # ── Treasure chest ───────────────────────────────────────────────────────
    _chest_match = re.match(r"enc_(?:open|leave)_(\d+)$", data)
    if _chest_match:
        owner_uid = int(_chest_match.group(1))
        if uid != owner_uid:
            await query.answer("Not your encounter!", show_alert=True); return
        uid = owner_uid
        enc = active_encounters.get(uid)
        if not enc or enc.get("mode") != "treasure":
            await query.answer(); await query.edit_message_text("No active chest."); return
        p = get_player(uid)
        if not p: await query.answer(); return
        await query.answer()
        active_encounters.pop(uid, None)
        tier = enc.get("chest_tier", "wooden")
        td   = _CHEST_TIERS[tier]
        action = "open" if "open" in data else "leave"
        result_markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("⚔️ Continue", callback_data=f"enc_next_{uid}_continue"),
            InlineKeyboardButton("🏁 End",      callback_data=f"enc_next_{uid}_end"),
        ]])
        if action == "leave":
            try:
                await query.edit_message_text(f"🚶 You walk past the chest.\n_Safety first._",
                                              parse_mode="Markdown", reply_markup=result_markup)
            except Exception: pass
            return
        # Open the chest
        td_gold_min, td_gold_max = td["gold"]
        gold_found = random.randint(td_gold_min, td_gold_max)
        exp_found  = random.randint(*td["exp"])
        # Curse check: lose gold/exp instead
        if random.random() < td["curse_chance"]:
            gold_penalty = random.randint(20, 150)
            exp_penalty  = random.randint(10, 50)
            p["gold"] = max(0, safe_int(p.get("gold", 0)) - gold_penalty)
            save_player(p)
            try:
                await query.edit_message_text(
                    f"💀 *CURSED CHEST!*\n_{td['emoji']} The chest springs a trap!_\n"
                    f"Lost *{gold_penalty} gold* and *{exp_penalty} EXP*! Watch your greed...",
                    parse_mode="Markdown", reply_markup=result_markup)
            except Exception: pass
            return
        # Normal rewards
        p["gold"] = safe_int(p.get("gold", 0)) + gold_found
        add_exp(p, exp_found)
        loot_lines = [f"💰 +{gold_found} gold", f"⭐ +{exp_found} EXP"]
        gear_drop = None
        if random.random() < td["gear_chance"]:
            p_lv = p.get("level", 1)
            if p_lv < 20:   _rar = random.choice(["common", "uncommon"])
            elif p_lv < 40: _rar = random.choice(["uncommon", "rare"])
            elif p_lv < 60: _rar = random.choice(["rare", "epic"])
            else:           _rar = random.choice(["rare", "epic", "legendary"])
            _gear_pool = [n for n, d in {**WEAPONS, **ARMORS, **SHIELDS, **ACCESSORIES, **HATS, **GLOVES, **BOOTS, **MASKS}.items() if d.get("rarity") == _rar]
            gear_drop = random.choice(_gear_pool) if _gear_pool else None
        if gear_drop:
            inv = sjl(p.get("inventory"), []); inv.append(gear_drop); p["inventory"] = json.dumps(inv)
            loot_lines.append(f"🎁 Found: *{gear_drop}*!")
        # Bonus potion
        if random.random() < 0.15:
            potion = random.choice(["Health Potion", "Greater Health Potion"])
            inv = sjl(p.get("inventory"), []); inv.append(potion); p["inventory"] = json.dumps(inv)
            loot_lines.append(f"🧪 *{potion}*!")
        save_player(p)
        _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})["wins"] = \
            _enc_sessions.get(uid, {}).get("wins", 0) + 1
        try:
            await query.edit_message_text(
                f"🎉 *{td['emoji']} Chest Opened!*\n" + "\n".join(loot_lines),
                parse_mode="Markdown", reply_markup=result_markup)
        except Exception: pass
        return

    # ── Random events ────────────────────────────────────────────────────────
    _event_match = re.match(r"enc_event_(\d+)_(\w+)$", data)
    if _event_match:
        owner_uid = int(_event_match.group(1))
        choice    = _event_match.group(2)
        if uid != owner_uid:
            await query.answer("Not your encounter!", show_alert=True); return
        uid = owner_uid
        enc = active_encounters.get(uid)
        if not enc or enc.get("mode") != "event":
            await query.answer(); await query.edit_message_text("No active event."); return
        p = get_player(uid)
        if not p: await query.answer(); return
        await query.answer()
        active_encounters.pop(uid, None)
        etype = enc.get("event_type", "shrine")
        result_markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("⚔️ Continue", callback_data=f"enc_next_{uid}_continue"),
            InlineKeyboardButton("🏁 End",      callback_data=f"enc_next_{uid}_end"),
        ]])
        result_text = "..."
        if choice == "skip":
            result_text = "🚶 You move on, leaving the encounter behind."
        elif etype == "merchant" and choice == "buy":
            # Sell a random item from stock
            _merch_items = [("Health Potion", 60), ("Greater Health Potion", 150),
                            ("Fortune Coin", 50), ("Pet Snack", 25)]
            item_name, cost = random.choice(_merch_items)
            if safe_int(p.get("gold", 0)) >= cost:
                p["gold"] = safe_int(p.get("gold", 0)) - cost
                inv = sjl(p.get("inventory"), []); inv.append(item_name); p["inventory"] = json.dumps(inv)
                result_text = f"🛒 *Deal made!*\nBought *{item_name}* for {cost} gold."
            else:
                result_text = f"🛒 *No deal!*\nYou don't have enough gold ({cost}g needed)."
        elif etype == "shrine" and choice == "pray":
            _r = random.random()
            if _r < 0.50:
                exp_bonus = random.randint(50, 200)
                add_exp(p, exp_bonus)
                result_text = f"🗿 *The shrine glows warmly.*\n+{exp_bonus} EXP blessed upon you!"
            elif _r < 0.75:
                hp_restore = round(calc_max_hp(p) * 0.30)
                p["hp"] = min(calc_max_hp(p), safe_int(p.get("hp", 0)) + hp_restore)
                result_text = f"🗿 *Holy energy fills you.*\n+{hp_restore} HP restored!"
            else:
                gold_drain = random.randint(10, 60)
                p["gold"] = max(0, safe_int(p.get("gold", 0)) - gold_drain)
                result_text = f"🗿 *The shrine rumbles and takes its tithe.*\n−{gold_drain} gold vanished..."
        elif etype == "fallen" and choice == "loot":
            _r = random.random()
            if _r < 0.55:
                p_lv = p.get("level", 1)
                _rar = "common" if p_lv < 20 else ("uncommon" if p_lv < 40 else "rare")
                _pool = [n for n, d in {**WEAPONS, **ARMORS, **SHIELDS, **ACCESSORIES, **HATS, **GLOVES, **BOOTS, **MASKS}.items() if d.get("rarity") == _rar]
                item = random.choice(_pool) if _pool else "Health Potion"
                inv = sjl(p.get("inventory"), []); inv.append(item); p["inventory"] = json.dumps(inv)
                result_text = f"💀 *Found something.*\n🎁 *{item}* recovered from the pack."
            else:
                gold = random.randint(15, 80)
                p["gold"] = safe_int(p.get("gold", 0)) + gold
                result_text = f"💀 *Found some coin.*\n💰 +{gold} gold recovered."
        elif etype == "ambush" and choice == "fight":
            # Quick skirmish: win/lose based on player stats
            _enc_w = get_weather()
            player_dmg = calc_attack_damage(p, _enc_w)
            bandit_hp  = random.randint(int(p.get("max_hp", 100) * 0.3), int(p.get("max_hp", 100) * 0.7))
            rounds = 0
            while bandit_hp > 0 and rounds < 10:
                bandit_hp -= player_dmg; rounds += 1
            if bandit_hp <= 0:
                gold_stolen = random.randint(30, 120)
                p["gold"] = safe_int(p.get("gold", 0)) + gold_stolen
                result_text = (f"⚔️ *Bandits defeated!*\nYou fought off the ambush in {rounds} strike(s)!\n"
                               f"💰 +{gold_stolen} gold from their pockets!")
            else:
                gold_loss = max(0, safe_int(p.get("gold", 0)) // 50)
                p["gold"] = safe_int(p.get("gold", 0)) - gold_loss
                result_text = f"⚠️ *Overwhelmed!*\nThe bandits grabbed {gold_loss} gold before fleeing!"
        elif etype == "ambush" and choice == "flee":
            _r = random.random()
            if _r < 0.65:
                result_text = "🏃 *Escaped!*\nYou slipped away before they could grab you."
            else:
                result_text = f"⚠️ *Couldn't shake them!* Took damage in the chaos."
        save_player(p)
        try:
            await query.edit_message_text(result_text, parse_mode="Markdown", reply_markup=result_markup)
        except Exception: pass
        return

    # ── All in-combat actions: parse owner uid from callback data ───────────
    # All combat buttons embed the owner's uid: enc_atk_{uid}, enc_flee_{uid}, etc.
    # Validate ownership first so random clickers can't corrupt the battle card.
    _enc_combat_match = re.match(r"enc_(?:atk|skl|heal|flee|mv|catch|switch|guard|pet)_(\d+)", data)
    if _enc_combat_match:
        owner_uid = int(_enc_combat_match.group(1))
        if query.from_user.id != owner_uid:
            await query.answer("Not your encounter!", show_alert=True); return
        uid = owner_uid

    # Stop Telegram's spinner immediately — before any DB operations
    try:
        await query.answer()
    except Exception:
        pass

    # ── All in-combat actions require an active encounter ────────────────────
    enc = active_encounters.get(uid)
    if not enc:
        try:
            await query.edit_message_text(
                "⚠️ *Encounter session expired.*\nThe bot may have restarted. Use /encounter to start a new one.",
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton("▶️ New Encounter", callback_data=f"enc_mode_{uid}_battle"),
                    InlineKeyboardButton("🌿 New Hunt", callback_data=f"enc_mode_{uid}_hunt"),
                ]]))
        except Exception:
            pass
        return

    p = get_player(uid)
    if not p: return

    # Helper: end encounter (win/lose/flee)
    async def _end_encounter(result_text, gave_rewards=False):
        active_encounters.pop(uid, None)
        # Clear any turn-based combat debuffs so they don't bleed into the next session
        for _cf in ("heal_blocked_turns", "revive_blocked_turns", "silence_turns", "hex_turns",
                    "stun_turns", "freeze_turns", "entangle_turns", "distract_turns"):
            if safe_int(p.get(_cf)) > 0:
                p[_cf] = 0
        save_player(p)
        # Accumulate session stats
        sess = _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})
        if "Victory" in result_text or "defeated!" in result_text or "Caught!" in result_text:
            sess["wins"] += 1
        elif "defeated by" in result_text or "knocked you out" in result_text:
            sess["losses"] += 1
        is_win = sess["wins"] > 0 and ("Victory" in result_text or "defeated!" in result_text or "Caught!" in result_text or "broke free" not in result_text)
        is_loss = "defeated by" in result_text or "knocked you out" in result_text
        # Build continue/retry/end buttons
        enc_mode = enc.get("mode", "battle")
        if is_loss:
            result_markup = InlineKeyboardMarkup([[
                InlineKeyboardButton("🔄 Retry", callback_data=f"enc_next_{uid}_retry"),
                InlineKeyboardButton("🏁 End", callback_data=f"enc_next_{uid}_end"),
            ]])
        else:
            result_markup = InlineKeyboardMarkup([[
                InlineKeyboardButton("⚔️ Continue", callback_data=f"enc_next_{uid}_continue"),
                InlineKeyboardButton("🏁 End", callback_data=f"enc_next_{uid}_end"),
            ]])
        try:
            await query.answer()
        except Exception:
            pass
        try:
            await query.edit_message_text(result_text, parse_mode="Markdown", reply_markup=result_markup)
        except Exception:
            try:
                await context.bot.send_message(query.message.chat_id, result_text,
                    parse_mode="Markdown", reply_markup=result_markup)
            except Exception:
                pass
            # Old card still has active buttons — strip them so stale taps don't trigger
            try:
                await query.edit_message_reply_markup(reply_markup=None)
            except Exception:
                pass

    # ── FLEE ────────────────────────────────────────────────────────────────
    if data == f"enc_flee_{uid}":
        flee_chance = 0.6
        if random.random() < flee_chance:
            await _end_encounter("🏃 *You fled safely!*")
        else:
            npc_act = _enc_npc_attack(enc, p) if enc["mode"] == "battle" else _enc_monster_attack(enc)
            if enc["p_hp"] <= 0:
                await _end_encounter(f"💀 *You were knocked out trying to flee!*")
            else:
                enc.setdefault("action_log",[]).append(f"🏃 Flee failed!")
                enc.setdefault("action_log",[]).append(npc_act)
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await query.edit_message_text(_encounter_battle_card(enc),
                                                      reply_markup=_encounter_battle_markup(enc, p))
                    except Exception:
                        try:
                            await context.bot.send_message(
                                query.message.chat_id, _encounter_battle_card(enc),
                                parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                        except Exception: pass
        return

    # ── BATTLE MODE ACTIONS ─────────────────────────────────────────────────
    if enc["mode"] == "battle":
        action_txt = ""
        # Stun / paralyze / freeze / fear: block ALL player actions this turn
        _p_blocked = enc.pop("p_stunned", False) or enc.pop("p_skip", False)
        if _p_blocked:
            action_txt = "⚡ You're stunned and lose your turn!"
        elif data == f"enc_atk_{uid}":
            _enc_w = get_weather()
            dmg    = calc_attack_damage(p, _enc_w)
            if enc.pop("p_weakened", False): dmg = max(1, int(dmg * 0.65))
            if enc.pop("p_slow", False):     dmg = max(1, int(dmg * 0.80))
            if enc.pop("p_blind", False) and random.random() < 0.40:
                action_txt = "👁️ You swing blindly and miss!"
            else:
                _enc_crit = ""
                if check_crit(p):
                    dmg = apply_crit(p, dmg); _enc_crit = " 💥 *CRIT!*"
                enc["e_hp"] = max(0, enc["e_hp"] - dmg)
                pet_extra = ""
                pet_info = enc.get("pet_info")
                if pet_info and pet_info.get("atk", 0) > 0:
                    pet_dmg = max(1, int(pet_info["atk"] * random.uniform(0.8, 1.2)))
                    enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                    pet_extra = f"\n🐾 *{pet_info['name']}* strikes for *{pet_dmg}*!"
                _enc_extras = _enc_crit
                if get_enchant_bonus(p, "burn_proc") and random.random() < 0.10:
                    enc["e_burning"] = True; _enc_extras += "\n🔥 Your weapon *ignites* the enemy!"
                if get_enchant_bonus(p, "lifesteal_flat"):
                    _ls = max(1, round(dmg * 0.15))
                    enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _ls)
                    _enc_extras += f"\n💜 Lifesteal +{_ls} HP!"
                _enc_cls  = get_player_class(p)
                _enc_pk   = _enc_cls.get("passive_key", "") if _enc_cls else ""
                _enc_path = p.get("class_path", "A")
                _enc_line = get_class_line(p)
                if dmg > 0:
                    if _enc_line == "warrior" and _enc_path == "A" and random.random() < 0.10:
                        enc["e_burning"] = True; _enc_extras += "\n⚔️ *Blessed Strike!* Holy fire ignites!"
                    elif _enc_line == "mage" and _enc_path == "A" and random.random() < 0.12:
                        enc["e_burning"] = True; _enc_extras += "\n🔥 *Arcane Burn!* Magical fire clings!"
                    elif _enc_line == "thief" and _enc_path == "A" and random.random() < 0.15:
                        enc["e_poisoned"] = True; _enc_extras += "\n🐍 *Poison Strike!* The blade was coated in poison!"
                    elif _enc_line == "archer" and _enc_path == "A" and random.random() < 0.12:
                        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
                        _enc_extras += "\n🏹 *Pin Down!* Enemy distracted — stunned 1 turn!"
                    if _enc_pk == "curse_touch" and random.random() < 0.08:
                        enc["e_weakened"] = True; _enc_extras += "\n💜 *Curse Touch!* Enemy weakened!"
                action_txt = f"You attacked for *{dmg}* damage!{pet_extra}{_enc_extras}"

        elif data.startswith(f"enc_skl_{uid}_"):
            p_skills = get_combat_skills(p)
            try:
                idx = int(data[len(f"enc_skl_{uid}_"):])
                sk  = p_skills[idx]
            except (ValueError, IndexError):
                await query.answer("Skill not available!", show_alert=True); return
            _HEAL_LIMIT_TYPES = {"self_heal","self_heal_buff","group_heal","revive_heal",
                                 "regen","heal_shield","mass_cleanse","full_revive","aoe_heal_dmg"}
            if sk.get("type") in _HEAL_LIMIT_TYPES or str(sk.get("type","")).endswith("heal"):
                if enc.get("skill_heal_uses", 0) >= 3:
                    await query.answer("🚫 Heal limit reached (3/3)! Healing skills exhausted.", show_alert=True)
                    return
            action_txt, _sk_dmg, _is_support = _enc_process_skill(enc, p, sk)
            if _is_support:
                enc["skill_heal_uses"] = enc.get("skill_heal_uses", 0) + 1
                npc_act = _enc_npc_attack(enc, p)
                dot_txt = _apply_dot_tick(enc)
                if dot_txt: npc_act += f"\n_{dot_txt}_"
                if enc["p_hp"] <= 0:
                    await _end_encounter(f"💀 *You were defeated by {enc['e_name']}!*")
                    return
                enc.setdefault("action_log", []).append(action_txt)
                enc.setdefault("action_log", []).append(npc_act)
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                save_player(p)
                context.user_data["encounter"] = enc
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await query.edit_message_text(_encounter_battle_card(enc),
                                                      reply_markup=_encounter_battle_markup(enc, p))
                    except Exception:
                        try:
                            await context.bot.send_message(
                                query.message.chat_id, _encounter_battle_card(enc),
                                parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                        except Exception: pass
                return
            # Damage skills fall through to the normal NPC-attack-back flow below

        elif data == f"enc_heal_{uid}":
            _inv = sjl(p.get("inventory"), [])
            _potion, _heal = None, 0
            if "Grand Restorative Flask" in _inv:   _potion, _heal = "Grand Restorative Flask", 1500
            elif "Greater Health Potion" in _inv:   _potion, _heal = "Greater Health Potion", 500
            elif "Health Potion" in _inv:           _potion, _heal = "Health Potion", 250
            if not _potion:
                enc.setdefault("action_log", []).append("🧪 No potions in your bag!")
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc))
                except Exception: pass
                return
            _inv.remove(_potion); p["inventory"] = json.dumps(_inv); save_player(p)
            _hex_note = ""
            if enc.pop("p_hexed", False): _heal = max(1, _heal // 2); _hex_note = " *(Hexed — half heal)*"
            enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _heal)
            action_txt = f"🧪 Used *{_potion}*!{_hex_note} +{_heal} HP! ({enc['p_hp']}/{enc['p_max_hp']})"
            npc_act = _enc_npc_attack(enc, p)
            dot_txt = _apply_dot_tick(enc)
            if dot_txt: npc_act += f"\n_{dot_txt}_"
            if enc["p_hp"] <= 0:
                await _end_encounter(f"💀 *You were defeated by {enc['e_name']}!*")
                return
            enc.setdefault("action_log",[]).append(action_txt)
            enc.setdefault("action_log",[]).append(npc_act)
            if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
            try:
                await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                              reply_markup=_encounter_battle_markup(enc, p))
            except Exception:
                try:
                    await query.edit_message_text(_encounter_battle_card(enc),
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await context.bot.send_message(
                            query.message.chat_id, _encounter_battle_card(enc),
                            parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                    except Exception: pass
            return

        elif data == f"enc_guard_{uid}":
            enc["p_guarding"] = True
            action_txt = "🛡️ You brace for impact! *(40% damage reduction next hit)*"

        elif data == f"enc_pet_{uid}":
            if enc.get("pet_ability_used"):
                await query.answer("Pet ability already used this battle!", show_alert=True); return
            pet_info = enc.get("pet_info")
            if not pet_info:
                await query.answer("No active pet!", show_alert=True); return
            enc["pet_ability_used"] = True
            da = pet_info.get("def_ability","shield")
            patk = pet_info.get("atk", 5)
            pname = pet_info.get("name","Pet")
            # Offensive use of pet ability
            if da in ("counter","stun","poison"):
                pet_dmg = max(1, int(patk * 1.8 * random.uniform(0.9, 1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                if da == "stun":
                    enc["e_stunned_turns"] = 1
                    action_txt = f"🐾 *{pname}* stuns the enemy for *{pet_dmg}* dmg! ⚡ Enemy stunned!"
                elif da == "poison":
                    enc["e_poisoned"] = True
                    action_txt = f"🐾 *{pname}* poisons the enemy for *{pet_dmg}* dmg! ☠️ Poisoned!"
                else:
                    action_txt = f"🐾 *{pname}* counter-strikes for *{pet_dmg}* dmg!"
            elif da == "lifesteal":
                pet_dmg = max(1, int(patk * 1.5 * random.uniform(0.9, 1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                heal_amt = round(enc["p_max_hp"] * 0.20)
                enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + heal_amt)
                action_txt = f"🐾 *{pname}* drains *{pet_dmg}* dmg and heals you *{heal_amt}* HP! 💜"
            elif da == "shield":
                shield_hp = max(5, patk * 2)
                enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + shield_hp)
                action_txt = f"🐾 *{pname}* creates a shield, restoring *{shield_hp}* HP! ✨"
            else:
                pet_dmg = max(1, int(patk * 1.4 * random.uniform(0.9,1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                action_txt = f"🐾 *{pname}* attacks for *{pet_dmg}* dmg!"

        else:
            # Unknown action — do nothing, card stays as-is
            pass

        # Check enemy dead
        if enc["e_hp"] <= 0:
            # kill_heal enchant: restore HP on kill
            _kh = get_enchant_bonus(p, "kill_heal")
            if _kh:
                enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _kh)
            e_level = enc.get("e_level", 1)
            gold_r = enc.get("e_gold_range", (5, 15))
            gold   = (random.randint(*gold_r) if isinstance(gold_r, tuple) else random.randint(5, 30)) * 4 + e_level * 20
            exp_r  = enc.get("e_exp_range", (20, 50))
            # Scale EXP so ~100 fights earns one level's worth of EXP
            exp    = exp_for_level(max(1, e_level)) // 100 + (random.randint(*exp_r) if isinstance(exp_r, tuple) else random.randint(20, 50))

            # Close-fight bonus
            hp_pct = enc["p_hp"] / max(1, enc["p_max_hp"])
            close_bonus = ""
            if hp_pct <= 0.15:
                gold = int(gold * 2.0); exp = int(exp * 2.0)
                close_bonus = "\n🔥 *Clutch Victory!* Bonus rewards for surviving on the edge!"
            elif hp_pct <= 0.30:
                gold = int(gold * 1.5); exp = int(exp * 1.5)
                close_bonus = "\n⚔️ *Close Fight Bonus!*"

            # Apply level-based reward multiplier
            reward_mult = enc.get("reward_mult", 1.0)
            gold = round(gold * reward_mult)
            exp  = round(exp  * reward_mult)

            add_exp(p, exp)
            p["gold"] = safe_int(p.get("gold", 0)) + gold
            asyncio.create_task(_party_exp_bonus(context.bot, uid, exp, f"*{enc['e_name']}*"))

            # Gear drops — full item pool including all rarities
            _num_gear = enc.get("num_gear", 2)
            gear_rarities = enc.get("gear_rarities", ["uncommon", "rare"])
            _gear_all = {**WEAPONS, **ARMORS, **SHIELDS, **ACCESSORIES, **HATS, **GLOVES, **BOOTS, **MASKS}
            gear_drops = []
            for _gi in range(_num_gear):
                _rar = random.choice(gear_rarities)
                _gp = [n for n, d in _gear_all.items() if d.get("rarity") == _rar]
                if not _gp: _gp = [n for n, d in _gear_all.items() if d.get("rarity") in ("rare","epic")]
                if _gp:
                    _gd = random.choice(_gp)
                    gear_drops.append(_gd)
                    add_item(p, _gd)

            # Potions — scarce, chance-based
            _num_pots = enc.get("num_pots", 0)
            _potion_pool = ["Health Potion","Greater Health Potion","Greater Health Potion"]
            potion_drops = [random.choice(_potion_pool) for _ in range(_num_pots)]
            if not potion_drops and random.random() < 0.20:
                potion_drops = ["Health Potion"]
            for _pt in potion_drops: add_item(p, _pt)

            # Extra consumable drop
            extra_drop = None
            if random.random() < 0.70:
                _extras = ["Fortune Coin","Enchanting Scroll","Pet Snack","Iron Shard","Fortune Coin"]
                extra_drop = random.choice(_extras); add_item(p, extra_drop)

            # Loot key item
            loot_key  = enc.get("e_loot_key", "Encounter Token")
            loot_item = loot_key if random.random() < 0.60 else None
            if loot_item: add_item(p, loot_item)

            # Track in session
            _sess = _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})
            _sess["gold"] = _sess.get("gold", 0) + gold
            _sess["exp"]  = _sess.get("exp",  0) + exp
            for _si in gear_drops + potion_drops + ([extra_drop] if extra_drop else []) + ([loot_item] if loot_item else []):
                _sess.setdefault("items", []).append(_si)

            loot_line = ""
            for _gd in gear_drops:   loot_line += f"\n🎁 *{_gd}*"
            for _pt in potion_drops: loot_line += f"\n🧪 *{_pt}*"
            if extra_drop:           loot_line += f"\n✨ *{extra_drop}*"
            if loot_item:            loot_line += f"\n📦 *{loot_item}*"
            await _end_encounter(
                f"✅ *Victory!*\n*{enc['e_name']}* was defeated!{close_bonus}\n"
                f"💰 +{gold:,} gold | ⭐ +{exp:,} EXP{loot_line}")
            return

        # NPC attacks back
        npc_act = _enc_npc_attack(enc, p)
        # DOT tick (player and enemy)
        dot_txt = _apply_dot_tick(enc)
        if dot_txt: npc_act += f"\n_{dot_txt}_"
        # Enemy may have died from DOT
        if enc["e_hp"] <= 0:
            enc.setdefault("action_log",[]).append(action_txt)
            enc.setdefault("action_log",[]).append(npc_act)
            await _end_encounter(f"☠️ *{enc['e_name']}* was defeated by status effects!\n✅ *Victory!*")
            return
        # Check player dead
        if enc["p_hp"] <= 0:
            await _end_encounter(f"💀 *You were defeated by {enc['e_name']}!*")
            return
        enc.setdefault("action_log",[]).append(action_txt)
        enc.setdefault("action_log",[]).append(npc_act)
        if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
        try:
            await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                          reply_markup=_encounter_battle_markup(enc, p))
        except Exception:
            try:
                await query.edit_message_text(_encounter_battle_card(enc),
                                              reply_markup=_encounter_battle_markup(enc, p))
            except Exception:
                try:
                    await context.bot.send_message(
                        query.message.chat_id, _encounter_battle_card(enc),
                        parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                except Exception: pass
        return

    # ── HUNT MODE ACTIONS ────────────────────────────────────────────────────
    if enc["mode"] == "hunt":
        action_txt = ""
        # Stun / paralyze / freeze / fear: block ALL player actions this turn
        _ph_blocked = enc.pop("p_stunned", False) or enc.pop("p_skip", False)
        if _ph_blocked:
            action_txt = "⚡ You're stunned and lose your turn!"
        elif data == f"enc_atk_{uid}":
            _hunt_w = get_weather()
            dmg     = calc_attack_damage(p, _hunt_w)
            if enc.pop("p_weakened", False): dmg = max(1, int(dmg * 0.65))
            if enc.pop("p_slow", False):     dmg = max(1, int(dmg * 0.80))
            elem_e = ELEMENT_EMOJI.get(enc.get("element",""), "")
            if enc.pop("p_blind", False) and random.random() < 0.40:
                action_txt = f"👁️ You swing blindly at *{enc['e_name']}* {elem_e} and miss!"
            else:
                _hunt_crit = ""
                if check_crit(p):
                    dmg = apply_crit(p, dmg); _hunt_crit = " 💥 *CRIT!*"
                enc["e_hp"] = max(0, enc["e_hp"] - dmg)
                pet_extra = ""
                pet_info = enc.get("pet_info")
                if pet_info and pet_info.get("atk", 0) > 0:
                    pet_dmg = max(1, int(pet_info["atk"] * random.uniform(0.8, 1.2)))
                    enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                    pet_extra = f"\n🐾 *{pet_info['name']}* strikes for *{pet_dmg}*!"
                _enc_extras = _hunt_crit
                if get_enchant_bonus(p, "burn_proc") and random.random() < 0.10:
                    enc["e_burning"] = True; _enc_extras += "\n🔥 Your weapon *ignites* the enemy!"
                if get_enchant_bonus(p, "lifesteal_flat"):
                    _ls = max(1, round(dmg * 0.15))
                    enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _ls)
                    _enc_extras += f"\n💜 Lifesteal +{_ls} HP!"
                _hunt_cls  = get_player_class(p)
                _hunt_pk   = _hunt_cls.get("passive_key", "") if _hunt_cls else ""
                _hunt_path = p.get("class_path", "A")
                _hunt_line = get_class_line(p)
                if dmg > 0:
                    if _hunt_line == "warrior" and _hunt_path == "A" and random.random() < 0.10:
                        enc["e_burning"] = True; _enc_extras += "\n⚔️ *Blessed Strike!* Holy fire ignites!"
                    elif _hunt_line == "mage" and _hunt_path == "A" and random.random() < 0.12:
                        enc["e_burning"] = True; _enc_extras += "\n🔥 *Arcane Burn!* Magical fire clings!"
                    elif _hunt_line == "thief" and _hunt_path == "A" and random.random() < 0.15:
                        enc["e_poisoned"] = True; _enc_extras += "\n🐍 *Poison Strike!* The blade was coated in poison!"
                    elif _hunt_line == "archer" and _hunt_path == "A" and random.random() < 0.12:
                        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
                        _enc_extras += "\n🏹 *Pin Down!* Enemy distracted — stunned 1 turn!"
                    if _hunt_pk == "curse_touch" and random.random() < 0.08:
                        enc["e_weakened"] = True; _enc_extras += "\n💜 *Curse Touch!* Enemy weakened!"
                action_txt = f"You attacked *{enc['e_name']}* {elem_e} for *{dmg}* damage!{pet_extra}{_enc_extras}"

        elif data.startswith(f"enc_skl_{uid}_"):
            p_skills = get_combat_skills(p)
            try:
                idx = int(data[len(f"enc_skl_{uid}_"):])
                sk  = p_skills[idx]
            except (ValueError, IndexError):
                await query.answer("Skill not available!", show_alert=True); return
            _HEAL_LIMIT_TYPES = {"self_heal","self_heal_buff","group_heal","revive_heal",
                                 "regen","heal_shield","mass_cleanse","full_revive","aoe_heal_dmg"}
            if sk.get("type") in _HEAL_LIMIT_TYPES or str(sk.get("type","")).endswith("heal"):
                if enc.get("skill_heal_uses", 0) >= 3:
                    await query.answer("🚫 Heal limit reached (3/3)! Healing skills exhausted.", show_alert=True)
                    return
            action_txt, _hsk_dmg, _is_support = _enc_process_skill(enc, p, sk)
            if _is_support:
                enc["skill_heal_uses"] = enc.get("skill_heal_uses", 0) + 1
                mon_act = _enc_monster_attack(enc)
                dot_txt = _apply_dot_tick(enc)
                if dot_txt: mon_act += f"\n_{dot_txt}_"
                if enc["p_hp"] <= 0:
                    await _end_encounter(f"💀 *{enc['e_name']}* knocked you out!")
                    return
                enc.setdefault("action_log", []).append(action_txt)
                enc.setdefault("action_log", []).append(mon_act)
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                save_player(p)
                context.user_data["encounter"] = enc
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await query.edit_message_text(_encounter_battle_card(enc),
                                                      reply_markup=_encounter_battle_markup(enc, p))
                    except Exception:
                        try:
                            await context.bot.send_message(
                                query.message.chat_id, _encounter_battle_card(enc),
                                parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                        except Exception: pass
                return
            # Damage skills fall through to the normal monster-attack-back flow below

        elif data == f"enc_heal_{uid}":
            _inv = sjl(p.get("inventory"), [])
            _potion, _heal = None, 0
            if "Grand Restorative Flask" in _inv:   _potion, _heal = "Grand Restorative Flask", 1500
            elif "Greater Health Potion" in _inv:   _potion, _heal = "Greater Health Potion", 500
            elif "Health Potion" in _inv:           _potion, _heal = "Health Potion", 250
            if not _potion:
                enc.setdefault("action_log", []).append("🧪 No potions in your bag!")
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc))
                except Exception: pass
                return
            _inv.remove(_potion); p["inventory"] = json.dumps(_inv); save_player(p)
            _hex_note = ""
            if enc.pop("p_hexed", False): _heal = max(1, _heal // 2); _hex_note = " *(Hexed — half heal)*"
            enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _heal)
            action_txt = f"🧪 Used *{_potion}*!{_hex_note} +{_heal} HP! ({enc['p_hp']}/{enc['p_max_hp']})"
            mon_act = _enc_monster_attack(enc)
            dot_txt = _apply_dot_tick(enc)
            if dot_txt: mon_act += f"\n_{dot_txt}_"
            if enc["p_hp"] <= 0:
                await _end_encounter(f"💀 *{enc['e_name']}* knocked you out!")
                return
            enc.setdefault("action_log",[]).append(action_txt)
            enc.setdefault("action_log",[]).append(mon_act)
            if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
            try:
                await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                              reply_markup=_encounter_battle_markup(enc, p))
            except Exception:
                try:
                    await query.edit_message_text(_encounter_battle_card(enc),
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await context.bot.send_message(
                            query.message.chat_id, _encounter_battle_card(enc),
                            parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                    except Exception: pass
            return

        elif data == f"enc_catch_{uid}":
            mon_key  = enc["e_key"]
            mdata    = MONSTER_BY_KEY.get(mon_key)
            base_rate = enc.get("e_catch_rate", 0.20)
            hp_pct    = enc["e_hp"] / max(1, enc["e_max_hp"])
            hp_mod    = 1.3 - hp_pct  # lower HP = better catch rate
            catch_chance = min(0.55, base_rate * hp_mod)
            if random.random() < catch_chance:
                elem    = enc.get("element", "")
                elem_e  = ELEMENT_EMOJI.get(elem, "")
                catch_r = enc.get("e_catch_rate", 0.30)
                _elem_to_core = {
                    "fire": "Fire", "water": "Water", "earth": "Earth",
                    "wind": "Wind", "lightning": "Lightning", "ice": "Ice",
                    "shadow": "Shadow", "dark": "Shadow",
                    "holy": "Holy", "void": "Void",
                    "physical": "Earth", "poison": "Shadow",
                }
                if catch_r < 0.08:
                    core_item = "Rare Monster Core"
                else:
                    core_name = _elem_to_core.get(elem, "Earth")
                    core_item = f"Monster Core ({core_name})"
                _core_roll = random.random()
                _core_qty = 3 if _core_roll < 0.05 else (2 if _core_roll < 0.30 else 1)
                for _ in range(_core_qty):
                    add_item(p, core_item)
                exp_gain  = enc["e_level"] * 8
                gold_gain = enc["e_level"] * 8
                add_exp(p, exp_gain)
                p["gold"] = safe_int(p.get("gold", 0)) + gold_gain
                asyncio.create_task(_party_exp_bonus(context.bot, uid, exp_gain, f"a wild *{enc['e_name']}*"))
                _core_str = f"*{core_item}* ×{_core_qty}" if _core_qty > 1 else f"*{core_item}*"
                _bonus_str = " 🍀 *Lucky drop!*" if _core_qty > 1 else ""
                await _end_encounter(
                    f"🎯 *Caught!* *{enc['e_name']}* {elem_e}\n"
                    f"📦 Received: {_core_str}{_bonus_str}\n"
                    f"💰 +{gold_gain} gold | ⭐ +{exp_gain} EXP")
            else:
                mon_act = _enc_monster_attack(enc)
                enc.setdefault("action_log",[]).append(f"*{enc['e_name']}* broke free!")
                enc.setdefault("action_log",[]).append(mon_act)
                if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
                if enc["p_hp"] <= 0:
                    await _end_encounter(f"💀 *{enc['e_name']}* broke free and knocked you out!")
                    return
                try:
                    await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                                  reply_markup=_encounter_battle_markup(enc, p))
                except Exception:
                    try:
                        await query.edit_message_text(_encounter_battle_card(enc),
                                                      reply_markup=_encounter_battle_markup(enc, p))
                    except Exception:
                        try:
                            await context.bot.send_message(
                                query.message.chat_id, _encounter_battle_card(enc),
                                parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                        except Exception: pass
            return

        elif data == f"enc_guard_{uid}":
            enc["p_guarding"] = True
            action_txt = "🛡️ You brace for impact! *(40% damage reduction next hit)*"

        elif data == f"enc_pet_{uid}":
            if enc.get("pet_ability_used"):
                await query.answer("Pet ability already used this battle!", show_alert=True); return
            pet_info = enc.get("pet_info")
            if not pet_info:
                await query.answer("No active pet!", show_alert=True); return
            enc["pet_ability_used"] = True
            da = pet_info.get("def_ability","shield")
            patk = pet_info.get("atk", 5)
            pname = pet_info.get("name","Pet")
            if da in ("counter","stun","poison"):
                pet_dmg = max(1, int(patk * 1.8 * random.uniform(0.9, 1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                if da == "stun":
                    enc["e_stunned_turns"] = 1
                    action_txt = f"🐾 *{pname}* stuns the enemy for *{pet_dmg}* dmg! ⚡ Enemy stunned!"
                elif da == "poison":
                    enc["e_poisoned"] = True
                    action_txt = f"🐾 *{pname}* poisons the enemy for *{pet_dmg}* dmg! ☠️ Poisoned!"
                else:
                    action_txt = f"🐾 *{pname}* counter-strikes for *{pet_dmg}* dmg!"
            elif da == "lifesteal":
                pet_dmg = max(1, int(patk * 1.5 * random.uniform(0.9, 1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                heal_amt = round(enc["p_max_hp"] * 0.20)
                enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + heal_amt)
                action_txt = f"🐾 *{pname}* drains *{pet_dmg}* dmg and heals you *{heal_amt}* HP! 💜"
            elif da == "shield":
                shield_hp = max(5, patk * 2)
                enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + shield_hp)
                action_txt = f"🐾 *{pname}* creates a shield, restoring *{shield_hp}* HP! ✨"
            else:
                pet_dmg = max(1, int(patk * 1.4 * random.uniform(0.9,1.1)))
                enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
                action_txt = f"🐾 *{pname}* attacks for *{pet_dmg}* dmg!"

        else:
            pass

        # Monster defeated
        if enc["e_hp"] <= 0:
            _kh = get_enchant_bonus(p, "kill_heal")
            if _kh: enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _kh)
            exp_gain  = exp_for_level(max(1, enc["e_level"])) // 100
            gold_gain = enc["e_level"] * 28
            hp_pct = enc["p_hp"] / max(1, enc["p_max_hp"])
            close_bonus = ""
            if hp_pct <= 0.15:
                exp_gain = int(exp_gain * 2.0); gold_gain = int(gold_gain * 2.0)
                close_bonus = "\n🔥 *Clutch Victory!* Bonus rewards!"
            elif hp_pct <= 0.30:
                exp_gain = int(exp_gain * 1.5); gold_gain = int(gold_gain * 1.5)
                close_bonus = "\n⚔️ *Close Fight Bonus!*"
            reward_mult = enc.get("reward_mult", 1.0)
            exp_gain  = round(exp_gain  * reward_mult)
            gold_gain = round(gold_gain * reward_mult)
            add_exp(p, exp_gain)
            p["gold"] = safe_int(p.get("gold", 0)) + gold_gain
            asyncio.create_task(_party_exp_bonus(context.bot, uid, exp_gain, f"*{enc['e_name']}*"))
            elem = enc.get("element","")
            elem_e = ELEMENT_EMOJI.get(elem, "")
            # Gear drops — full item pool
            _hnum_gear = enc.get("num_gear", 2)
            _hgear_rarities = enc.get("gear_rarities", ["uncommon", "rare"])
            _gear_all_h = {**WEAPONS,**ARMORS,**SHIELDS,**ACCESSORIES,**HATS,**GLOVES,**BOOTS,**MASKS}
            hunt_gear_drops = []
            for _hgi in range(_hnum_gear):
                _hrar = random.choice(_hgear_rarities)
                _hgp = [n for n, d in _gear_all_h.items() if d.get("rarity") == _hrar]
                if not _hgp: _hgp = [n for n, d in _gear_all_h.items() if d.get("rarity") in ("rare","epic")]
                if _hgp:
                    _hgd = random.choice(_hgp); hunt_gear_drops.append(_hgd); add_item(p, _hgd)
            # Potions — scarce
            _hnum_pots = enc.get("num_pots", 0)
            _hpots = [random.choice(["Health Potion","Greater Health Potion","Greater Health Potion"])
                      for _ in range(_hnum_pots)]
            if not _hpots and random.random() < 0.25:
                _hpots = [random.choice(["Health Potion","Greater Health Potion"])]
            for _hp2 in _hpots: add_item(p, _hp2)
            # Element mat (always)
            _elem_mats = {"fire":["Enchanting Scroll","Grand Restorative Flask"],"water":["Fortune Coin","Greater Health Potion"],
                          "earth":["Fortune Coin","Pet Snack"],"wind":["Enchanting Scroll","Fortune Coin"],
                          "lightning":["Enchanting Scroll","Grand Restorative Flask"],"shadow":["Scroll of Revival","Fortune Coin"],
                          "holy":["Scroll of Revival","Grand Restorative Flask"],"void":["Scroll of Revival","Enchanting Scroll"]}
            hunt_loot = random.choice(_elem_mats.get(elem, ["Fortune Coin","Greater Health Potion"]))
            add_item(p, hunt_loot)
            # Pet EXP
            pet_info = enc.get("pet_info"); pet_exp_txt = ""
            if pet_info:
                _pet_owner = get_active_pet_record(uid)
                if _pet_owner:
                    pet_exp = enc["e_level"] * 12; give_pet_exp(uid, pet_exp)
                    pet_exp_txt = f"\n🐾 *{pet_info['name']}* +{pet_exp} EXP"
            _sess = _enc_sessions.setdefault(uid, {"gold":0,"exp":0,"wins":0,"losses":0,"items":[]})
            _sess["gold"] = _sess.get("gold", 0) + gold_gain; _sess["exp"] = _sess.get("exp", 0) + exp_gain
            loot_txt = ""
            for _hg in hunt_gear_drops: loot_txt += f"\n🎁 *{_hg}*"
            for _hpt in _hpots:         loot_txt += f"\n🧪 *{_hpt}*"
            loot_txt += f"\n✨ *{hunt_loot}*"
            await _end_encounter(
                f"⚔️ *{enc['e_name']}* {elem_e} defeated!{close_bonus}\n"
                f"💰 +{gold_gain:,} gold | ⭐ +{exp_gain:,} EXP{loot_txt}{pet_exp_txt}")
            return

        # Monster attacks back
        mon_act = _enc_monster_attack(enc)
        dot_txt = _apply_dot_tick(enc)
        if dot_txt: mon_act += f"\n_{dot_txt}_"
        # Enemy may have died from DOT
        if enc["e_hp"] <= 0:
            enc.setdefault("action_log",[]).append(action_txt)
            enc.setdefault("action_log",[]).append(mon_act)
            await _end_encounter(f"☠️ *{enc['e_name']}* was defeated by status effects!\n✅ *Victory!*")
            return
        if enc["p_hp"] <= 0:
            await _end_encounter(f"💀 *{enc['e_name']}* knocked you out!")
            return
        enc.setdefault("action_log",[]).append(action_txt)
        enc.setdefault("action_log",[]).append(mon_act)
        if len(enc["action_log"]) > 6: enc["action_log"] = enc["action_log"][-6:]
        try:
            await query.edit_message_text(_encounter_battle_card(enc), parse_mode="Markdown",
                                          reply_markup=_encounter_battle_markup(enc, p))
        except Exception:
            try:
                await query.edit_message_text(_encounter_battle_card(enc),
                                              reply_markup=_encounter_battle_markup(enc, p))
            except Exception:
                try:
                    await context.bot.send_message(
                        query.message.chat_id, _encounter_battle_card(enc),
                        parse_mode="Markdown", reply_markup=_encounter_battle_markup(enc, p))
                except Exception: pass
        return

# ── HOLD HANDS ────────────────────────────────────────────────────────────────
async def holdhands_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    if not update.message.reply_to_message and not context.args:
        hands = _get_holding_hands(p)
        if hands:
            lines = [f"🤝 *{p['username']}* is holding hands with:\n"]
            for h in hands:
                dur = _holdhands_duration(h.get("since",""))
                lines.append(f"🤝 *{h['name']}*  _({dur})_")
            lines.append("\nUse /releasehands to let go of someone.")
            await send_group(update, "\n".join(lines), delay=30)
        else:
            await send_group(update,
                "🤝 *Hold Hands*\n\n"
                "Reply to someone's message and type /holdhands to reach out!\n"
                "_No limit, no fee. Both partners must agree._", delay=20)
        return

    du = update.message.reply_to_message.from_user if update.message.reply_to_message else None
    if not du:
        await send_group(update, "Reply to the person you want to hold hands with!", delay=9); return
    if du.id == user.id:
        await send_group(update, "You can't hold your own hand!", delay=9); return

    tp = get_player(du.id)
    if not tp:
        await send_group(update, f"{du.first_name} hasn't ascended yet!", delay=9); return

    p_hands  = _get_holding_hands(p)
    tp_hands = _get_holding_hands(tp)

    if any(h["id"] == du.id for h in p_hands):
        await send_group(update, f"🤝 You're already holding hands with *{du.first_name}*!", delay=9); return
    if any(h["id"] == user.id for h in tp_hands):
        await send_group(update, f"🤝 *{du.first_name}* is already holding your hand!", delay=9); return

    pending_holdhands[user.id] = {
        "target_id": du.id,
        "chat_id":   update.effective_chat.id,
        "expires":   (datetime.now() + timedelta(minutes=5)).isoformat(),
    }
    a_name = _social_name(user)
    d_name = _social_name(du)
    markup = InlineKeyboardMarkup([[
        InlineKeyboardButton("🤝 Take Hand", callback_data=f"hh_accept_{user.id}"),
        InlineKeyboardButton("🙅 Pull Away", callback_data=f"hh_decline_{user.id}"),
    ]])
    await send_group(update,
        f"🤝 {a_name} reaches out to {d_name}...\n\n"
        f"_{du.first_name}, will you take their hand?_\n"
        f"_Expires in 5m._",
        permanent=False, delay=300, reply_markup=markup)


async def holdhands_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    action      = parts[1]
    proposer_id = int(parts[2])

    proposal = pending_holdhands.get(proposer_id)
    if not proposal:
        await query.edit_message_text("🤝 This invitation already expired.", parse_mode="Markdown"); return
    if datetime.now() > datetime.fromisoformat(proposal["expires"]):
        pending_holdhands.pop(proposer_id, None)
        await query.edit_message_text("🤝 This invitation has expired.", parse_mode="Markdown"); return
    if query.from_user.id != proposal["target_id"]:
        await query.answer("This invitation isn't for you!", show_alert=True); return

    pending_holdhands.pop(proposer_id, None)
    proposer = get_player(proposer_id)
    target   = get_player(proposal["target_id"])

    if action == "decline":
        await query.edit_message_text(
            f"🙅 *{query.from_user.first_name}* pulls their hand away.",
            parse_mode="Markdown"); return

    if not proposer or not target:
        await query.edit_message_text("❌ Player data not found.", parse_mode="Markdown"); return

    p_hands  = _get_holding_hands(proposer)
    tp_hands = _get_holding_hands(target)

    if any(h["id"] == target["user_id"] for h in p_hands):
        await query.edit_message_text("🤝 You're already holding hands!", parse_mode="Markdown"); return

    now_str = datetime.now().isoformat()
    p_hands.append( {"id": target["user_id"],   "name": target["username"],   "since": now_str})
    tp_hands.append({"id": proposer["user_id"], "name": proposer["username"], "since": now_str})
    _save_holding_hands(proposer, p_hands)
    _save_holding_hands(target,   tp_hands)
    save_player(proposer); save_player(target)

    p_total  = len(p_hands)
    tp_total = len(tp_hands)
    multi_note = ""
    if p_total > 1 or tp_total > 1:
        multi_note = f"\n_{proposer['username']} holds {p_total} hand{'s' if p_total>1 else ''} · {target['username']} holds {tp_total} hand{'s' if tp_total>1 else ''}_"

    await query.edit_message_text(
        f"🤝 *{proposer['username']}* and *{target['username']}* are holding hands!{multi_note}\n\n"
        f"_Use /holdhands to check · /releasehands to let go._",
        parse_mode="Markdown")


async def releasehands_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    hands = _get_holding_hands(p)
    if not hands:
        await send_group(update, "🤝 You're not holding anyone's hand.", delay=9); return

    # Reply-to: release that specific person's hand
    if update.message.reply_to_message:
        target_uid = update.message.reply_to_message.from_user.id
        match = next((h for h in hands if h["id"] == target_uid), None)
        if not match:
            await send_group(update, "🤝 You're not holding that person's hand.", delay=9); return
        await _do_release_hands(update, p, user, match)
        return

    if len(hands) == 1:
        await _do_release_hands(update, p, user, hands[0])
        return

    # Multiple — show picker
    rows = []
    for h in hands:
        dur = _holdhands_duration(h.get("since",""))
        rows.append([InlineKeyboardButton(f"🫱 Let go of {h['name']} ({dur})", callback_data=f"rh_pick_{user.id}_{h['id']}")])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data=f"close_msg_{user.id}")])
    await send_group(update,
        f"🤝 You're holding *{len(hands)}* hands. Who do you want to let go of?",
        permanent=False, delay=60, reply_markup=InlineKeyboardMarkup(rows))


async def _do_release_hands(update_or_query, p, user, hand_entry):
    """Shared helper: releases hand_entry from p and their partner."""
    partner_id   = hand_entry["id"]
    partner_name = hand_entry["name"]
    dur = _holdhands_duration(hand_entry.get("since",""))

    new_hands = [h for h in _get_holding_hands(p) if h["id"] != partner_id]
    _save_holding_hands(p, new_hands)
    save_player(p)

    partner = get_player(partner_id)
    if partner:
        _save_holding_hands(partner, [h for h in _get_holding_hands(partner) if h["id"] != p["user_id"]])
        save_player(partner)

    text = (f"🫱 *{p['username']}* lets go of *{partner_name}*'s hand.\n"
            f"_They held on for {dur}._")
    if hasattr(update_or_query, "message"):
        await send_group(update_or_query, text, delay=30)
    else:
        await update_or_query.edit_message_text(text, parse_mode="Markdown")


async def releasehands_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    uid        = int(parts[2])
    partner_id = int(parts[3])
    if query.from_user.id != uid:
        await query.answer("Not your hands!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.edit_message_text("Player not found.", parse_mode="Markdown"); return
    hands = _get_holding_hands(p)
    hand_entry = next((h for h in hands if h["id"] == partner_id), None)
    if not hand_entry:
        await query.edit_message_text("🤝 You're not holding that person's hand anymore.", parse_mode="Markdown"); return
    await _do_release_hands(query, p, query.from_user, hand_entry)


