def roll_pool_shot():
    total_weight = sum(s["weight"] for s in POOL_SHOTS)
    roll = random.randint(0, total_weight - 1)
    cumulative = 0
    for shot in POOL_SHOTS:
        cumulative += shot["weight"]
        if roll < cumulative:
            return shot
    return POOL_SHOTS[0]

def roll_pool_shot_with_luk(p):
    shot = roll_pool_shot()
    luk = get_stat(p, "LUK")
    upgrade_chance = luk * 0.003
    if random.random() < upgrade_chance:
        tier_order = ["common","uncommon","rare","epic","legendary","mythic"]
        current_idx = tier_order.index(shot["rarity"])
        if current_idx < len(tier_order) - 1:
            next_rarity = tier_order[current_idx + 1]
            upgraded = [s for s in POOL_SHOTS if s["rarity"] == next_rarity]
            if upgraded:
                shot = random.choice(upgraded)
    return shot

async def pool_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    chat_id = update.effective_chat.id
    s = get_or_create_shadow(user.id, user.first_name)
    p = get_player(user.id) if s.get("ascended") else None

    last_pool = p.get("last_pool") if p else s.get("last_pool")
    if last_pool:
        try:
            elapsed = (datetime.now() - datetime.fromisoformat(last_pool)).total_seconds()
            if elapsed < 8:
                remaining = int(8 - elapsed)
                await send_group(update, f"🎱 Cooldown: {remaining}s", delay=5)
                return
        except Exception:
            pass

    shot = roll_pool_shot_with_luk(p) if p else roll_pool_shot()

    flavor = ""
    if p and random.random() < 0.25:
        line = get_class_line(p)
        options = POOL_CLASS_FLAVOR.get(line, [])
        if options:
            flavor = " " + random.choice(options)

    rarity_prefix = {
        "common":"🎱","uncommon":"🎯","rare":"🔵","epic":"🟣","legendary":"🟡","mythic":"🔴",
    }.get(shot["rarity"], "🎱")

    item_found = None
    if shot.get("loot") and p:
        item_found = roll_loot_table(shot["loot"])
        if item_found:
            add_item(p, item_found)

    exp_gain  = shot["exp"]
    gold_gain = shot["gold"]

    if p:
        lvl_bonus = max(1.0, 1.0 + (p["level"] - 1) * 0.15)
        gold_bonus = max(1.0, 1.0 + (p["level"] - 1) * 0.12)
        exp_gain  = int(exp_gain  * lvl_bonus)
        gold_gain = int(gold_gain * gold_bonus)
        p["gold"] = p.get("gold", 0) + gold_gain
        p["last_pool"] = datetime.now().isoformat()
        lmsgs, leveled = add_exp(p, exp_gain)
        for _d, _e, _g in track_objective(p, "pool_run"):
            p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
        save_player(p)
        if leveled and p["level"] % 10 == 0:
            asyncio.create_task(announce(context.bot, chat_id,
                f"🎉 *{p['username']}* reached *Level {p['level']}*! 🎱",
                delay=60))
    else:
        s["last_pool"] = datetime.now().isoformat()
        lmsgs, leveled = add_shadow_exp(s, exp_gain)
        save_shadow(s)

    flavor_suffix = f" {flavor.strip()}" if flavor else ""
    lines = [f"{rarity_prefix} *{user.first_name}* — _{shot['text']}{flavor_suffix}_"]
    reward_parts = []
    if exp_gain > 0:  reward_parts.append(f"✨ +{exp_gain} EXP")
    if gold_gain > 0: reward_parts.append(f"💰 +{gold_gain}g")
    if reward_parts:  lines.append("  •  ".join(reward_parts))
    if item_found:
        rarity_tag = ""
        for pool3 in [WEAPONS, ARMORS, ACCESSORIES, CONSUMABLES]:
            if item_found in pool3:
                rarity_tag = RARITY_EMOJI.get(pool3[item_found].get("rarity", ""), "")
                break
        lines.append(f"🎒 {rarity_tag} *{item_found}*")

    # Secondary item roll from global pool
    if p:
        bonus_item = _roll_pool_bonus(p)
        if bonus_item:
            add_item(p, bonus_item)
            save_player(p)
            bi_rarity = ""
            for pool_check in [WEAPONS, ARMORS, ACCESSORIES, SHIELDS, HATS, GLOVES, BOOTS, MASKS]:
                if bonus_item in pool_check:
                    bi_rarity = RARITY_EMOJI.get(pool_check[bonus_item].get("rarity",""), "")
                    break
            lines.append(f"🎁 {bi_rarity} *{bonus_item}*")

    key = (chat_id, user.id)
    old_id = last_bot_message.get(key)
    if old_id:
        try:
            await update.get_bot().delete_message(chat_id=chat_id, message_id=old_id)
        except Exception:
            pass

    msg_obj = await update.get_bot().send_message(
        chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")
    last_bot_message[key] = msg_obj.message_id
    asyncio.create_task(_auto_delete(update.get_bot(), chat_id, msg_obj.message_id, 9))
    try:
        await update.message.delete()
    except Exception:
        pass

# ── HUSTLE ────────────────────────────────────────────────────────────────────
async def hustle_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Run all ready activities (daily, train, quest, pool, claim, explore) in one shot."""
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await reply_to_dm(update, context, "Use /ascend first!"); return
    if is_defeated(p):
        await reply_to_dm(update, context, "💀 Too beaten up to hustle right now."); return

    now    = datetime.now()
    lines  = []
    ran    = []
    skipped = []
    w      = get_weather()

    # ── Daily ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_daily"), 86400):
        p["last_daily"] = now.isoformat()
        gold = 50 + p["level"] * 5; p["gold"] = p.get("gold",0) + gold
        item = None
        if random.random() < 0.10:
            item = random.choice(["Health Potion","Greater Health Potion","Grand Restorative Flask"])
            add_item(p, item)
        daily_exp = 200 + p["level"] * 10
        lmsgs, _ = add_exp(p, daily_exp)
        entry = f"🎁 *Daily:* +{daily_exp} EXP, +{gold}g"
        if item: entry += f", *{item}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🎁 Daily  -  {time_remaining(p.get('last_daily'), 86400)}")

    # ── Train ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_train"), 1800):
        p["last_train"] = now.isoformat()
        base = 150 + p["level"] * 5
        cls  = get_player_class(p)
        if cls:
            pk = cls.get("passive_key","")
            if pk in ("arcane_mind","spell_surge","arcane_mastery","mana_overload","eternal_wisdom"):
                base = round(base * 1.30)
            elif pk in ("iron_will","holy_stance","devotion","bulwark","divine_judgment"):
                base = round(base * 1.20)
            elif pk in ("quick_hands","evasion","shadowstep","ghost_form","deaths_shadow",
                        "eagle_eye","trailblazer","natures_bond","guardian_stance","pathfinder"):
                base = round(base * 1.35)
            elif pk in ("mending_aura","divine_grace","sacred_ground","resurrection","divine_presence",
                        "dark_sense","purge","judgement","wrath_of_the_righteous"):
                base = round(base * 1.15)
        lmsgs, _ = add_exp(p, base)
        ran.append(f"🏋️ *Train:* +{base} EXP")
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🏋️ Train  -  {time_remaining(p.get('last_train'), 1800)}")

    # ── Quest ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_quest"), 3600):
        p["last_quest"] = now.isoformat()
        if p["level"] <= 3:   qpool = [q for q in SOLO_QUESTS if q["tier"]=="Easy"]
        elif p["level"] <= 7: qpool = [q for q in SOLO_QUESTS if q["tier"] in ["Easy","Medium"]]
        else:                 qpool = SOLO_QUESTS
        q  = random.choice(qpool or SOLO_QUESTS)
        item_found = roll_loot_table(q.get("loot_table",[]))
        if item_found: add_item(p, item_found)
        luk_val = get_stat(p, "LUK")
        gold    = round(q["gold"] * (1 + luk_val * 0.002))
        p["gold"] = p.get("gold",0) + gold
        p["quests_done"] = p.get("quests_done",0) + 1
        lmsgs, _ = add_exp(p, q["exp"], w)
        check_titles(p)
        entry = f"🗺️ *Quest:* +{q['exp']} EXP, +{gold}g"
        if item_found: entry += f", *{item_found}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🗺️ Quest  -  {time_remaining(p.get('last_quest'), 3600)}")

    # ── Pool shot ──────────────────────────────────────────────────────────────
    last_pool = p.get("last_pool")
    pool_ready = True
    if last_pool:
        try:
            elapsed = (now - datetime.fromisoformat(last_pool)).total_seconds()
            if elapsed < 8:
                pool_ready = False
                skipped.append(f"🎱 Pool  -  {int(8 - elapsed)}s")
        except: pass
    if pool_ready:
        p["last_pool"] = now.isoformat()
        shot      = roll_pool_shot_with_luk(p)
        exp_gain  = shot["exp"]; gold_gain = shot["gold"]
        exp_gain  = int(exp_gain  * max(1.0, 1.0 + (p["level"] - 1) * 0.15))
        gold_gain = int(gold_gain * max(1.0, 1.0 + (p["level"] - 1) * 0.12))
        p["gold"] = p.get("gold",0) + gold_gain
        item_found = None
        if shot.get("loot"):
            item_found = roll_loot_table(shot["loot"])
            if item_found: add_item(p, item_found)
        bonus_item = _roll_pool_bonus(p)
        if bonus_item: add_item(p, bonus_item)
        lmsgs, _ = add_exp(p, exp_gain)
        rarity_prefix = {"common":"🎱","uncommon":"🎯","rare":"🔵","epic":"🟣","legendary":"🟡","mythic":"🔴"}.get(shot["rarity"],"🎱")
        entry = f"{rarity_prefix} *Pool:* +{exp_gain} EXP"
        if gold_gain: entry += f", +{gold_gain}g"
        if item_found: entry += f", *{item_found}*!"
        if bonus_item: entry += f"\n  🎱 Table drop: *{bonus_item}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)

    # ── Claim ─────────────────────────────────────────────────────────────────
    today_str     = now.strftime("%Y-%m-%d")
    yesterday_str = (now - timedelta(days=1)).strftime("%Y-%m-%d")
    last_claim    = p.get("last_claim")
    if last_claim == today_str:
        skipped.append("🎁 Claim  -  already claimed today")
    else:
        streak = safe_int(p.get("claim_streak"))
        streak = streak + 1 if last_claim == yesterday_str else 1
        gold_reward  = 50 + min(streak * 10, 200)
        slate_count  = 1 if streak >= 3 else 0
        scale_count  = 1 if streak >= 7 else 0
        bonus_scroll = streak >= 14
        inv = sjl(p.get("inventory"), [])
        if slate_count: inv.extend(["Iron Shard"] * slate_count)
        if scale_count: inv.extend(["Iron Shard"] * scale_count)
        if bonus_scroll: inv.append("Enchanting Scroll")
        p["inventory"] = json.dumps(inv)
        p["gold"] = p.get("gold", 0) + gold_reward
        p["last_claim"] = today_str
        p["claim_streak"] = streak
        streak_emojis = "🔥" * min(streak, 7)
        claim_entry = f"🎁 *Claim Day {streak}* {streak_emojis}: +{gold_reward}g"
        if slate_count or scale_count:
            claim_entry += f", +{slate_count + scale_count} Iron Shard"
        if bonus_scroll:
            claim_entry += ", +1 Enchanting Scroll"
        ran.append(claim_entry)

    # ── Explore ────────────────────────────────────────────────────────────────
    if p.get("explore_date") == today_str and safe_int(p.get("explore_count_today")) >= 2:
        skipped.append("🗺️ Explore  -  2/2 used today")
    elif user.id in explore_timers and not explore_timers[user.id].done():
        skipped.append("🗺️ Explore  -  expedition in progress")
    else:
        if p["level"] <= 5:     _elig = [z for z in EXPLORE_ZONES if z["tier"]=="Easy"]
        elif p["level"] <= 15:  _elig = [z for z in EXPLORE_ZONES if z["tier"] in ["Easy","Medium"]]
        elif p["level"] <= 30:  _elig = [z for z in EXPLORE_ZONES if z["tier"] in ["Easy","Medium","Hard"]]
        elif p["level"] <= 60:  _elig = [z for z in EXPLORE_ZONES if z["tier"] != "Legendary"]
        else:                   _elig = EXPLORE_ZONES
        _zone = random.choice(_elig)
        if p.get("explore_date") != today_str:
            p["explore_count_today"] = 0
            p["explore_date"] = today_str
        p["explore_count_today"] = safe_int(p.get("explore_count_today")) + 1
        p["last_explore"] = now.isoformat()
        _remaining = 2 - safe_int(p.get("explore_count_today"))
        ran.append(f"🗺️ *Explore:* Expedition to *{_zone['name']}* started — results in 1 hour! ({_remaining} left today)")
        chat_id   = update.effective_chat.id
        _bot      = update.get_bot()
        _uid      = user.id
        _uname    = p.get("username", user.first_name)
        _zone_ref = _zone

        async def _hustle_explore():
            await asyncio.sleep(3600)
            pp = get_player(_uid)
            if not pp: return
            w2 = get_weather()
            success = random.random() < 0.70
            if success:
                exp  = round(_zone_ref["exp"] * w2.get("exp_mod", 1.0))
                gold = _zone_ref["gold"]
                pp["gold"] = pp.get("gold", 0) + gold
                item_found = roll_loot_table(_zone_ref.get("loot_table", []))
                if item_found: add_item(pp, item_found)
                lmsgs, leveled = add_exp(pp, exp)
                save_player(pp)
                rarity = ""
                if item_found:
                    for _pool in [WEAPONS, ARMORS, ACCESSORIES, CONSUMABLES]:
                        if item_found in _pool:
                            rarity = RARITY_EMOJI.get(_pool[item_found].get("rarity", ""), "")
                            break
                msg = (f"🗺️ *{pp['username']}* returns from *{_zone_ref['name']}*!\n\n"
                       f"✅ Expedition successful!\n"
                       f"✨ +{exp} EXP | 💰 +{gold} Gold")
                if item_found: msg += f"\n🎒 Found: {rarity} *{item_found}*!"
                if lmsgs: msg += "\n\n" + "\n".join(lmsgs)
            else:
                save_player(pp)
                msg = (f"🗺️ *{pp['username']}* returns from *{_zone_ref['name']}*!\n\n"
                       f"❌ The expedition failed — nothing to show for it.")
            try:
                await _bot.send_message(chat_id=_uid, text=msg, parse_mode="Markdown")
            except Exception:
                try: await _bot.send_message(chat_id=chat_id, text=msg, parse_mode="Markdown")
                except Exception: pass

        _task = asyncio.create_task(_hustle_explore())
        explore_timers[_uid] = _task

    if not ran:
        cd_list = "\n".join(f"  {s}" for s in skipped)
        await reply_to_dm(update, context,
            f"🎱 *{user.first_name}*  -  nothing ready yet.\n\n{cd_list}"); return

    save_player(p)

    out = [f"🎱 *{user.first_name}* runs the table!\n"]
    out += ran
    if skipped:
        out += ["", "⏳ *Still cooling down:*"] + [f"  {s}" for s in skipped]
    await reply_to_dm(update, context, "\n".join(out))


# ── RESETSTATS ────────────────────────────────────────────────────────────────
def _do_resetstats(p):
    """Execute the stat reset and return (new_stats, refunded)."""
    sd = safe_stats(p)
    # Only the 6 allocatable stats are refunded — DEF is not allocatable (comes from gear/cores only)
    alloc_defaults = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5}
    # Get actual class bonuses so we don't count them as user-allocated points
    class_bonuses = _calc_applied_class_bonuses(p)
    total_allocated = 0
    for stat, base in alloc_defaults.items():
        bonus = class_bonuses.get(stat, 0)
        current = sd.get(stat, base)
        user_pts = current - base - bonus
        if user_pts > 0:
            total_allocated += user_pts
    # Reset only allocatable stats; preserve DEF (Monster Core Earth bonus)
    core_def = sd.get("DEF", 0)
    new_stats = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5,"DEF":core_def}
    for stat, bonus in class_bonuses.items():
        if stat in new_stats and stat != "DEF":
            new_stats[stat] = new_stats.get(stat, 5) + bonus
    refunded = total_allocated + safe_int(p.get("stat_points"))
    p["stats"] = json.dumps(new_stats)
    p["stat_points"] = refunded
    save_player(p)
    return new_stats, refunded

async def resetstats_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    _rss_cost = 1_000_000
    if not context.args or context.args[0].lower() != "confirm":
        rsstat_markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("✅ Confirm Reset", callback_data=f"rsstat_confirm_{user.id}"),
            InlineKeyboardButton("❌ Cancel",        callback_data=f"rsstat_cancel_{user.id}"),
        ]])
        sd = safe_stats(p)
        await send_group(update,
            f"⚠️ *Stat Reset*\n\n"
            f"This will refund ALL allocated stat points back to your pool.\n"
            f"Your class stat bonuses will be preserved.\n\n"
            f"Current stats: STR:{sd.get('STR',5)} AGI:{sd.get('AGI',5)} "
            f"INT:{sd.get('INT',5)} WIS:{sd.get('WIS',5)} "
            f"DEX:{sd.get('DEX',5)} LUK:{sd.get('LUK',5)}\n\n"
            f"Cost: *{_rss_cost:,}g*\n\n"
            f"Tap Confirm or type /resetstats confirm to proceed.",
            delay=20, reply_markup=rsstat_markup); return

    if safe_int(p.get("gold")) < _rss_cost:
        await send_group(update,
            f"Not enough gold! Need {_rss_cost:,}g, you have {p.get('gold',0):,}g.", delay=9); return
    p["gold"] = safe_int(p.get("gold")) - _rss_cost
    new_stats, refunded = _do_resetstats(p)
    await send_group(update,
        f"🔄 *Stat Reset Complete!*\n\n"
        f"All allocated stat points have been refunded.\n"
        f"💡 *{refunded} points* returned to your pool.\n\n"
        f"DEF is now gear-only  -  armor and shields provide your defense.\n\n"
        f"Use `/allocate` to redistribute your points.\n"
        f"Current stats after class bonuses:\n"
        f"STR:{new_stats['STR']} AGI:{new_stats['AGI']} "
        f"INT:{new_stats['INT']} WIS:{new_stats['WIS']} "
        f"DEX:{new_stats['DEX']} LUK:{new_stats['LUK']}",
        delay=60)

async def resetstats_callback(update, context):
    """Handle resetstats confirm/cancel buttons."""
    query = update.callback_query
    caller_id = query.from_user.id
    if not _cb_lock(caller_id):
        await query.answer("Processing — please wait.", show_alert=False); return
    try:
        await query.answer()
        data = query.data
        parts = data.split("_")
        if len(parts) < 3:
            return
        action = parts[1]
        try:
            uid = int(parts[2])
        except (ValueError, IndexError):
            return
        if caller_id != uid:
            await query.answer("This isn't your reset button!", show_alert=True); return
        if action == "cancel":
            try:
                await query.edit_message_text("❌ Stat reset cancelled.", parse_mode="Markdown")
            except Exception:
                pass
            return
        p = get_player(uid)
        if not p:
            await query.answer("Player not found!", show_alert=True); return
        _rss_cost = 1_000_000
        if safe_int(p.get("gold")) < _rss_cost:
            await query.answer(f"Not enough gold! Need {_rss_cost:,}g.", show_alert=True); return
        p["gold"] = safe_int(p.get("gold")) - _rss_cost
        new_stats, refunded = _do_resetstats(p)
        result = (f"🔄 *Stat Reset Complete!*\n\n"
                  f"All allocated stat points have been refunded.\n"
                  f"💡 *{refunded} points* returned to your pool.\n\n"
                  f"DEF is now gear-only  -  armor and shields provide your defense.\n\n"
                  f"Use `/allocate` to redistribute your points.\n"
                  f"Current stats after class bonuses:\n"
                  f"STR:{new_stats['STR']} AGI:{new_stats['AGI']} "
                  f"INT:{new_stats['INT']} WIS:{new_stats['WIS']} "
                  f"DEX:{new_stats['DEX']} LUK:{new_stats['LUK']}")
        try:
            await query.edit_message_text(result, parse_mode="Markdown")
        except Exception:
            pass
    finally:
        _cb_unlock(caller_id)

# ── BROADCAST (admin only) ────────────────────────────────────────────────────
async def broadcast_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text(
            "Usage: /broadcast <message>\n\n"
            "Sends a DM to every player in the database."
        )
        return

    c = _db().cursor()
    c.execute("SELECT DISTINCT user_id FROM players")
    user_ids = [row[0] for row in c.fetchall()]

    sent = 0; failed = 0
    status_msg = await update.message.reply_text(f"📡 Broadcasting to {len(user_ids)} players...")

    for uid in user_ids:
        try:
            await context.bot.send_message(chat_id=uid, text=text)
            sent += 1
        except Exception:
            failed += 1

    try:
        await status_msg.edit_text(
            f"📣 *Broadcast complete.*\n"
            f"✅ Delivered: *{sent}*\n"
            f"❌ Failed: *{failed}* _(blocked or never DM'd bot)_",
            parse_mode="Markdown"
        )
    except Exception:
        pass


# ── SEND QUEST (admin only) ───────────────────────────────────────────────────
async def sendquest_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    global _broadcast_quest, _broadcast_claims
    user = update.effective_user
    if user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    # Format: /sendquest <exp> <phrase…>
    if not context.args or len(context.args) < 2:
        await update.message.reply_text(
            "Usage: /sendquest <exp> <phrase>\n\n"
            "Example: /sendquest 500 Lets go team!\n\n"
            "Players earn the EXP by saying the exact phrase in the group.\n"
            "Use /cancelquest to end it early."
        )
        return

    try:
        exp = int(context.args[0])
    except ValueError:
        await update.message.reply_text("First argument must be a number (EXP amount).\nExample: /sendquest 500 Lets go team!")
        return

    phrase = " ".join(context.args[1:]).strip()
    quest_id = str(int(time.time()))
    _broadcast_quest  = {"id": quest_id, "phrase": phrase, "exp": exp, "expires": time.time() + 86400}
    _broadcast_claims = set()

    c = _db().cursor()
    c.execute("SELECT DISTINCT user_id FROM players")
    user_ids = [row[0] for row in c.fetchall()]

    dm_text = (
        f"📜 *Special Quest*\n\n"
        f"Say this phrase in the group chat to earn your reward:\n\n"
        f"*\"{phrase}\"*\n\n"
        f"💫 Reward: *{exp} EXP*\n"
        f"⏳ Expires in 24 hours"
    )

    sent = 0; failed = 0
    status_msg = await update.message.reply_text(f"📡 Sending quest to {len(user_ids)} players...")
    for uid in user_ids:
        try:
            await context.bot.send_message(chat_id=uid, text=dm_text, parse_mode="Markdown")
            sent += 1
        except Exception:
            failed += 1

    try:
        await status_msg.edit_text(
            f"✅ *Quest sent!*\n\n"
            f"Phrase: *\"{phrase}\"*\n"
            f"Reward: *{exp} EXP*\n\n"
            f"📨 Delivered: *{sent}* | ❌ Failed: *{failed}*\n"
            f"_Use /cancelquest to end it early._",
            parse_mode="Markdown"
        )
    except Exception:
        pass


async def cancelquest_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    global _broadcast_quest, _broadcast_claims
    if update.effective_user.id != ADMIN_ID:
        return
    if _broadcast_quest is None:
        await update.message.reply_text("No active broadcast quest.")
        return
    phrase = _broadcast_quest["phrase"]
    claimed = len(_broadcast_claims)
    _broadcast_quest  = None
    _broadcast_claims = set()
    await update.message.reply_text(
        f"🚫 Quest cancelled.\n\nPhrase: *\"{phrase}\"*\n{claimed} player(s) had already claimed it.",
        parse_mode="Markdown"
    )


# ── WIPE (admin only) ─────────────────────────────────────────────────────────
async def wipe_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    last = _wipe_confirm.get(user.id)
    if not last or (datetime.now() - datetime.fromisoformat(last)).total_seconds() > 30:
        _wipe_confirm[user.id] = datetime.now().isoformat()
        await send_group(update,
            "⚠️ *Are you sure?* This wipes ALL player data.\n"
            "Type /wipe again within 30 seconds to confirm.", delay=30)
        return

    _wipe_confirm.pop(user.id, None)
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("DROP TABLE IF EXISTS shadow_profiles")
    c.execute("DROP TABLE IF EXISTS players")
    c.execute("DROP TABLE IF EXISTS guilds")
    c.execute("DROP TABLE IF EXISTS bounties")
    conn.commit(); conn.close()
    init_db()
    # Clear memory state
    active_bosses.clear(); secret_boss_active.clear()
    active_events.clear(); active_raids.clear(); active_soloraids.clear()
    last_event_times.clear()
    message_counters.clear()
    pending_trades.clear(); pending_guild_reqs.clear()
    pending_duels.clear(); active_arenas.clear()
    await send_group(update,
        "🗑️ *Database wiped and reset.*\n"
        "All players, guilds, and data cleared.\n"
        "Fresh start!", delay=30)

def is_banned(user_id: int) -> bool:
    try:
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT 1 FROM banned_users WHERE user_id=?", (user_id,))
        row = c.fetchone(); conn.close()
        return row is not None
    except Exception:
        return False  # table missing or DB error — treat as not banned

def _do_ban_wipe(tid: int, tname: str):
    """Record ban in banned_users. Remove from guild and clear relationship bonds."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("INSERT OR REPLACE INTO banned_users (user_id, username, banned_at) VALUES (?,?,?)",
              (tid, tname, datetime.now().isoformat()))
    conn.commit(); conn.close()

    p = get_player(tid)
    if not p:
        return

    # Remove from guild members list
    gid = p.get("guild_id")
    if gid and str(gid) != "None":
        try:
            g = get_guild(gid)
            if g:
                members = sjl(g.get("members"), [])
                if tid in members:
                    members.remove(tid)
                g["members"] = json.dumps(members)
                save_guild(g)
        except Exception:
            pass
    p["guild_id"] = None

    # Clear marriages on both sides
    m_list = sjl(p.get("marriages"), [])
    if not m_list and p.get("married_to_id"):
        m_list = [{"id": int(p["married_to_id"]), "name": p.get("married_to_name", "")}]
    for m in m_list:
        try:
            partner = get_player(m["id"])
            if partner:
                pm = sjl(partner.get("marriages"), [])
                pm = [x for x in pm if x.get("id") != tid]
                partner["marriages"] = json.dumps(pm) if pm else None
                if not pm:
                    partner["married_to_id"] = None
                    partner["married_to_name"] = None
                    partner["married_at"] = None
                else:
                    partner["married_to_id"] = pm[0]["id"]
                    partner["married_to_name"] = pm[0]["name"]
                save_player(partner)
        except Exception:
            pass
    p["marriages"] = None
    p["married_to_id"] = None
    p["married_to_name"] = None
    p["married_at"] = None

    # Clear holding hands on both sides
    try:
        h_list = _get_holding_hands(p)
        for h in h_list:
            try:
                partner = get_player(h["id"])
                if partner:
                    ph = _get_holding_hands(partner)
                    ph = [x for x in ph if x.get("id") != tid]
                    _save_holding_hands(partner, ph)
                    save_player(partner)
            except Exception:
                pass
        _save_holding_hands(p, [])
    except Exception:
        pass

    save_player(p)

_BAN_PAGE_SIZE = 10

def _build_ban_picker(page: int = 0):
    """Return (text, InlineKeyboardMarkup) for the ban player-picker."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("""
        SELECT user_id, username, level FROM players
        WHERE user_id NOT IN (SELECT user_id FROM banned_users)
        ORDER BY level DESC
    """)
    rows = c.fetchall(); conn.close()
    total = len(rows)
    start = page * _BAN_PAGE_SIZE
    page_rows = rows[start:start + _BAN_PAGE_SIZE]

    text = f"🔨 *Ban Player — Select a target* (page {page+1})\n_Tap a name to get a confirmation button._\n"
    buttons = []
    for uid, uname, lvl in page_rows:
        buttons.append([InlineKeyboardButton(
            f"Lv{lvl} {uname}", callback_data=f"banpick_sel_{uid}")])

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀️ Prev", callback_data=f"banpick_pg_{page-1}"))
    if start + _BAN_PAGE_SIZE < total:
        nav.append(InlineKeyboardButton("Next ▶️", callback_data=f"banpick_pg_{page+1}"))
    if nav:
        buttons.append(nav)
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="banpick_cancel")])
    return text, InlineKeyboardMarkup(buttons)

async def ban_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query: return
    if query.from_user.id != ADMIN_ID:
        await query.answer("Admin only.", show_alert=True); return

    data = query.data

    # ── Cancel ────────────────────────────────────────────────────────────────
    if data == "banpick_cancel":
        await query.answer()
        try: await query.edit_message_text("Cancelled.")
        except Exception: pass
        return

    # ── Page navigation ───────────────────────────────────────────────────────
    if data.startswith("banpick_pg_"):
        await query.answer()
        page = int(data.split("_")[2])
        text, markup = _build_ban_picker(page)
        try: await query.edit_message_text(text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
        return

    # ── Select player → show confirmation ─────────────────────────────────────
    if data.startswith("banpick_sel_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT username, level FROM players WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        if not row:
            try: await query.edit_message_text("❌ Player not found.")
            except Exception: pass
            return
        tname, lvl = row
        markup = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Yes, ban them", callback_data=f"banpick_confirm_{tid}")],
            [InlineKeyboardButton("◀️ Back",          callback_data="banpick_pg_0")],
        ])
        try:
            await query.edit_message_text(
                f"Ban <b>{tname}</b>  |  Lv {lvl}  |  ID <code>{tid}</code>\n\n"
                f"This wipes all their data and blocks them permanently.",
                parse_mode="HTML", reply_markup=markup)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban sel error] {e}")
            except Exception: pass
        return

    # ── Confirm ban ───────────────────────────────────────────────────────────
    if data.startswith("banpick_confirm_"):
        await query.answer("Banning...", show_alert=False)
        tid = int(data.split("_")[2])
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT username FROM players WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        tname = row[0] if row else f"User#{tid}"
        try:
            _do_ban_wipe(tid, tname)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban wipe error] {e}")
            except Exception: pass
            return
        try:
            await context.bot.send_message(chat_id=tid,
                text="🚫 You have been banned from 8ball World.")
        except Exception:
            pass
        try:
            await query.edit_message_text(
                f"🔨 <b>{tname}</b> (ID <code>{tid}</code>) banned and wiped.",
                parse_mode="HTML")
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban confirm edit error] {e}")
            except Exception: pass
        return

    await query.answer()

async def ban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    tid = None; tname = None

    # Priority 1: reply to their message
    if update.message and update.message.reply_to_message:
        ru = update.message.reply_to_message.from_user
        tid = ru.id
        tname = ru.first_name
    # Priority 2: numeric user ID
    elif context.args and context.args[0].lstrip("-").isdigit():
        tid = int(context.args[0])
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT username FROM players WHERE user_id=?", (tid,))
        row = c.fetchone()
        if not row:
            c.execute("SELECT username FROM shadow_profiles WHERE user_id=?", (tid,))
            row = c.fetchone()
        conn.close()
        tname = row[0] if row else f"User#{tid}"
    # Priority 3: display name or @handle
    elif context.args:
        target = get_player_by_username(context.args[0])
        if not target:
            await send_group(update, "❌ No player found with that name or ID.", delay=9); return
        tid = target["user_id"]; tname = target["username"]
    else:
        # No args — show interactive player picker (highest level first)
        text, markup = _build_ban_picker(0)
        await update.message.reply_text(text, parse_mode="Markdown", reply_markup=markup)
        return

    _do_ban_wipe(tid, tname)
    try:
        await context.bot.send_message(chat_id=tid, text="🚫 You have been banned from 8ball World.")
    except Exception:
        pass
    await send_group(update,
        f"🔨 *{tname}* (ID: `{tid}`) has been banned and wiped from the game.\n"
        f"They can no longer use any bot commands.", delay=30)

def _build_unban_picker():
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT user_id, username, banned_at FROM banned_users ORDER BY banned_at DESC")
    rows = c.fetchall(); conn.close()
    return rows

def _build_unban_markup(rows):
    buttons = []
    for uid, uname, banned_at in rows:
        try:
            dt = datetime.fromisoformat(banned_at).strftime("%m/%d/%y")
        except Exception:
            dt = "?"
        buttons.append([InlineKeyboardButton(
            f"{uname}  (banned {dt})", callback_data=f"unbanpick_sel_{uid}")])
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="unbanpick_cancel")])
    return InlineKeyboardMarkup(buttons)

async def unban_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query: return
    if query.from_user.id != ADMIN_ID:
        await query.answer("Admin only.", show_alert=True); return

    data = query.data

    if data == "unbanpick_cancel":
        await query.answer()
        try: await query.edit_message_text("Cancelled.")
        except Exception: pass
        return

    if data.startswith("unbanpick_sel_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT username, banned_at FROM banned_users WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        if not row:
            try: await query.edit_message_text("❌ User not found in ban list.")
            except Exception: pass
            return
        uname, banned_at = row
        try:
            dt = datetime.fromisoformat(banned_at).strftime("%Y-%m-%d")
        except Exception:
            dt = "?"
        markup = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Yes, unban them", callback_data=f"unbanpick_confirm_{tid}")],
            [InlineKeyboardButton("◀️ Back",            callback_data="unbanpick_back")],
        ])
        try:
            await query.edit_message_text(
                f"Unban <b>{uname}</b>?\nBanned on: {dt}\n\n"
                f"Their stats and progress are fully restored.",
                parse_mode="HTML", reply_markup=markup)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[unban sel error] {e}")
            except Exception: pass
        return

    if data == "unbanpick_back":
        await query.answer()
        rows = _build_unban_picker()
        if not rows:
            try: await query.edit_message_text("No banned players.")
            except Exception: pass
            return
        try:
            await query.edit_message_text(
                "🔓 *Unban Player — Select a player to unban*",
                parse_mode="Markdown", reply_markup=_build_unban_markup(rows))
        except Exception: pass
        return

    if data.startswith("unbanpick_confirm_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("SELECT username FROM banned_users WHERE user_id=?", (tid,))
        row = c.fetchone()
        if not row:
            conn.close()
            try: await query.edit_message_text("❌ Already unbanned or not found.")
            except Exception: pass
            return
        uname = row[0]
        c.execute("DELETE FROM banned_users WHERE user_id=?", (tid,))
        conn.commit(); conn.close()
        try:
            await context.bot.send_message(chat_id=tid,
                text="✅ You have been unbanned from 8ball World. Your account has been fully restored.")
        except Exception:
            pass
        try:
            await query.edit_message_text(
                f"✅ <b>{uname}</b> has been unbanned.",
                parse_mode="HTML")
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[unban confirm error] {e}")
            except Exception: pass
        return

    await query.answer()

async def unban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    # No args — show interactive picker
    if not context.args:
        rows = _build_unban_picker()
        if not rows:
            await send_group(update, "No banned players.", delay=15); return
        await update.message.reply_text(
            "🔓 *Unban Player — Select a player to unban*",
            parse_mode="Markdown", reply_markup=_build_unban_markup(rows))
        return

    arg = context.args[0].lstrip("@")
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    if arg.isdigit():
        c.execute("SELECT user_id, username FROM banned_users WHERE user_id=?", (int(arg),))
    else:
        c.execute("SELECT user_id, username FROM banned_users WHERE LOWER(username)=?", (arg.lower(),))
    row = c.fetchone()
    if not row:
        conn.close()
        await send_group(update, "❌ No banned user found with that name.", delay=9); return

    tid, tname = row
    c.execute("DELETE FROM banned_users WHERE user_id=?", (tid,))
    conn.commit(); conn.close()
    try:
        await context.bot.send_message(chat_id=tid,
            text="✅ You have been unbanned from 8ball World. Your account has been fully restored.")
    except Exception:
        pass
    await send_group(update,
        f"✅ *{tname}* has been unbanned.\n"
        f"Their stats and progress are fully restored.", delay=20)

async def banlist_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT user_id, username, banned_at FROM banned_users ORDER BY banned_at DESC")
    rows = c.fetchall(); conn.close()
    if not rows:
        await send_group(update, "✅ No banned users.", delay=15); return
    lines = [f"🔨 *Banned Users* ({len(rows)} total)\n"]
    for uid, uname, banned_at in rows:
        try:
            dt = datetime.fromisoformat(banned_at).strftime("%Y-%m-%d")
        except Exception:
            dt = "?"
        lines.append(f"• *{uname}*  `{uid}`  — {dt}")
    lines.append("\n_Use /unban to remove someone from this list._")
    await send_group(update, "\n".join(lines), permanent=False, delay=60)

def _calc_max_stat_points(p):
    lvl = safe_int(p.get("level", 1))
    prestige = safe_int(p.get("prestige_count", 0))
    base_pts = (lvl * 3 + lvl // 5) if lvl <= 20 else (20 * 3 + 20 // 5 + (lvl - 20) * 6)
    return base_pts + prestige * 10

async def fixstats_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: inspect and correct stat points.
    /fixstats                       — scan all, list high pools
    /fixstats <name or id>          — full inspection
    /fixstats <name or id> setpool <n> — set pool directly to n
    /fixstats <name or id> fix      — auto-reduce pool by formula"""
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    def _inspect(p):
        class_bonuses = _calc_applied_class_bonuses(p)
        sd = safe_stats(p)
        base = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5}
        allocated = sum(max(0, sd.get(s, b) - b - class_bonuses.get(s, 0)) for s, b in base.items())
        pool      = safe_int(p.get("stat_points"))
        max_pts   = _calc_max_stat_points(p)
        return allocated, pool, max_pts

    if not context.args:
        conn_s = sqlite3.connect(DB_PATH); conn_s.row_factory = sqlite3.Row; c_s = conn_s.cursor()
        c_s.execute("SELECT user_id, username, level, prestige_count, stat_points, "
                    "stats, class_id, class_path FROM players")
        rows = [dict(r) for r in c_s.fetchall()]; conn_s.close()
        flagged = []
        for row in rows:
            pool = safe_int(row.get("stat_points"))
            max_pts = _calc_max_stat_points(row)
            if pool > max_pts + 10:
                flagged.append(f"• *{row['username']}* (id `{row['user_id']}`) "
                               f"lv{row['level']} p{row.get('prestige_count',0)}: "
                               f"pool={pool} max={max_pts} excess≈{pool-max_pts}")
        if not flagged:
            await send_group(update, "✅ No stat pool anomalies found.", delay=15); return
        await send_group(update,
            f"⚠️ *High Pools ({len(flagged)}):*\n\n" + "\n".join(flagged[:20]) +
            f"\n\nUse `/fixstats <name> setpool 0` to zero, or inspect first.", delay=60); return

    query_str = context.args[0]
    rest = context.args[1:]

    target_id = None
    try:
        target_id = int(query_str)
    except ValueError:
        search = query_str.lower()
        conn_n = sqlite3.connect(DB_PATH); conn_n.row_factory = sqlite3.Row; c_n = conn_n.cursor()
        c_n.execute("SELECT user_id, username FROM players WHERE LOWER(username) LIKE ?",
                    (f"%{search}%",))
        matches = [dict(r) for r in c_n.fetchall()]; conn_n.close()
        if not matches:
            await send_group(update, f"No player found matching '{query_str}'.", delay=9); return
        if len(matches) > 1:
            names = "\n".join(f"• *{m['username']}* — id `{m['user_id']}`" for m in matches[:10])
            await send_group(update,
                f"Multiple matches:\n\n{names}\n\nUse the id.", delay=20); return
        target_id = matches[0]["user_id"]

    p = get_player(target_id)
    if not p:
        await send_group(update, f"Player not found.", delay=9); return

    allocated, current_pool, max_pts = _inspect(p)
    prestige = safe_int(p.get("prestige_count", 0))

    # setpool — direct override
    if rest and rest[0].lower() == "setpool":
        try:
            new_val = int(rest[1]) if len(rest) > 1 else 0
        except (ValueError, IndexError):
            await send_group(update, "Usage: /fixstats <name> setpool <number>", delay=9); return
        p["stat_points"] = new_val
        save_player(p)
        p2 = get_player(target_id)
        saved = safe_int(p2.get("stat_points")) if p2 else new_val
        await send_group(update,
            f"✅ *{p['username']}* pool set: {current_pool} → {saved}", delay=15); return

    # fix — formula auto-reduce (only safe when player hasn't prestiged with class baked in)
    if rest and rest[0].lower() == "fix":
        total = allocated + current_pool
        if total <= max_pts:
            await send_group(update,
                f"✅ *{p['username']}* is within bounds. No fix needed.\n"
                f"pool={current_pool} allocated={allocated} max={max_pts}", delay=15); return
        excess = total - max_pts
        new_pool = max(0, current_pool - excess)
        p["stat_points"] = new_pool
        save_player(p)
        p2 = get_player(target_id)
        saved = safe_int(p2.get("stat_points")) if p2 else new_pool
        await send_group(update,
            f"✅ Fixed *{p['username']}*\n"
            f"Pool: {current_pool} → {saved} (removed {excess})\n"
            f"_If still flagged, use `setpool` to override directly._", delay=15); return

    # inspect
    sd = safe_stats(p)
    stats_line = " ".join(f"{s}:{sd.get(s,b)}" for s,b in
                          [("STR",5),("AGI",5),("INT",5),("WIS",5),("DEX",5),("LUK",5)])
    cls_name = (get_player_class(p) or {}).get("name", "none")
    await send_group(update,
        f"🔍 *{p['username']}* — id `{target_id}`\n"
        f"Level: {p['level']}  |  Prestige: {prestige}  |  Class: {cls_name}\n"
        f"Stats: {stats_line}\n"
        f"Allocated (est): {allocated}  |  Pool: {current_pool}\n"
        f"Formula max: {max_pts}  |  Pool excess: {max(0, current_pool - max_pts)}\n\n"
        f"`/fixstats {target_id} fix` — auto reduce pool\n"
        f"`/fixstats {target_id} setpool 0` — zero the pool directly", delay=30)


async def fixgear_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: strip class-restricted gear from a player (or scan all).
    Usage: /fixgear               — list all players wearing invalid gear
           /fixgear <name or id>  — strip invalid gear for that player"""
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    def _invalid_gear(p):
        cls_line = get_class_line(p)
        path = p.get("class_path")
        bad = []
        for slot, pool in [("equipped_weapon", WEAPONS), ("equipped_armor", ARMORS),
                            ("equipped_hat", HATS), ("equipped_gloves", GLOVES),
                            ("equipped_boots", BOOTS), ("equipped_mask", MASKS)]:
            name = p.get(slot)
            if not name: continue
            d = pool.get(name, {})
            item_class = d.get("class") or d.get("line")
            if item_class and (not cls_line or item_class != cls_line):
                bad.append(name)
        s_name = p.get("equipped_shield")
        if s_name:
            s_data = SHIELDS.get(s_name, {})
            if s_data.get("type") == "claw":
                if cls_line != "thief" or path != "B": bad.append(s_name)
            else:
                if cls_line != "warrior" or path != "A": bad.append(s_name)
        return bad

    if not context.args:
        conn_fg = sqlite3.connect(DB_PATH); conn_fg.row_factory = sqlite3.Row; c_fg = conn_fg.cursor()
        c_fg.execute("SELECT user_id, username, class_id, class_path, equipped_weapon, equipped_armor, "
                     "equipped_shield, equipped_hat, equipped_gloves, equipped_boots, equipped_mask FROM players")
        rows = [dict(r) for r in c_fg.fetchall()]; conn_fg.close()
        flagged = []
        for row in rows:
            bad = _invalid_gear(row)
            if bad:
                flagged.append(f"• *{row['username']}* (id `{row['user_id']}`): {', '.join(bad)}")
        if not flagged:
            await send_group(update, "✅ No invalid gear found.", delay=15); return
        await send_group(update,
            f"⚠️ *Invalid Gear Found ({len(flagged)}):*\n\n" + "\n".join(flagged[:20]) +
            f"\n\nUse `/fixgear <name or id>` to strip.", delay=60); return

    query_str = context.args[0]
    target_id = None
    try:
        target_id = int(query_str)
    except ValueError:
        conn_fg2 = sqlite3.connect(DB_PATH); conn_fg2.row_factory = sqlite3.Row; c_fg2 = conn_fg2.cursor()
        c_fg2.execute("SELECT user_id, username FROM players WHERE LOWER(username) LIKE ?",
                      (f"%{query_str.lower()}%",))
        matches = [dict(r) for r in c_fg2.fetchall()]; conn_fg2.close()
        if not matches:
            await send_group(update, f"No player found matching '{query_str}'.", delay=9); return
        if len(matches) > 1:
            names = "\n".join(f"• *{m['username']}* — id `{m['user_id']}`" for m in matches[:10])
            await send_group(update,
                f"Multiple matches:\n\n{names}\n\nUse the id.", delay=20); return
        target_id = matches[0]["user_id"]

    p = get_player(target_id)
    if not p:
        await send_group(update, f"Player not found.", delay=9); return

    unequipped = _unequip_class_gear(p)
    if not unequipped:
        await send_group(update, f"✅ *{p['username']}* has no invalid gear equipped.", delay=15); return
    save_player(p)
    await send_group(update,
        f"✅ Stripped *{p['username']}*'s invalid gear:\n" +
        "\n".join(f"• {item}" for item in unequipped) +
        "\n\nItems returned to their inventory.", delay=15)


async def admingivexp_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    args = context.args
    if not args:
        await update.message.reply_text(
            "Usage: /admingivexp <name/id/search> <amount>\n\n"
            "If multiple players match the search, you'll get a picker.\n"
            "Examples:\n"
            "  /admingivexp john 900000\n"
            "  /admingivexp 123456789 50000\n"
            "  /admingivexp @john 200000"
        )
        return

    # If last arg is a number it's the amount; otherwise no amount given yet
    try:
        exp_amount = int(args[-1])
        query_parts = args[:-1]
    except ValueError:
        await update.message.reply_text("Last argument must be the EXP amount.\nExample: /admingivexp john 900000")
        return

    if not query_parts:
        await update.message.reply_text("Provide a name, @username, or user ID before the amount.")
        return

    search = " ".join(query_parts).strip().lower().lstrip("@")
    c = _db().cursor()

    # Collect all matches: exact user_id, exact tg_username, partial username/display
    matches = []
    seen = set()

    def _add(row):
        if row and row["user_id"] not in seen:
            seen.add(row["user_id"])
            matches.append(dict(row))

    # 1. Exact user_id
    try:
        uid_int = int(search)
        row = c.execute("SELECT user_id, username, level, tg_username FROM players WHERE user_id=?", (uid_int,)).fetchone()
        _add(row)
    except ValueError:
        pass

    # 2. Exact @handle
    c.execute("SELECT user_id, username, level, tg_username FROM players WHERE LOWER(tg_username)=?", (search,))
    for row in c.fetchall(): _add(row)

    # 3. Exact display name
    c.execute("SELECT user_id, username, level, tg_username FROM players WHERE LOWER(username)=?", (search,))
    for row in c.fetchall(): _add(row)

    # 4. Partial match on either field (up to 20 results)
    c.execute("""SELECT user_id, username, level, tg_username FROM players
                 WHERE LOWER(username) LIKE ? OR LOWER(tg_username) LIKE ?
                 ORDER BY level DESC LIMIT 20""", (f"%{search}%", f"%{search}%"))
    for row in c.fetchall(): _add(row)

    if not matches:
        await update.message.reply_text(f"No players found matching '{search}'.")
        return

    if len(matches) == 1:
        # Single match — apply directly
        p = get_player(matches[0]["user_id"])
        if not p:
            await update.message.reply_text("Player found but data missing."); return
        old_level = p["level"]
        add_exp(p, exp_amount)
        save_player(p)
        new_level = p["level"]
        level_note = f" _(levelled up: {old_level} → {new_level})_" if new_level != old_level else ""
        handle = f" (@{matches[0]['tg_username']})" if matches[0].get("tg_username") else ""
        await update.message.reply_text(
            f"✅ Gave *{exp_amount:,} EXP* to *{p['username']}*{handle}{level_note}\n"
            f"New level: *{new_level}*  |  EXP: *{p['exp']:,}*",
            parse_mode="Markdown"
        )
        return

    # Multiple matches — show picker (store exp in callback data)
    rows = []
    for m in matches[:20]:
        handle = f"@{m['tg_username']} · " if m.get("tg_username") else ""
        label = f"{m['username']} ({handle}Lv {m['level']}  |  id:{m['user_id']})"
        rows.append([InlineKeyboardButton(label,
            callback_data=f"agivexp_{m['user_id']}_{exp_amount}")])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="agivexp_cancel")])
    await update.message.reply_text(
        f"Found *{len(matches)}* players matching *'{search}'*.\n"
        f"Select who should receive *{exp_amount:,} EXP*:",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(rows)
    )


async def admingivexp_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if update.effective_user.id != ADMIN_ID:
        await query.answer("Not authorised.", show_alert=True); return
    await query.answer()
    data = query.data

    if data == "agivexp_cancel":
        try: await query.edit_message_text("_Cancelled._", parse_mode="Markdown")
        except: pass
        return

    parts = data.split("_")   # agivexp_<uid>_<exp>
    try:
        target_uid = int(parts[1])
        exp_amount = int(parts[2])
    except (IndexError, ValueError):
        await query.edit_message_text("Invalid callback data."); return

    p = get_player(target_uid)
    if not p:
        await query.edit_message_text("Player not found."); return

    old_level = p["level"]
    add_exp(p, exp_amount)
    save_player(p)
    new_level = p["level"]
    level_note = f" _(levelled up: {old_level} → {new_level})_" if new_level != old_level else ""

    try:
        await query.edit_message_text(
            f"✅ Gave *{exp_amount:,} EXP* to *{p['username']}*{level_note}\n"
            f"New level: *{new_level}*  |  EXP: *{p['exp']:,}*",
            parse_mode="Markdown"
        )
    except Exception: pass


async def adminresetclass_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin-only: reset a player's class so they can re-choose. For testing purposes."""
    if update.effective_user.id != ADMIN_ID:
        return
    if not context.args:
        await update.message.reply_text(
            "Usage: /adminresetclass <@username or user_id>\n"
            "Clears class_id, class_path, and all_skills so the player can pick again.")
        return
    target = context.args[0].lstrip("@")
    p = get_player_by_username(target)
    if not p:
        try:
            p = get_player(int(target))
        except ValueError:
            p = None
    if not p:
        await update.message.reply_text(f"Player '{target}' not found."); return
    old_class = p.get("class_id") or "none"
    old_cls   = CLASS_TREE.get(old_class, {})
    old_name  = old_cls.get("name", old_class)

    # Reverse all class stat bonuses (same logic as /resetclass)
    bonuses = _calc_applied_class_bonuses(p)
    sd = safe_stats(p)
    for stat, val in bonuses.items():
        sd[stat] = max(0, sd.get(stat, 0) - val)
    p["stats"] = json.dumps(sd)

    p["class_id"]   = None
    p["class_path"] = None
    p["all_skills"] = json.dumps([])

    # Clear class-specific combat state
    for _f in ("charging_killshot", "steady_aim_target", "steady_aim_stacks",
               "mark_first_hit", "deadeye_kill_bonus", "spell_cast_count",
               "holy_field_until", "devotion_charge",
               "contract_target", "contract_until",
               "serpent_revive_used", "cure_priority"):
        p.pop(_f, None)
    for _f in ("charging_killshot", "steady_aim_stacks", "mark_first_hit",
               "deadeye_kill_bonus", "spell_cast_count", "devotion_charge"):
        p[_f] = 0  # integer fields need a default, not absent

    # Strip class-restricted gear
    unequipped = _unequip_class_gear(p)
    new_max_hp = calc_max_hp(p)
    p["hp"] = min(safe_int(p.get("hp", new_max_hp)), new_max_hp)

    save_player(p)
    gear_note = f"\n⚠️ Class gear unequipped: {', '.join(unequipped)}" if unequipped else ""
    bonus_note = (f"\n📉 Stat bonuses reversed: " +
                  ", ".join(f"{s} -{v}" for s, v in bonuses.items())) if bonuses else ""
    await update.message.reply_text(
        f"✅ *{p['username']}*'s class reset.\n"
        f"Old class: *{old_name}*{bonus_note}{gear_note}\n"
        f"They can now use /class to choose a new one.",
        parse_mode="Markdown")


async def fixbounties_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: inspect and fix stuck bounties.
    /fixbounties              — list ALL unclaimed bounties (including expired)
    /fixbounties wipe         — delete all expired+unclaimed bounties
    /fixbounties wipe <name>  — delete all unclaimed bounties on that player
    /fixbounties claim <name> — force-claim all unclaimed bounties on that player (gold goes to admin)
    """
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    conn = _db(); c = conn.cursor()
    now_iso = datetime.now().isoformat()

    args = context.args or []
    action = args[0].lower() if args else "list"
    target_name = " ".join(args[1:]) if len(args) > 1 else None

    # ── Resolve target player ──────────────────────────────────────────────────
    target_uid = None
    if target_name:
        tp = get_player_by_username(target_name)
        if not tp:
            tp_c = c.execute("SELECT user_id, username FROM players WHERE username LIKE ?",
                             (f"%{target_name}%",)).fetchone()
            tp = dict(tp_c) if tp_c else None
        if not tp:
            await send_group(update, f"❌ Player *{target_name}* not found.", delay=9); return
        target_uid = tp["user_id"]

    if action == "list":
        rows = c.execute(
            "SELECT b.bounty_id, b.target_id, b.placer_id, b.reward, b.expires_at, b.claimed_by, "
            "p.username as target_name, p2.username as placer_name "
            "FROM bounties b "
            "LEFT JOIN players p  ON b.target_id  = p.user_id "
            "LEFT JOIN players p2 ON b.placer_id = p2.user_id "
            "WHERE b.claimed_by IS NULL "
            "ORDER BY b.expires_at DESC LIMIT 20"
        ).fetchall()
        if not rows:
            await send_group(update, "✅ No unclaimed bounties in the database.", delay=15); return
        lines = [f"🎯 *Unclaimed Bounties* ({len(rows)} shown)\n"]
        for r in rows:
            exp = r["expires_at"] or "?"
            expired = exp < now_iso if exp != "?" else False
            status = "💀 EXPIRED" if expired else "✅ LIVE"
            lines.append(
                f"ID `{r['bounty_id']}` | {status}\n"
                f"  Target: *{r['target_name'] or r['target_id']}*  "
                f"Placer: *{r['placer_name'] or r['placer_id']}*  "
                f"Reward: *{r['reward']}g*\n"
                f"  Expires: {exp[:16]}"
            )
        lines.append("\n`/fixbounties wipe` — delete expired\n"
                     "`/fixbounties wipe <name>` — delete all on player\n"
                     "`/fixbounties claim <name>` — force-claim all on player")
        await send_group(update, "\n".join(lines), permanent=True, delay=120); return

    if action == "wipe":
        if target_uid:
            deleted = c.execute(
                "DELETE FROM bounties WHERE target_id=? AND claimed_by IS NULL",
                (target_uid,)).rowcount
            conn.commit()
            await send_group(update,
                f"🗑️ Wiped *{deleted}* unclaimed bounty(s) on *{tp['username']}*.", delay=15)
        else:
            deleted = c.execute(
                "DELETE FROM bounties WHERE claimed_by IS NULL AND expires_at < ?",
                (now_iso,)).rowcount
            conn.commit()
            await send_group(update,
                f"🗑️ Deleted *{deleted}* expired unclaimed bounty(s).", delay=15)
        return

    if action == "claim":
        if not target_uid:
            await send_group(update, "Usage: /fixbounties claim <playername>", delay=9); return
        rows = c.execute(
            "SELECT * FROM bounties WHERE target_id=? AND claimed_by IS NULL",
            (target_uid,)).fetchall()
        if not rows:
            await send_group(update, f"No unclaimed bounties on that player.", delay=9); return
        total = sum(r["reward"] for r in rows)
        c.execute("UPDATE bounties SET claimed_by=? WHERE target_id=? AND claimed_by IS NULL",
                  (ADMIN_ID, target_uid))
        conn.commit()
        await send_group(update,
            f"✅ Force-claimed *{len(rows)}* bounty(s) on *{tp['username']}* "
            f"totaling *{total}g*. (Gold not awarded — use this to unstick the board.)", delay=15)
        return

    await send_group(update, "Unknown action. Use: list | wipe | wipe <name> | claim <name>", delay=9)


# ── IDLE REWARD SYSTEM ────────────────────────────────────────────────────────
def _calc_idle_exp(idle_secs: float, player_level: int = 1) -> int:
    """Compound EXP for being offline. 0 if < 30 min. Scales with level, no hard time cap."""
    if idle_secs < 1800:
        return 0
    idle_hours = idle_secs / 3600
    # Hourly rate scales with level; power < 1 gives diminishing returns over time
    rate = 300 + player_level * 40
    exp = int(rate * (idle_hours ** 0.65))
    return max(50, exp)

async def _try_idle_reward(uid: int, bot, prev_seen_iso: str):
    """Award idle EXP to shadow + RPG player, send DM. Call before updating last_seen."""
    global _idle_last_awarded
    now_ts = time.time()
    if _idle_last_awarded.get(uid, 0) > now_ts - 60:
        return  # already awarded within last 60 s (rapid messages)
    try:
        idle_secs = (datetime.now() - datetime.fromisoformat(prev_seen_iso)).total_seconds()
        p = get_player(uid)
        plvl = p["level"] if p else 1
        idle_exp = _calc_idle_exp(idle_secs, plvl)
        if idle_exp <= 0:
            return
        _idle_last_awarded[uid] = now_ts
        ih = idle_secs / 3600
        away_str = (f"{int(ih)}h {int((idle_secs % 3600) / 60)}m"
                    if ih >= 1 else f"{int(idle_secs / 60)}m")
        s = get_shadow(uid)
        if s:
            add_shadow_exp(s, idle_exp)
            save_shadow(s)
        if p and not is_defeated(p):
            add_exp(p, idle_exp)
            save_player(p)
        try:
            await bot.send_message(
                uid,
                f"🎱 *Welcome back!*\n\n"
                f"You were away for *{away_str}*.\n"
                f"💫 Idle reward: *+{idle_exp:,} EXP*\n"
                f"_(Scales with your level — the higher your level, the more you earn)_",
                parse_mode="Markdown")
        except Exception:
            pass
    except Exception:
        pass

# ── PASSIVE MESSAGE HANDLER ───────────────────────────────────────────────────
async def handle_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    user = update.effective_user
    if not user or user.is_bot: return
    if is_banned(user.id): return
    if not _rate_ok(user.id):
        return  # silently drop — no response, no feedback loop
    chat_id = update.effective_chat.id
    text    = (update.message.text or "").lower()

    # Alliance name creation: leader typed the name after clicking "Found an Order"
    if context.user_data.get("awaiting_alliance_name") is not None:
        raw_name = (update.message.text or "").strip()
        if raw_name and not raw_name.startswith("/") and 2 <= len(raw_name) <= 20:
            p_create = get_player(user.id)
            if p_create and not p_create.get("alliance_id"):
                if not get_alliance_by_name(raw_name):
                    new_aid = f"{user.id}_{int(time.time())}"
                    new_a = {
                        "id": new_aid, "name": raw_name, "leader_id": user.id,
                        "members": json.dumps([user.id]),
                        "influence_pool": 0, "created": int(time.time()),
                    }
                    save_alliance(new_a)
                    p_create["alliance_id"] = new_aid; save_player(p_create)
                    del context.user_data["awaiting_alliance_name"]
                    try: await update.message.reply_text(
                        f"⚔️ *Secret Order Founded!*\n\n*{raw_name}* is now bound to the void.\nUse /alliance to manage your order.",
                        parse_mode="Markdown")
                    except: pass
                    return
                else:
                    try: await update.message.reply_text(
                        f"❌ An order named *{raw_name}* already exists. Try another name.",
                        parse_mode="Markdown")
                    except: pass
                    return
            else:
                del context.user_data["awaiting_alliance_name"]

    # Silent influence: social greetings
    _p_msg = get_player(user.id)
    # Keep tg_username fresh on every message so /attack @handle always works
    if getattr(user, "username", None):
        try:
            _tgu_c = sqlite3.connect(DB_PATH)
            _tgu_c.execute("UPDATE players SET tg_username=? WHERE user_id=?", (user.username, user.id))
            _tgu_c.commit(); _tgu_c.close()
        except Exception:
            pass
        if _p_msg:
            _p_msg["tg_username"] = user.username
    # Also capture tg_username for anyone being replied to
    if update.message.reply_to_message and update.message.reply_to_message.from_user:
        _ru = update.message.reply_to_message.from_user
        if getattr(_ru, "username", None):
            try:
                _tgr_c = sqlite3.connect(DB_PATH)
                _tgr_c.execute("UPDATE players SET tg_username=? WHERE user_id=?", (_ru.username, _ru.id))
                _tgr_c.commit(); _tgr_c.close()
            except Exception:
                pass
    if _p_msg and update.message.reply_to_message:
        _txt = (update.message.text or "").lower().strip()
        _greets_pos = ["thank you", "thanks", "ty ", "ty!", "thx", " ty"]
        _greets_wel  = ["you're welcome", "youre welcome", "welcome", " np ", "no problem", "anytime"]
        if any(g in _txt for g in _greets_pos):
            _add_influence(_p_msg, 1); save_player(_p_msg)
        elif any(g in _txt for g in _greets_wel):
            _add_influence(_p_msg, 1); save_player(_p_msg)
    # Secret quest: phrase completion
    if _p_msg and update.message.text and not update.message.text.startswith("/"):
        _reply_uid = (update.message.reply_to_message.from_user.id
                      if update.message.reply_to_message and update.message.reply_to_message.from_user
                      else None)
        await _try_complete_quest_phrase(_p_msg, update.message.text, _reply_uid, context.bot)
    # Admin broadcast quest: phrase completion check
    if _p_msg and update.message.text and _broadcast_quest:
        await _try_complete_broadcast_quest(_p_msg, update.message.text, context.bot)
    # Quest dispatch trigger (20% chance if no active quest, 8h+ since last)
    if _p_msg and random.random() < 0.20:
        await _dispatch_secret_quest(user.id, context.bot)

    # Non-text messages (stickers, photos, etc.)  -  track shadow profile but skip keyword triggers
    if not update.message.text:
        s = get_or_create_shadow(user.id, user.first_name)
        s["username"]      = user.first_name
        s["message_count"] = s.get("message_count", 0) + 1
        s["last_seen"]     = datetime.now().isoformat()
        save_shadow(s)
        return

    # Railrunner target-spotted notification (rate-limited: once per 10 min per target)
    _bounty_spot_cache = context.bot_data.setdefault("bounty_spot_cache", {})
    cache_key = (user.id, chat_id)
    last_spot = _bounty_spot_cache.get(cache_key, 0)
    if (datetime.now().timestamp() - last_spot) > 600:
        try:
            bconn = sqlite3.connect(DB_PATH); bconn.row_factory = sqlite3.Row
            rows = bconn.execute(
                "SELECT b.placer_id FROM bounties b "
                "JOIN players rp ON rp.user_id = b.placer_id AND rp.class_id = 'bounty_hunter' "
                "WHERE b.target_id=? AND b.claimed_by IS NULL AND b.expires_at > ?",
                (user.id, datetime.now().isoformat())).fetchall()
            bconn.close()
            for row in rows:
                if row["placer_id"] != user.id:
                    asyncio.create_task(context.bot.send_message(
                        chat_id=row["placer_id"],
                        text=f"🔭 *Target spotted!* Your bounty target *{user.first_name}* "
                             f"just sent a message in the group.",
                        parse_mode="Markdown"))
            if rows:
                _bounty_spot_cache[cache_key] = datetime.now().timestamp()
        except Exception: pass

    # Random events  -  every ~100 messages, minimum 30 min between events
    message_counters[chat_id] = message_counters.get(chat_id, 0) + 1
    cnt = message_counters[chat_id]

    # Periodic cleanup every 500 messages
    if cnt % 500 == 0:
        now_iso = datetime.now().isoformat()
        expired_trades = [uid for uid, t in pending_trades.items()
                          if t.get("expires", now_iso) < now_iso]
        for uid in expired_trades:
            pending_trades.pop(uid, None)
        expired_raids = [cid for cid, r in active_raids.items()
                         if not r.get("in_progress")
                         and r.get("expires", now_iso) < now_iso]
        for cid in expired_raids:
            active_raids.pop(cid, None)

    _last_ev = last_event_times.get(chat_id)
    _ev_ok = _last_ev is None or (datetime.now() - _last_ev).total_seconds() >= 1800
    if cnt % 100 == 0 and chat_id not in active_events and _ev_ok:
        roll = random.random()
        if roll < 0.70:   freq = "common"
        elif roll < 0.90: freq = "uncommon"
        else:             freq = "rare"
        pool = [e for e in RANDOM_EVENTS if e["freq"]==freq]
        if pool:
            event = random.choice(pool).copy()
            active_events[chat_id] = event
            last_event_times[chat_id] = datetime.now()
            if event["key"] == "legendary_merchant":
                from datetime import timedelta
                legend_shop_expiry[chat_id] = datetime.now() + timedelta(minutes=event.get("duration_min", 10))
            msg = await update.message.reply_text(event["msg"], parse_mode="Markdown")
            # Store drake message id for reply detection
            if event["key"] == "drake":
                active_drakes[chat_id] = {
                    "msg_id": msg.message_id,
                    "hp": event["enemy_hp"],
                    "max_hp": event["enemy_hp"],
                    "fighters": {},
                    "loot_table": event.get("loot_table",[]),
                    "exp_reward": event["exp_reward"],
                }
                active_events.pop(chat_id, None)

    # Shadow profile
    s = get_or_create_shadow(user.id, user.first_name)
    s["username"] = user.first_name

    _is_group = update.effective_chat.type in ("group", "supergroup")

    if _is_group:
        _megaphone_state["group"] = update.effective_chat.id
        s["home_group"] = update.effective_chat.id

    p = get_player(user.id) if s.get("ascended") else None
    asyncio.create_task(check_pet_notifications(p, context.bot))

    # Idle reward — fire before updating last_seen, group context only
    _prev_seen = s.get("last_seen")
    if _prev_seen and _is_group:
        asyncio.create_task(_try_idle_reward(user.id, context.bot, _prev_seen))

    # Update last_seen regardless of context so DM-only players build and consume the timer
    s["message_count"] = s.get("message_count",0) + 1
    s["last_seen"] = datetime.now().isoformat()

    if p and s: sync_levels(p, s)

    cds_s = safe_cds(s)
    cds_p = safe_cds(p) if p else {}

    shadow_exp = 0; rpg_exp = 0; rpg_gold = 0

    # Bleed tick
    if p and is_bleeding(p):
        tick_dmg = check_bleed_tick(p)
        if tick_dmg:
            if p["hp"] <= 0:
                p["hp"] = 0
                p["defeated_until"] = (datetime.now()+timedelta(minutes=6)).isoformat()
                p["last_defeated_by"] = "Bleed damage (DoT)"
                p["losses"] = p.get("losses", 0) + 1
                p["kill_streak"] = 0
                asyncio.create_task(_notify_defeat(context.bot, p, "Bleed damage (you bled out)"))
                asyncio.create_task(announce(context.bot, chat_id,
                    f"🩸 *{p['username']}* bled out and is defeated for 6m!",
                    delay=30))
                _bleed_atk_ids = get_recent_attackers(p)
                if _bleed_atk_ids:
                    _bleed_atk = get_player(_bleed_atk_ids[-1])
                    if _bleed_atk:
                        _bleed_atk["wins"] = _bleed_atk.get("wins", 0) + 1
                        _bleed_atk["kill_streak"] = safe_int(_bleed_atk.get("kill_streak")) + 1
                        if _bleed_atk["kill_streak"] > safe_int(_bleed_atk.get("max_kill_streak")):
                            _bleed_atk["max_kill_streak"] = _bleed_atk["kill_streak"]
                        _today = datetime.now().strftime("%Y-%m-%d")
                        if _bleed_atk.get("kills_today_date") != _today:
                            _bleed_atk["kills_today"] = 0; _bleed_atk["kills_today_date"] = _today
                        _bleed_atk["kills_today"] = safe_int(_bleed_atk.get("kills_today")) + 1
                        if _bleed_atk["kills_today"] >= 5: _bleed_atk["is_wanted"] = 1
                        save_player(_bleed_atk)
                        _fire(check_and_claim_bounty(context.bot, _bleed_atk, p, chat_id))
            save_player(p)

    # Cannot earn EXP while defeated
    defeated_no_exp = p and is_defeated(p)

    # Easter eggs
    for egg in EASTER_EGGS:
        if re.search(egg["pattern"], text, re.IGNORECASE):
            if egg.get("secret_boss"):
                w = get_weather()
                if w.get("secret_eligible") and \
                   chat_id not in secret_boss_active and \
                   chat_id not in active_bosses:
                    bd = BOSSES["void"]
                    secret_boss_active[chat_id] = {
                        "data":bd.copy(),"hp":bd["max_hp"],
                        "participants":[{"id":user.id,"name":user.first_name,"dmg":0}]}
                    await update.message.reply_text(
                        f"🌑 *THE VOID BALL AWAKENS!*\n_{bd['desc']}_\n\n"
                        f"❤️ HP: {bd['max_hp']}\n*{user.first_name}* called it forth! /strike!",
                        parse_mode="Markdown")
            break

    # Keyword triggers
    if not defeated_no_exp:
        for trigger in KEYWORD_TRIGGERS:
            if re.search(trigger["pattern"], text, re.IGNORECASE):
                key = trigger["key"]
                if not cds_s.get(key) or \
                   datetime.now() > datetime.fromisoformat(cds_s[key]) + timedelta(seconds=trigger["cooldown"]):
                    cds_s[key] = datetime.now().isoformat()
                    if trigger["exp"] > 0:
                        shadow_exp += trigger["exp"]
                        if p: rpg_exp += trigger["exp"]
                    elif trigger["exp"] < 0:
                        s["exp"] = max(0, s["exp"]+trigger["exp"])
                        if p: p["exp"] = max(0, p.get("exp",0)+trigger["exp"])
                    if trigger.get("gold_chance") and random.random() < trigger["gold_chance"]:
                        rpg_gold += 1
                break

        # Daily first message bonus
        today = datetime.now().strftime("%Y-%m-%d")
        if cds_s.get("daily_date") != today:
            cds_s.update({"daily_date":today,"daily_messages":0,
                          "daily_bonus_given":False,
                          "streak_50":False,"streak_100":False,"streak_500":False})
        if not cds_s.get("daily_bonus_given"):
            cds_s["daily_bonus_given"] = True
            shadow_exp += 50
            if p: rpg_exp += 50

        cds_s["daily_messages"] = cds_s.get("daily_messages",0) + 1
        dm = cds_s["daily_messages"]
        if dm >= 50 and not cds_s.get("streak_50"):
            cds_s["streak_50"] = True; shadow_exp += 150
            if p: rpg_exp += 150
            asyncio.create_task(announce(context.bot, chat_id,
                f"🔥 *{user.first_name}* hit a *50 message streak!* +150 EXP!",
                delay=8))
        if dm >= 100 and not cds_s.get("streak_100"):
            cds_s["streak_100"] = True; shadow_exp += 300; rpg_gold += 30
            if p: rpg_exp += 300
            asyncio.create_task(announce(context.bot, chat_id,
                f"🔥 *{user.first_name}* hit a *100 message streak!* +300 EXP!",
                delay=8))
        if dm >= 500 and not cds_s.get("streak_500"):
            cds_s["streak_500"] = True; shadow_exp += 800
            if p: rpg_exp += 800
            asyncio.create_task(announce(context.bot, chat_id,
                f"🏆 *{user.first_name}* hit a *500 message streak!* +800 EXP! 🎱",
                delay=8))

    # Apply shadow EXP
    s["passive_cooldowns"] = json.dumps(cds_s)
    if shadow_exp > 0 and not defeated_no_exp:
        lmsgs, did_level = add_shadow_exp(s, shadow_exp)
        save_shadow(s)
        if did_level and s["level"] % 10 == 0:
            hint = ""
            if not s.get("ascended") and s["level"] >= 5:
                hint = "\n_Type /ascend in a private chat to enter the RPG!_"
            tier = get_tier(s["level"])
            asyncio.create_task(announce(context.bot, chat_id,
                f"{tier['emoji']} *{s['username']}* reached *Level {s['level']}*!{hint}",
                delay=60))
    else:
        save_shadow(s)

    # Apply RPG EXP
    if p and not defeated_no_exp:
        p["gold"] = p.get("gold",0) + rpg_gold
        p["passive_cooldowns"] = json.dumps(cds_p)
        if rpg_exp > 0:
            lmsgs, did_level = add_exp(p, rpg_exp)
            if did_level and p["level"] > s["level"]:
                s["level"] = p["level"]; s["exp"] = 0; save_shadow(s)
            save_player(p)
            if did_level and p["level"] % 10 == 0:
                cls = get_player_class(p)
                cnote = f" the *{cls['name']}*" if cls else ""
                ann = [f"🎉 *{p['username']}*{cnote} reached *Level {p['level']}*! 🎱"]
                for msg in lmsgs:
                    if any(x in msg for x in ["choose a class","Choose your path","LEVEL 100"]):
                        ann.append(msg)
                asyncio.create_task(announce(context.bot, chat_id,
                    "\n".join(ann), delay=60))
        else:
            save_player(p)

    # Drake reply detection  -  if message is a reply to drake message
    if chat_id in active_drakes:
        drake = active_drakes[chat_id]
        if (update.message.reply_to_message and
                update.message.reply_to_message.message_id == drake["msg_id"] and
                p and not is_defeated(p)):
            dmg = random.randint(10,30) + p["level"]//2
            drake["hp"] = max(0, drake["hp"]-dmg)
            uid = user.id
            drake["fighters"][uid] = drake["fighters"].get(uid,0) + dmg
            lines = [f"🐉 *{user.first_name}* strikes the Wild Drake for *{dmg}*!\n"
                     f"❤️ Drake HP: {drake['hp']}/{drake['max_hp']}"]
            if drake["hp"] <= 0:
                active_drakes.pop(chat_id, None)
                lines.append("\n🏆 *Wild Drake defeated!*\n")
                total_dmg = sum(drake["fighters"].values())
                for fid, fdmg in drake["fighters"].items():
                    fp = get_player(fid)
                    if not fp: continue
                    share = fdmg/max(1,total_dmg)
                    exp_share = round(drake["exp_reward"] * share)
                    loot = roll_loot_table(drake.get("loot_table",[]))
                    if loot: add_item(fp, loot)
                    lmsgs, leveled = add_exp(fp, exp_share)
                    save_player(fp)
                    lines.append(f"✅ *{fp['username']}*  -  +{exp_share} EXP"
                                 + (f" | 🎒 *{loot}*!" if loot else ""))
                    if leveled and fp["level"] % 10 == 0:
                        asyncio.create_task(announce(context.bot, chat_id,
                            f"🎉 *{fp['username']}* reached *Level {fp['level']}* from the Drake! 🐉",
                            delay=60))
            try:
                await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
            except Exception:
                pass

# ── EVENT HANDLERS ────────────────────────────────────────────────────────────
async def greet_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] not in ("traveler","merchant","shrine"): return
    s = get_or_create_shadow(user.id, user.first_name)
    p = get_player(user.id)
    active_events.pop(chat_id, None)
    if event["key"] == "traveler":
        loot = roll_loot_table(event.get("loot_table",[]))
        if p and not is_defeated(p):
            if loot: add_item(p, loot)
            lmsgs, leveled = add_exp(p, event["exp"]); save_player(p)
            msg = f"🧙 *{user.first_name}* greets the traveler! +{event['exp']} EXP"
            if loot: msg += f" | 🎒 *{loot}*!"
        else:
            lmsgs, leveled = add_shadow_exp(s, event["exp"]); save_shadow(s)
            msg = f"🧙 *{user.first_name}* greets the traveler! +{event['exp']} EXP"
        await send_group(update, msg, delay=15)
    elif event["key"] == "merchant":
        if p:
            set_status(p, "shop_discount_until", event["duration_min"]*60)
            save_player(p)
        await send_group(update,
            f"🛍️ *{user.first_name}* greeted the merchant!\n"
            f"*20% shop discount* for {event['duration_min']}m! Use /shop", delay=15)
    elif event["key"] == "shrine":
        if p:
            stat = random.choice(["STR","DEF","AGI","INT","WIS"])
            sd = safe_stats(p); sd[stat] = sd.get(stat,5)+5; p["stats"] = json.dumps(sd)
            save_player(p)
            await send_group(update,
                f"🔮 *{user.first_name}* prays at the shrine!\n*+5 {stat}* for 2 hours!", delay=15)

async def fight_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] not in ("bandit", "rival"):
        await send_group(update, "⚔️ Nothing to fight here right now.", delay=5)
        return
    p = get_player(user.id); s = get_or_create_shadow(user.id, user.first_name)

    # ── Rival event: first player to /fight claims it ────────────────────────
    if event["key"] == "rival":
        active_events.pop(chat_id, None)
        gold_prize = random.randint(400, 1000)
        exp_prize  = random.randint(1000, 2250)
        lines = [f"⚔️ *{user.first_name}* steps up first and claims the table!"]
        if p and not is_defeated(p):
            p["gold"] = p.get("gold", 0) + gold_prize
            add_exp(p, exp_prize); save_player(p)
            lines.append(f"💰 +{gold_prize} gold | ✨ +{exp_prize} EXP")
        elif s:
            add_shadow_exp(s, exp_prize); save_shadow(s)
            lines.append(f"✨ +{exp_prize} EXP")
        await send_group(update, "\n".join(lines), delay=20)
        return

    # ── Bandit event ──────────────────────────────────────────────────────────
    dmg = random.randint(10, 30)
    event["enemy_hp"] = event.get("enemy_hp", 150) - dmg
    event.setdefault("fighters", [])
    if user.id not in event["fighters"]: event["fighters"].append(user.id)
    lines = [f"🗡️ *{user.first_name}* strikes the bandit for {dmg}! "
             f"(HP: {max(0, event['enemy_hp'])}/150)"]
    if event["enemy_hp"] <= 0:
        active_events.pop(chat_id, None)
        lines.append("💀 *Bandit defeated!* +1250 EXP each!")
        for fid in event["fighters"]:
            fp = get_player(fid); fs = get_shadow(fid)
            if fp and not is_defeated(fp):
                loot = roll_loot_table(event.get("loot_table", []))
                if loot: add_item(fp, loot)
                lmsgs, leveled = add_exp(fp, 1250); save_player(fp)
                if loot: lines.append(f"🎒 *{fp['username']}* found *{loot}*!")
                if leveled and fp["level"] % 10 == 0:
                    asyncio.create_task(announce(context.bot, chat_id,
                        f"🎉 *{fp['username']}* reached *Level {fp['level']}* from battle! ⚔️",
                        delay=60))
            elif fs:
                lmsgs, leveled = add_shadow_exp(fs, 1250); save_shadow(fs)
    await send_group(update, "\n".join(lines), delay=15)

async def shoot_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] != "ghost": return
    p = get_player(user.id); s = get_or_create_shadow(user.id, user.first_name)
    dmg = random.randint(15,35)
    event["enemy_hp"] = event.get("enemy_hp",200) - dmg
    event.setdefault("fighters",[])
    if user.id not in event["fighters"]: event["fighters"].append(user.id)
    lines = [f"👻 *{user.first_name}* shoots the spirit for {dmg}! "
             f"(HP: {max(0,event['enemy_hp'])}/200)"]
    if event["enemy_hp"] <= 0:
        active_events.pop(chat_id, None)
        lines.append("✨ *Spirit banished!* +1500 EXP each!")
        for fid in event["fighters"]:
            fp = get_player(fid); fs = get_shadow(fid)
            if fp and not is_defeated(fp):
                loot = roll_loot_table(event.get("loot_table",[]))
                if loot: add_item(fp, loot)
                lmsgs, leveled = add_exp(fp, 1500); save_player(fp)
                if loot: lines.append(f"🎒 *{fp['username']}* found *{loot}*!")
                if leveled and fp["level"] % 10 == 0:
                    asyncio.create_task(announce(context.bot, chat_id,
                        f"🎉 *{fp['username']}* reached *Level {fp['level']}* from the ghost! 👻",
                        delay=60))
            elif fs:
                lmsgs, leveled = add_shadow_exp(fs, 1500); save_shadow(fs)
    await send_group(update, "\n".join(lines), delay=15)

async def claim_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] != "cache": return
    active_events.pop(chat_id, None)
    p = get_player(user.id)
    loot = roll_loot_table(event.get("loot_table",[]))
    gold = random.randint(250,1000)
    if p:
        if loot: add_item(p, loot)
        p["gold"] = p.get("gold",0) + gold; save_player(p)
    await send_group(update,
        f"💰 *{user.first_name}* claims the abandoned cache!\n"
        f"💰 +{gold} gold" + (f" | 🎒 *{loot}*!" if loot else ""), delay=15)

async def pray_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await greet_event(update, context)  # shrine handled in greet

# ── INLINE CALLBACKS ──────────────────────────────────────────────────────────

# ── Solo Raid Attack/Skill callback ──
async def soloraid_act_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    # format: sr_act_{uid}_{action}
    if len(parts) < 4:
        return
    try:
        uid = int(parts[2])
        action = parts[3]
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("This isn't your raid!", show_alert=True)
        return

    user = query.from_user
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if uid not in active_soloraids:
        await query.answer("No active solo raid! Use /soloraid.", show_alert=True); return
    if is_defeated(p):
        await query.answer("You're defeated — can't act!", show_alert=True); return
    _cc = _consume_cc(p)
    if _cc:
        await query.answer(_cc, show_alert=True); return

    chat_id = query.message.chat.id

    if action == "skl":
        # Trigger skill against solo raid enemy
        all_skills = sjl(p.get("all_skills"), [])
        if not all_skills:
            await query.answer("No skills unlocked yet!", show_alert=True); return
        sr = active_soloraids[uid]
        if len(all_skills) > 1:
            markup = _build_skill_picker_keyboard(all_skills, uid, 0, show_close=False)
            await query.edit_message_text(
                f"🔮 *vs {sr['enemy']['name']}* — choose a skill:",
                parse_mode="Markdown", reply_markup=markup)
            return
        sk = all_skills[0]
        w = get_weather()
        sk_lines, sk_dmg = apply_skill_to_raid_enemy(p, sk, sr, w)
        enemy = sr["enemy"]
        out = [f"⚡ *{user.first_name}* uses *{sk['name']}* on *{enemy['name']}*!"]
        out.extend(sk_lines)
        if sk_dmg > 0:
            out.append(f"💥 *{sk_dmg} damage!* Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}")

        if sr["enemy_hp"] <= 0:
            out.append(f"\n✅ *{enemy['name']}* destroyed!")
            tier = sr["tier"]; wave_enemies = tier["wave_enemies"]; cw = sr["wave"]
            if cw < len(wave_enemies):
                sr["wave"] += 1; ne = wave_enemies[cw].copy()
                sr["enemy"] = ne; sr["enemy_hp"] = ne["hp"]; sr["enemy_max_hp"] = ne["hp"]
                sr.pop("enemy_statuses", None)
                out.append(f"\n🌊 *Wave {sr['wave']}  -  {ne['name']}*")
                out.append(f"❤️ HP: {ne['hp']} | 💀 {ne['dmg_min']}–{ne['dmg_max']}")
            elif cw == len(wave_enemies):
                bd = BOSSES[tier["wave_boss_key"]]; boss_hp = bd["max_hp"] // 2
                sr["wave"] = len(wave_enemies) + 1
                sr["enemy"] = {"name": bd["name"] + " ⚡","dmg_min": round(bd["dmg_min"]*0.6),"dmg_max": round(bd["dmg_max"]*0.6)}
                sr["enemy_hp"] = boss_hp; sr["enemy_max_hp"] = boss_hp
                sr.pop("enemy_statuses", None)
                out.append(f"\n🎱 *FINAL BOSS  -  {bd['name']}!* ❤️ HP: {boss_hp}")
            else:
                active_soloraids.pop(uid, None)
                exp_r = tier["exp_reward"]; gold_r = tier["gold_reward"]
                p["gold"] = p.get("gold", 0) + gold_r; p["quests_done"] = p.get("quests_done", 0) + 1
                for _d, _e, _g in track_objective(p, "solo_win"):
                    p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
                loot = roll_loot_table(tier.get("loot_table", []), p)
                if loot:
                    add_item(p, loot)
                    r = ""
                    for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                        if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                    out.append(f"🎒 Found: {r} *{loot}*!")
                add_exp(p, exp_r, get_weather())
                out.append(f"\n🏆 *SOLO RAID COMPLETE!* +{exp_r:,} EXP | +{gold_r}g")
                save_player(p)
                try:
                    await query.edit_message_text(text="\n".join(out)[:4096], parse_mode="Markdown")
                except Exception: pass
                return
        else:
            killed = raid_enemy_counter(p, sr, out)
            if killed:
                active_soloraids.pop(uid, None)
                save_player(p)
                try:
                    await query.edit_message_text(text="\n".join(out)[:4096], parse_mode="Markdown")
                except Exception:
                    pass
                return

        save_player(p)
        try:
            await query.edit_message_text(text="\n".join(out)[:4096], parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
        except Exception: pass
        return

    if action == "heal":
        sr = active_soloraids[uid]
        heal_amt = round(sr["player_max_hp"] * 0.25)
        sr["player_hp"] = min(sr["player_max_hp"], sr["player_hp"] + heal_amt)
        save_player(p)
        try:
            await query.edit_message_text(
                f"🩺 *{user.first_name}* rests and recovers *{heal_amt} HP!*\n"
                f"❤️ HP: {sr['player_hp']}/{sr['player_max_hp']} | "
                f"Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}",
                parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
        except Exception: pass
        return

    if action == "flee":
        active_soloraids.pop(uid, None)
        save_player(p)
        try:
            await query.edit_message_text("🏃 *You fled from the solo raid!*", parse_mode="Markdown")
        except Exception: pass
        return

    # action == "atk" — standard attack
    sr = active_soloraids[uid]
    enemy = sr["enemy"]
    w = get_weather()
    dmg = calc_attack_damage(p, w)
    is_crit = check_crit(p)
    if is_crit: dmg = apply_crit(p, dmg)
    if safe_int(p.get("charging_killshot")):
        p["charging_killshot"] = 0; dmg = get_stat(p, "AGI") * 4; is_crit = False

    sr["enemy_hp"] = max(0, sr["enemy_hp"] - dmg)
    sr["total_dmg"] = sr.get("total_dmg", 0) + dmg

    lines = [
        f"⚔️ *{user.first_name}* strikes *{enemy['name']}* for *{dmg}{'💥' if is_crit else ''}!*",
        f"❤️ Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}  |  Your HP: {sr['player_hp']}/{sr['player_max_hp']}",
    ]
    bleed_dmg = tick_enemy_bleed(sr)
    if bleed_dmg:
        lines.append(f"🩸 *{enemy['name']}* bleeds for {bleed_dmg}! HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}")

    if sr["enemy_hp"] <= 0:
        tier = sr["tier"]; wave_enemies = tier["wave_enemies"]; cw = sr["wave"]
        lines.append(f"\n✅ *Wave {cw} cleared!*")
        sr.pop("enemy_statuses", None)
        if cw < len(wave_enemies):
            sr["wave"] += 1; ne = wave_enemies[cw].copy()
            sr["enemy"] = ne; sr["enemy_hp"] = ne["hp"]; sr["enemy_max_hp"] = ne["hp"]
            lines.append(f"\n🌊 *Wave {sr['wave']}  -  {ne['name']}*")
            lines.append(f"❤️ HP: {ne['hp']} | 💀 {ne['dmg_min']}–{ne['dmg_max']}")
        elif cw == len(wave_enemies):
            bd = BOSSES[tier["wave_boss_key"]]; boss_hp = bd["max_hp"] // 2
            sr["wave"] = len(wave_enemies) + 1
            sr["enemy"] = {"name": bd["name"] + " ⚡","dmg_min": round(bd["dmg_min"]*0.6),"dmg_max": round(bd["dmg_max"]*0.6)}
            sr["enemy_hp"] = boss_hp; sr["enemy_max_hp"] = boss_hp
            lines.append(f"\n🎱 *FINAL BOSS  -  {bd['name']}!* ❤️ HP: {boss_hp}")
        else:
            active_soloraids.pop(uid, None)
            exp_r = tier["exp_reward"]; gold_r = tier["gold_reward"]
            p["gold"] = p.get("gold", 0) + gold_r; p["quests_done"] = p.get("quests_done", 0) + 1
            for _d, _e, _g in track_objective(p, "solo_win"):
                p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
            loot = roll_loot_table(tier.get("loot_table", []), p)
            loot_line = ""
            if loot:
                add_item(p, loot); r = ""
                for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                    if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                loot_line = f"\n🎒 Found: {r} *{loot}*!"
            add_exp(p, exp_r, get_weather())
            lines.append(f"\n🏆 *SOLO RAID COMPLETE  -  {tier['name']}!*")
            lines.append(f"✅ +{exp_r:,} EXP | +{gold_r}g{loot_line}")
            save_player(p)
            try:
                await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown")
            except Exception: pass
            return
    else:
        enemy = sr["enemy"]
        if enemy_status_active(sr, "stunned_until"):
            lines.append(f"⚡ *{enemy['name']}* is stunned  -  no counter!")
        elif enemy_status_active(sr, "frozen_until"):
            lines.append(f"❄️ *{enemy['name']}* is frozen  -  no counter!")
        else:
            raw = random.randint(enemy["dmg_min"], enemy["dmg_max"])
            if enemy_status_active(sr, "weakened_until") or enemy_status_active(sr, "hexed_until"):
                raw = round(raw * 0.75)
            dodge = get_accessory_bonus(p, "dodge_bonus") + get_enchant_bonus(p, "dodge_bonus")
            cls_p = get_player_class(p)
            if cls_p and cls_p.get("passive_key") == "evasion": dodge += 0.10
            if dodge > 0 and random.random() < dodge:
                lines.append(f"💨 *{p['username']}* dodges!")
            else:
                edm = calc_defense(p, raw)
                sr["player_hp"] = max(0, sr["player_hp"] - edm)
                if sr["player_hp"] == 0:
                    exp_loss = apply_pvp_death(p, killer_name=enemy["name"], cause="Solo Raid")
                    asyncio.create_task(_notify_defeat(context.bot, p, enemy["name"] + " (Solo Raid)"))
                    active_soloraids.pop(uid, None)
                    save_player(p)
                    lines.append(f"💀 *{enemy['name']}* kills *{p['username']}*! 6min defeat. -{exp_loss} EXP.")
                    try:
                        await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown")
                    except Exception: pass
                    return
                else:
                    lines.append(f"🩸 *{enemy['name']}* hits *{p['username']}* for *{edm}!* "
                                 f"({sr['player_hp']}/{sr['player_max_hp']} raid HP)")
                    if sr["player_hp"] <= round(sr["player_max_hp"] * 0.30):
                        lines.append(f"⚠️ *Critically low HP!* Use /skill or a vial!")

    save_player(p)
    try:
        await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
    except Exception: pass


# ── Boss Attack/Skill callback ──
async def boss_act_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    # format: boss_act_{uid}_{action}
    parts = query.data.split("_", 3)
    if len(parts) < 4:
        return
    try:
        uid = int(parts[2]); action = parts[3]
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("These buttons are for the summoner only!", show_alert=True); return

    user = query.from_user
    p = get_player(uid)
    chat_id = query.message.chat.id

    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if is_defeated(p):
        await query.answer("You're defeated!", show_alert=True); return
    _cc = _consume_cc(p)
    if _cc:
        await query.answer(_cc, show_alert=True); return

    boss_dict = active_bosses.get(chat_id) or secret_boss_active.get(chat_id)
    if not boss_dict:
        await query.answer("No active boss in this chat!", show_alert=True); return

    is_secret = chat_id in secret_boss_active

    if action == "skl":
        all_skills = sjl(p.get("all_skills"), [])
        if not all_skills:
            await query.answer("No skills unlocked yet!", show_alert=True); return
        # Ensure player is a participant before picker so skill_pick_callback can find them
        if uid not in [u["id"] for u in boss_dict["participants"]]:
            boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
            if "player_hp" not in boss_dict:
                boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
            mhp = calc_max_hp(p)
            boss_dict["player_hp"][uid] = min(mhp, max(1, safe_int(p.get("hp")) or mhp))
            boss_dict["player_max_hp"][uid] = mhp
        if len(all_skills) > 1:
            markup = _build_skill_picker_keyboard(all_skills, uid, 0, show_close=False)
            await query.edit_message_text(
                f"🔮 *vs {boss_dict['data']['name']}* — choose a skill:",
                parse_mode="Markdown", reply_markup=markup)
            return
        sk = all_skills[0]

        if uid not in [u["id"] for u in boss_dict["participants"]]:
            boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
        participant = next(u for u in boss_dict["participants"] if u["id"] == uid)

        w = get_weather()
        stype = sk.get("type", "damage")
        lines = [f"⚡ *{user.first_name}* uses *{sk['name']}* on *{boss_dict['data']['name']}*!"]

        if stype in ("self_heal", "group_heal", "mass_cleanse",
                     "dmg_reduction_buff", "self_heal_buff", "revive_heal"):
            if stype == "self_heal":
                heal = round(get_stat(p, "WIS") * sk.get("mult", 3.0))
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"💚 Healed self for *{heal} HP*!")
            elif stype == "self_heal_buff":
                heal = round(p["max_hp"] * 0.30)
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"💚 *Rally!* +{heal} HP restored.")
            dmg = 0
        else:
            mult = sk.get("mult", 1.0) or 1.0
            hits = sk.get("hits", 1)
            if hits and hits > 1:
                total = 0; hit_log = []
                for _ in range(hits):
                    h = round(calc_attack_damage(p, w) * mult)
                    if check_crit(p): h = apply_crit(p, h); hit_log.append(f"💥{h}")
                    else: hit_log.append(str(h))
                    total += h
                dmg = total
                lines.append(f"⚡ {hits}-hit combo! [{' + '.join(hit_log)}] = {dmg}")
            elif stype in ("freeze_nuke", "execute_nuke", "holy_nuke", "fear_kill"):
                stat_key = sk.get("stat", get_primary_stat(p))
                dmg = round(get_stat(p, stat_key) * sk.get("mult", 3.0))
                lines.append(f"💥 *{sk['name']}!* {dmg} damage!")
            elif stype in ("drain", "drain_kill", "hp_drain"):
                drain_pct = min(sk.get("drain_pct", 0.25), 0.25)
                dmg = round(boss_dict["hp"] * drain_pct)
                heal = round(dmg * 0.50)
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"🩸 *{sk['name']}!* Drained {dmg} HP! Healed {heal}.")
            else:
                dmg = round(calc_attack_damage(p, w) * mult)
            if stype not in ("multihit", "multi_hit") and hits == 1 and check_crit(p):
                dmg = apply_crit(p, dmg)
                lines.append("💥 *CRITICAL HIT!*")
            boss_dict["hp"] = max(0, boss_dict["hp"] - dmg)
            participant["dmg"] += dmg
            lines.append(f"❤️ Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}")

        # Counter-attack
        alive = [u for u in boss_dict["participants"]
                 if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp",{}).get(u["id"],1) > 0]
        if alive and boss_dict["hp"] > 0 and random.random() < 0.90:
            target = random.choice(alive)
            tp = get_player(target["id"])
            if tp:
                if "player_hp" not in boss_dict:
                    boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
                    for u in boss_dict["participants"]:
                        pp2 = get_player(u["id"])
                        if pp2:
                            mhp2 = calc_max_hp(pp2)
                            boss_dict["player_hp"][u["id"]] = mhp2
                            boss_dict["player_max_hp"][u["id"]] = mhp2
                bdmg = calc_defense(tp, random.randint(
                    boss_dict["data"]["dmg_min"], boss_dict["data"]["dmg_max"]))
                boss_dict["player_hp"][target["id"]] = max(0,
                    boss_dict["player_hp"].get(target["id"], calc_max_hp(tp)) - bdmg)
                php  = boss_dict["player_hp"][target["id"]]
                pmhp = boss_dict["player_max_hp"].get(target["id"], calc_max_hp(tp))
                if php == 0:
                    exp_loss = apply_pvp_death(tp, killer_name=boss_dict['data']['name'], cause="Boss")
                    asyncio.create_task(_notify_defeat(context.bot, tp, boss_dict['data']['name'] + " (Boss)"))
                    save_player(tp)
                    lines.append(f"💀 *{boss_dict['data']['name']}* KILLS *{target['name']}*! 30min defeat. -{exp_loss} EXP.")
                else:
                    lines.append(f"💥 Boss hits *{target['name']}* for *{bdmg}!* ({php}/{pmhp} HP)")
                save_player(tp)

        if boss_dict["hp"] <= 0:
            data = boss_dict["data"]
            if is_secret: secret_boss_active.pop(chat_id, None)
            else: active_bosses.pop(chat_id, None)
            lines.append(f"\n🏆 *{data['name']} DEFEATED by {sk['name']}!*\n")
            w2 = get_weather()
            for u in boss_dict["participants"]:
                pp = get_player(u["id"])
                if not pp: continue
                pp["gold"] = pp.get("gold", 0) + data["gold"]
                loot = roll_loot_table(data.get("loot_table", []), boss=True)
                if loot:
                    add_item(pp, loot)
                    r = ""
                    for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                        if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                    lines.append(f"🎒 *{pp['username']}* found: {r} *{loot}*!")
                if award_title(pp, data["title"]):
                    lines.append(f"🏅 *{pp['username']}* earned: *{data['title']}*!")
                lmsgs, leveled = add_exp(pp, data["exp"], w2)
                save_player(pp)
                lines.append(f"✅ *{pp['username']}*  -  +{data['exp']:,} EXP | +{data['gold']} Gold")
            try:
                await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown")
            except Exception: pass
            return

        save_player(p)
        try:
            await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
        except Exception: pass
        return

    if action == "heal":
        if "player_hp" not in boss_dict:
            boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
            for u in boss_dict["participants"]:
                pp2 = get_player(u["id"])
                if pp2:
                    mhp2 = calc_max_hp(pp2)
                    boss_dict["player_hp"][u["id"]] = mhp2
                    boss_dict["player_max_hp"][u["id"]] = mhp2
        max_hp = boss_dict["player_max_hp"].get(uid, calc_max_hp(p))
        cur_hp = boss_dict["player_hp"].get(uid, max_hp)
        heal_amt = round(max_hp * 0.25)
        boss_dict["player_hp"][uid] = min(max_hp, cur_hp + heal_amt)
        try:
            await query.edit_message_text(
                f"🩺 *{user.first_name}* recovers *{heal_amt} HP!*\n"
                f"❤️ Your HP: {boss_dict['player_hp'][uid]}/{max_hp}\n"
                f"💀 Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}",
                parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
        except Exception: pass
        return

    if action == "flee":
        boss_dict["participants"] = [u for u in boss_dict["participants"] if u["id"] != uid]
        boss_dict.get("player_hp", {}).pop(uid, None)
        boss_dict.get("player_max_hp", {}).pop(uid, None)
        if not boss_dict["participants"]:
            active_bosses.pop(chat_id, None); secret_boss_active.pop(chat_id, None)
            try:
                await query.edit_message_text("🏃 *All players fled! The boss vanishes.*", parse_mode="Markdown")
            except Exception: pass
        else:
            try:
                await query.edit_message_text(
                    f"🏃 *{user.first_name}* fled!\n"
                    f"💀 Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}",
                    parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
            except Exception: pass
        return

    # action == "atk"
    if uid not in [u["id"] for u in boss_dict["participants"]]:
        boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
        if "player_hp" not in boss_dict:
            boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
        mhp = calc_max_hp(p)
        boss_dict["player_hp"][uid] = mhp; boss_dict["player_max_hp"][uid] = mhp
    elif "player_hp" not in boss_dict:
        boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
        for u in boss_dict["participants"]:
            pp = get_player(u["id"])
            if pp:
                mhp = calc_max_hp(pp)
                boss_dict["player_hp"][u["id"]] = mhp; boss_dict["player_max_hp"][u["id"]] = mhp
    participant = next(u for u in boss_dict["participants"] if u["id"] == uid)

    w = get_weather()
    dmg = calc_attack_damage(p, w)
    if check_crit(p): dmg = apply_crit(p, dmg)
    if safe_int(p.get("charging_killshot")):
        p["charging_killshot"] = 0; dmg = get_stat(p, "AGI") * 4

    boss_dict["hp"] = max(0, boss_dict["hp"] - dmg)
    participant["dmg"] += dmg

    lines = [
        f"⚔️ *{user.first_name}* strikes *{boss_dict['data']['name']}* for *{dmg}!*",
        f"❤️ Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}"
    ]

    alive = [u for u in boss_dict["participants"]
             if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp", {}).get(u["id"], 1) > 0]
    if alive and boss_dict["hp"] > 0 and random.random() < 0.90:
        hit_count = 2 if random.random() < 0.30 else 1
        targets = random.sample(alive, min(hit_count, len(alive)))
        for target in targets:
            tp = get_player(target["id"])
            if tp and not is_defeated(tp):
                raw = random.randint(boss_dict["data"]["dmg_min"], boss_dict["data"]["dmg_max"])
                edm = calc_defense(tp, raw)
                boss_dict["player_hp"][target["id"]] = max(0,
                    boss_dict["player_hp"].get(target["id"], calc_max_hp(tp)) - edm)
                php = boss_dict["player_hp"][target["id"]]
                pmhp = boss_dict["player_max_hp"].get(target["id"], calc_max_hp(tp))
                if php == 0:
                    exp_loss = apply_pvp_death(tp, killer_name=boss_dict['data']['name'], cause="Boss")
                    asyncio.create_task(_notify_defeat(context.bot, tp, boss_dict['data']['name'] + " (Boss)"))
                    save_player(tp)
                    lines.append(f"💀 *{boss_dict['data']['name']}* KILLS *{target['name']}*! 30min defeat. -{exp_loss} EXP.")
                else:
                    lines.append(f"💥 *{boss_dict['data']['name']}* hits *{target['name']}* for *{edm}!* ({php}/{pmhp} HP)")
                save_player(tp)

    alive_after = [u for u in boss_dict["participants"]
                   if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp", {}).get(u["id"], 1) > 0]
    if not alive_after and boss_dict["hp"] > 0:
        if is_secret: secret_boss_active.pop(chat_id, None)
        else: active_bosses.pop(chat_id, None)
        lines.append("💀 *ALL PLAYERS DEFEATED!* The boss wins...")
        save_player(p)
        try:
            await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown")
        except Exception: pass
        return

    if boss_dict["hp"] <= 0:
        data = boss_dict["data"]
        if is_secret: secret_boss_active.pop(chat_id, None)
        else: active_bosses.pop(chat_id, None)
        lines.append(f"\n🏆 *{data['name']} DEFEATED!*\n")
        w2 = get_weather()
        for u in boss_dict["participants"]:
            pp = get_player(u["id"])
            if not pp: continue
            pp["gold"] = pp.get("gold", 0) + data["gold"]
            loot = roll_loot_table(data.get("loot_table", []), boss=True)
            if loot:
                add_item(pp, loot); r = ""
                for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                    if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                lines.append(f"🎒 *{pp['username']}* found: {r} *{loot}*!")
            if award_title(pp, data["title"]):
                lines.append(f"🏅 *{pp['username']}* earned: *{data['title']}*!")
            add_exp(pp, data["exp"], w2); save_player(pp)
            lines.append(f"✅ *{pp['username']}*  -  +{data['exp']} EXP | +{data['gold']} Gold")
        try:
            await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown")
        except Exception: pass
        return

    save_player(p)
    try:
        await query.edit_message_text(text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
    except Exception: pass


# ── Prestige Path callback ──
async def prestige_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    # format: prestige_{uid}_{path}
    if len(parts) < 3:
        return
    try:
        uid = int(parts[1])
        path = parts[2].upper()
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("This isn't your prestige menu!", show_alert=True)
        return

    user = query.from_user
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    cid = p.get("class_id")
    if not cid:
        await query.answer("Choose a class first with /class.", show_alert=True); return
    cls = CLASS_TREE.get(cid, {})
    line = cls.get("line")
    existing_path = p.get("class_path")
    if existing_path:
        await query.answer("You already chose a path!", show_alert=True); return
    if p["level"] < 10:
        await query.answer("Path selection requires Level 10!", show_alert=True); return
    if path not in ("A", "B"):
        await query.answer("Invalid path.", show_alert=True); return

    paths = CLASS_PATHS.get(line, {})
    first_class = paths.get(path, [])[0] if paths.get(path) else None
    if not first_class:
        await query.answer("Invalid path for your class.", show_alert=True); return

    p["class_path"] = path
    p["class_id"] = first_class
    new_cls = CLASS_TREE.get(first_class, {})
    sd = safe_stats(p)
    for stat, bonus in new_cls.get("stat_bonus", {}).items():
        sd[stat] = sd.get(stat, 5) + bonus
    p["stats"] = json.dumps(sd)
    existing_skills = sjl(p.get("all_skills"), [])
    for sk in new_cls.get("skills", []):
        if sk["name"] not in [s["name"] for s in existing_skills]:
            existing_skills.append(sk)
    p["all_skills"] = json.dumps(existing_skills)
    # Catch-up: apply any tier advancements the player already qualifies for
    for _thresh in (30, 60, 100):
        if p["level"] >= _thresh:
            _auto_advance_class(p, _thresh)
    save_player(p)

    asyncio.create_task(announce(context.bot, query.message.chat.id,
        f"🌟 *{p['username']}* chose *Path {path}*  -  *{new_cls['name']}*!"))
    full_path = paths.get(path, [])
    path_names = " → ".join(CLASS_TREE.get(k, {}).get("name", "?") for k in full_path)
    msg = (f"🌟 *Path {path} chosen!* You are now a *{new_cls['name']}*!\n\n"
           f"_{new_cls['desc']}_\n\n"
           f"📜 Your journey: {path_names}\n\n"
           f"_Your class evolves automatically at Levels 30, 60, and 100._")
    try:
        await query.edit_message_text(msg, parse_mode="Markdown")
    except Exception:
        pass


# ── Shop Buy callback ──
async def shop_tab_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    # format: shoptab_{uid}_{tab}
    parts = query.data.split("_")
    if len(parts) < 3:
        await query.answer(); return
    try:    uid = int(parts[1])
    except: await query.answer(); return
    tab = parts[2]
    if query.from_user.id != uid:
        await query.answer("This isn't your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    discount = _shop_discount(p)
    text, markup = _build_shop_view(p, tab, uid, discount)
    try:
        await query.edit_message_text(text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass
    await query.answer()

async def shop_buy_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    # format: shopbuy_{uid}_{tab}_{idx}
    parts = query.data.split("_")
    if len(parts) < 4:
        await query.answer(); return
    try:
        uid = int(parts[1])
        tab = parts[2]
        idx = int(parts[3])
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    discount = _shop_discount(p)
    items = get_shop_tab_for_player(tab, p)
    if idx < 0 or idx >= len(items):
        await query.answer("Item no longer available.", show_alert=True); return
    entry = items[idx]
    price = round(entry["price"] * (1 - discount))
    if p["gold"] < price:
        await query.answer(f"Need {price:,}g — you have {p['gold']:,}g.", show_alert=True); return
    p["gold"] -= price
    add_item(p, entry["item"])
    save_player(p)
    await query.answer(f"✅ Bought {entry['item']} for {price:,}g!")
    # Rebuild the tab view with updated gold
    text, markup = _build_shop_view(p, tab, uid, discount)
    try:
        await query.edit_message_text(text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass

async def shopreroll_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    try:
        uid = int(parts[1])
        tab = parts[2]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    today = datetime.now().strftime("%Y-%m-%d")
    reroll_count = safe_int(p.get("shop_reroll_count", 0)) if p.get("shop_reroll_date") == today else 0

    if reroll_count >= 3:
        await query.answer("Already rerolled 3 times today!", show_alert=True); return
    if safe_int(p.get("gold", 0)) < 1000:
        await query.answer("Need 1,000g to reroll!", show_alert=True); return

    p["gold"] = safe_int(p.get("gold", 0)) - 1000
    p["shop_reroll_date"] = today
    p["shop_reroll_count"] = reroll_count + 1
    save_player(p)

    discount = _shop_discount(p)
    text, markup = _build_shop_view(p, tab, uid, discount)
    await query.answer(f"Shop rerolled! ({reroll_count + 1}/3 today)")
    try:
        await query.edit_message_text(text, parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass


# ── Allocate Stats callback ──
async def allocate_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    # format: alloc_{uid}_{stat}_{amt}
    if len(parts) < 4:
        await query.answer(); return
    try:
        uid  = int(parts[1])
        stat = parts[2].upper()
        amt  = int(parts[3])
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your stat screen!", show_alert=True)
        return

    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    STAT_NAMES = ["STR","AGI","INT","WIS","DEX","LUK"]
    if stat not in STAT_NAMES:
        await query.answer("Invalid stat.", show_alert=True); return

    sp = safe_int(p.get("stat_points"))
    if amt > sp:
        await query.answer("Not enough stat points!", show_alert=True); return

    sd = safe_stats(p)
    sd[stat] = sd.get(stat, 5) + amt
    p["stats"] = json.dumps(sd)
    p["stat_points"] = sp - amt
    save_player(p)
    sp = p["stat_points"]

    await query.answer(f"+{amt} {stat}! {sp} points left.")

    # Rebuild the allocate message with updated stats and buttons
    cls = get_player_class(p)
    rec = cls["primary_stat"] + " recommended" if cls else "Free to allocate"
    max_hp = calc_max_hp(p)
    text = (f"📊 *Stat Allocation*  -  *{sp}* points available\n\n"
            f"❤️ Max HP: {max_hp}\n"
            f"STR:{get_stat(p,'STR')} AGI:{get_stat(p,'AGI')} INT:{get_stat(p,'INT')} "
            f"WIS:{get_stat(p,'WIS')} DEX:{get_stat(p,'DEX')} LUK:{get_stat(p,'LUK')}\n\n"
            f"📌 STR  -  Attack damage (Warrior)\n"
            f"📌 AGI  -  Dodge & crit\n"
            f"📌 INT  -  Spell damage (Mage)\n"
            f"📌 WIS  -  Heal power (Priest)\n"
            f"📌 DEX  -  Accuracy & crit (Archer)\n"
            f"📌 LUK  -  Crit & gold bonus (Thief)\n"
            f"📌 DEF  -  From gear only (cannot allocate)\n\n"
            f"🧭 {rec}")
    rows = []
    if sp > 0:
        for s in STAT_NAMES:
            row = [InlineKeyboardButton(f"{s} +1", callback_data=f"alloc_{uid}_{s}_1")]
            if sp >= 5:
                row.append(InlineKeyboardButton(f"{s} +5", callback_data=f"alloc_{uid}_{s}_5"))
            rows.append(row)
    markup = InlineKeyboardMarkup(rows) if rows else None
    try:
        await query.edit_message_text(text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass


# ── MAIN ──────────────────────────────────────────────────────────────────────
async def _post_init(application):
    """On startup: DM admin if bot version changed."""
    version_file = "/data/bot_version.txt"
    try:
        with open(version_file) as f:
            last_version = f.read().strip()
    except Exception:
        last_version = None
    if last_version == CURRENT_VERSION:
        return
    try:
        with open(version_file, "w") as f:
            f.write(CURRENT_VERSION)
    except Exception: pass
    entry = next((e for e in reversed(CHANGELOG) if e["version"] == CURRENT_VERSION), None)
    if not entry: return
    changes_text = "\n".join(f"• {c}" for c in entry["changes"])
    msg = (f"🎱 *Bot Updated to {CURRENT_VERSION}*\n"
           f"_{entry['date']}_\n\n"
           f"{changes_text}")
    try:
        await application.bot.send_message(
            chat_id=ADMIN_ID, text=msg, parse_mode="Markdown")
    except Exception: pass

